#[derive(Clone)]
pub struct AppState {
    pub db: Database,
    pub web_dir: PathBuf,
    pub log_dir: PathBuf,
    pub local_address: String,
}

#[derive(Debug, Clone, Copy, Eq, PartialEq)]
pub enum SystemLifecycleCommand {
    Restart,
    Shutdown,
}

#[derive(Debug, Clone)]
struct PlaybackEvent {
    session_id: String,
    message: serde_json::Value,
}

#[derive(Debug, Clone)]
struct SyncPlayGroup {
    id: String,
    name: String,
    owner_user_id: Uuid,
    participants: BTreeMap<String, SyncPlayParticipant>,
    state: serde_json::Value,
    updated_at: OffsetDateTime,
}

#[derive(Debug, Clone)]
struct SyncPlayParticipant {
    user_id: Uuid,
    user_name: String,
    session_id: String,
}

