async fn known_catalog_plugin_or_not_found(
    db: &Database,
    plugin_id: &str,
    version: Option<&str>,
) -> Result<serde_json::Value, ApiError> {
    package_infos_from_repositories(
        &db.system_configuration_payloads()
            .await?
            .plugin_repositories,
    )
    .into_iter()
    .find(|package| {
        package_matches_plugin_id(package, plugin_id)
            && version.is_none_or(|version| {
                package_versions(package).iter().any(|candidate| {
                    json_string_field(candidate, "Version")
                        .is_some_and(|candidate| candidate.eq_ignore_ascii_case(version.trim()))
                })
            })
    })
    .ok_or_else(|| ApiError::not_found("Plugin not found"))
}

async fn plugin_manifest(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    Path(plugin_id): Path<String>,
) -> Result<Json<serde_json::Value>, ApiError> {
    require_admin(&state.db, &headers, query.api_key.as_deref()).await?;
    if let Some(package) = package_infos_from_repositories(
        &state
            .db
            .system_configuration_payloads()
            .await?
            .plugin_repositories,
    )
    .into_iter()
    .find(|package| package_matches_plugin_id(package, &plugin_id))
    {
        return Ok(Json(plugin_manifest_from_package(package)));
    }
    Ok(Json(serde_json::json!({
        "Guid": plugin_id,
        "Name": plugin_id,
        "Overview": "Plugin manifests are not supported by Jellyrin yet.",
        "Description": "Plugin compatibility is intentionally disabled in this milestone.",
        "Owner": "Jellyrin",
        "Category": "General",
        "Versions": []
    })))
}

async fn plugin_manifest_post(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    Path(plugin_id): Path<String>,
) -> Result<Json<serde_json::Value>, ApiError> {
    plugin_manifest(State(state), headers, Query(query), Path(plugin_id)).await
}

fn package_matches_plugin_id(package: &serde_json::Value, plugin_id: &str) -> bool {
    let plugin_id = plugin_id.trim();
    json_string_field(package, "Guid").is_some_and(|guid| guid.eq_ignore_ascii_case(plugin_id))
        || json_string_field(package, "Name").is_some_and(|name| {
            name.eq_ignore_ascii_case(plugin_id)
                || name.replace(' ', "").eq_ignore_ascii_case(plugin_id)
        })
}

fn plugin_manifest_from_package(package: serde_json::Value) -> serde_json::Value {
    let name = json_string_field(&package, "Name").unwrap_or_else(|| "Plugin".to_string());
    let guid =
        json_string_field(&package, "Guid").unwrap_or_else(|| stable_entity_id("Plugin", &name));
    serde_json::json!({
        "Guid": guid,
        "Name": name,
        "Overview": json_string_field(&package, "Overview").unwrap_or_default(),
        "Description": json_string_field(&package, "Description").unwrap_or_default(),
        "Owner": json_string_field(&package, "Owner").unwrap_or_else(|| "Jellyrin".to_string()),
        "Category": json_string_field(&package, "Category").unwrap_or_else(|| "General".to_string()),
        "ImageUrl": json_string_field(&package, "ImageUrl"),
        "Versions": package_versions(&package)
    })
}

async fn plugin_image(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    Path((plugin_id, version)): Path<(String, String)>,
) -> Result<axum::response::Response, ApiError> {
    require_admin(&state.db, &headers, query.api_key.as_deref()).await?;
    if let Some(path) = plugin_image_path_from_catalog(
        &state
            .db
            .system_configuration_payloads()
            .await?
            .plugin_repositories,
        &plugin_id,
        &version,
    ) && tokio::fs::metadata(&path)
        .await
        .map(|metadata| metadata.is_file())
        .unwrap_or(false)
    {
        let content_type = path
            .extension()
            .and_then(|extension| extension.to_str())
            .map(|extension| image_format_from_extension(extension).content_type)
            .unwrap_or("application/octet-stream")
            .to_string();
        return stream_path(path, content_type, &headers, true).await;
    }
    Ok(placeholder_png_response())
}

fn plugin_image_path_from_catalog(
    repositories: &serde_json::Value,
    plugin_id: &str,
    version: &str,
) -> Option<PathBuf> {
    package_infos_from_repositories(repositories)
        .into_iter()
        .find(|package| package_matches_plugin_id(package, plugin_id))
        .and_then(|package| {
            let version_path = package_versions(&package)
                .into_iter()
                .find(|candidate| {
                    json_string_field(candidate, "Version")
                        .is_some_and(|candidate| candidate.eq_ignore_ascii_case(version.trim()))
                })
                .and_then(|candidate| json_string_field(&candidate, "ImagePath"));
            version_path
                .or_else(|| json_string_field(&package, "ImagePath"))
                .map(PathBuf::from)
        })
}

async fn device_info(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(auth_query): Query<AuthQuery>,
    Query(query): Query<DeviceOptionsQuery>,
) -> Result<Json<serde_json::Value>, ApiError> {
    require_admin(&state.db, &headers, auth_query.api_key.as_deref()).await?;
    let device = match trimmed_optional(query.id) {
        Some(id) => state.db.device_session_by_id(&id).await?,
        None => None,
    };
    Ok(Json(
        device
            .as_ref()
            .map(device_to_json)
            .unwrap_or_else(empty_device_info_json),
    ))
}

fn empty_device_info_json() -> serde_json::Value {
    serde_json::json!({
        "Name": null,
        "Id": null,
        "LastUserName": null,
        "AppName": null,
        "AppVersion": null,
        "LastUserId": null,
        "DateLastActivity": null,
        "Capabilities": null
    })
}

fn device_to_json(device: &DeviceSession) -> serde_json::Value {
    serde_json::json!({
        "Name": device.device_name,
        "Id": device.device_id,
        "LastUserName": device.user_name,
        "AppName": device.client,
        "AppVersion": device.version,
        "LastUserId": device.user_id,
        "DateLastActivity": format_time_for_json(device.last_activity_at),
        "Capabilities": device.capabilities.clone()
    })
}

#[derive(Debug, Deserialize)]
struct DeviceOptionsQuery {
    #[serde(alias = "Id", alias = "id")]
    id: Option<String>,
}

#[derive(Debug, Deserialize)]
struct DeviceOptionsUpdate {
    #[serde(alias = "CustomName")]
    custom_name: Option<String>,
}

async fn device_options(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(auth_query): Query<AuthQuery>,
    Query(query): Query<DeviceOptionsQuery>,
) -> Result<Json<serde_json::Value>, ApiError> {
    require_admin(&state.db, &headers, auth_query.api_key.as_deref()).await?;
    let custom_name = if let Some(id) = trimmed_optional(query.id) {
        state
            .db
            .device_session_by_id(&id)
            .await?
            .map(|session| session.device_name)
    } else {
        None
    };
    Ok(Json(serde_json::json!({
        "CustomName": custom_name
    })))
}

async fn update_device_options(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(auth_query): Query<AuthQuery>,
    Query(query): Query<DeviceOptionsQuery>,
    Json(payload): Json<DeviceOptionsUpdate>,
) -> Result<StatusCode, ApiError> {
    let user = require_admin(&state.db, &headers, auth_query.api_key.as_deref()).await?;
    let Some(id) = trimmed_optional(query.id) else {
        return Err(ApiError::bad_request("Device id is required"));
    };
    let Some(custom_name) = trimmed_optional(payload.custom_name) else {
        return Err(ApiError::bad_request("CustomName is required"));
    };
    if state.db.device_session_by_id(&id).await?.is_none() {
        return Err(ApiError::not_found("Device not found"));
    }
    state.db.update_device_name(&id, &custom_name).await?;
    record_activity(
        &state.db,
        "Device options updated",
        Some("A device custom name was updated."),
        "Device",
        Some(user.id),
    )
    .await?;
    Ok(StatusCode::NO_CONTENT)
}

fn trimmed_optional(value: Option<String>) -> Option<String> {
    value
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
}

#[derive(Debug, Deserialize)]
struct DeleteDeviceQuery {
    #[serde(alias = "Id", alias = "id")]
    id: Option<String>,
}

async fn delete_device(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(auth_query): Query<AuthQuery>,
    Query(query): Query<DeleteDeviceQuery>,
) -> Result<StatusCode, ApiError> {
    let user = require_admin(&state.db, &headers, auth_query.api_key.as_deref()).await?;
    if let Some(id) = query
        .id
        .as_deref()
        .map(str::trim)
        .filter(|id| !id.is_empty())
    {
        state.db.revoke_device(id).await?;
        record_activity(
            &state.db,
            "Device deleted",
            Some("A device was revoked."),
            "Device",
            Some(user.id),
        )
        .await?;
    }
    Ok(StatusCode::NO_CONTENT)
}

