#[derive(Debug, Deserialize)]
struct DashboardConfigurationPageQuery {
    #[serde(flatten)]
    auth: AuthQuery,
    #[serde(alias = "Name", alias = "page", alias = "Page")]
    name: Option<String>,
}

#[derive(Debug, Deserialize)]
struct DashboardConfigurationPagesQuery {
    #[serde(flatten)]
    auth: AuthQuery,
    #[serde(alias = "enableInMainMenu", alias = "EnableInMainMenu")]
    enable_in_main_menu: Option<bool>,
}

async fn dashboard_configuration_pages(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<DashboardConfigurationPagesQuery>,
) -> Result<Json<Vec<serde_json::Value>>, ApiError> {
    require_admin(&state.db, &headers, query.auth.api_key.as_deref()).await?;
    let mut pages = discover_dashboard_configuration_pages(&state.web_dir).await?;
    if query.enable_in_main_menu == Some(true) {
        pages.retain(|page| {
            page.get("EnableInMainMenu")
                .and_then(serde_json::Value::as_bool)
                .unwrap_or(false)
        });
    }
    Ok(Json(pages))
}

async fn dashboard_configuration_page(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<DashboardConfigurationPageQuery>,
) -> Result<axum::response::Response, ApiError> {
    require_admin(&state.db, &headers, query.auth.api_key.as_deref()).await?;
    let name = query
        .name
        .as_deref()
        .map(str::trim)
        .filter(|name| !name.is_empty())
        .ok_or_else(|| ApiError::bad_request("Configuration page name is required"))?;
    let relative_path = safe_web_relative_path(name)?;
    let path = state.web_dir.join(relative_path);
    let bytes = tokio::fs::read(&path)
        .await
        .map_err(|error| match error.kind() {
            std::io::ErrorKind::NotFound => ApiError::not_found("Configuration page not found"),
            _ => error.into(),
        })?;
    let mut headers = HeaderMap::new();
    headers.insert(
        header::CONTENT_TYPE,
        web_content_type_for_path(&path).parse().unwrap(),
    );
    headers.insert(header::CACHE_CONTROL, "no-cache".parse().unwrap());
    Ok((headers, bytes).into_response())
}

async fn discover_dashboard_configuration_pages(
    web_dir: &FsPath,
) -> Result<Vec<serde_json::Value>, ApiError> {
    let mut read_dir = match tokio::fs::read_dir(web_dir).await {
        Ok(read_dir) => read_dir,
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => return Ok(Vec::new()),
        Err(error) => return Err(error.into()),
    };
    let mut pages = Vec::new();
    while let Some(entry) = read_dir.next_entry().await? {
        if !entry.file_type().await?.is_file() {
            continue;
        }
        let path = entry.path();
        let Some(file_name) = path.file_name().and_then(|name| name.to_str()) else {
            continue;
        };
        if !is_dashboard_configuration_page_name(file_name) {
            continue;
        }
        pages.push(dashboard_configuration_page_json(file_name));
    }
    pages.sort_by(|left, right| {
        let left = left
            .get("Name")
            .and_then(serde_json::Value::as_str)
            .unwrap_or_default();
        let right = right
            .get("Name")
            .and_then(serde_json::Value::as_str)
            .unwrap_or_default();
        left.cmp(right)
    });
    Ok(pages)
}

fn is_dashboard_configuration_page_name(file_name: &str) -> bool {
    let path = FsPath::new(file_name);
    matches!(
        path.extension()
            .and_then(|extension| extension.to_str())
            .map(|extension| extension.to_ascii_lowercase()),
        Some(extension) if extension == "html" || extension == "htm"
    )
}

fn dashboard_configuration_page_json(file_name: &str) -> serde_json::Value {
    serde_json::json!({
        "Name": file_name,
        "DisplayName": dashboard_configuration_page_display_name(file_name),
        "PluginId": null,
        "EnableInMainMenu": dashboard_configuration_page_in_main_menu(file_name),
        "MenuSection": "server",
        "MenuIcon": "settings",
        "EmbeddedResourcePath": null
    })
}

fn dashboard_configuration_page_in_main_menu(file_name: &str) -> bool {
    matches!(
        FsPath::new(file_name)
            .file_stem()
            .and_then(|stem| stem.to_str())
            .map(|stem| stem.to_ascii_lowercase()),
        Some(stem) if stem == "home" || stem == "dashboard"
    )
}

fn dashboard_configuration_page_display_name(file_name: &str) -> String {
    let stem = FsPath::new(file_name)
        .file_stem()
        .and_then(|stem| stem.to_str())
        .unwrap_or(file_name);
    stem.split(['-', '_', '.'])
        .filter(|part| !part.is_empty())
        .map(|part| {
            let mut chars = part.chars();
            match chars.next() {
                Some(first) => {
                    first.to_ascii_uppercase().to_string() + &chars.as_str().to_ascii_lowercase()
                }
                None => String::new(),
            }
        })
        .collect::<Vec<_>>()
        .join(" ")
}

fn safe_web_relative_path(name: &str) -> Result<PathBuf, ApiError> {
    let path = FsPath::new(name);
    if path.is_absolute() {
        return Err(ApiError::bad_request("Invalid configuration page name"));
    }
    let mut safe = PathBuf::new();
    for component in path.components() {
        match component {
            std::path::Component::Normal(part) => safe.push(part),
            std::path::Component::CurDir => {}
            _ => return Err(ApiError::bad_request("Invalid configuration page name")),
        }
    }
    if safe.as_os_str().is_empty() {
        return Err(ApiError::bad_request("Invalid configuration page name"));
    }
    Ok(safe)
}

fn web_content_type_for_path(path: &FsPath) -> &'static str {
    match path
        .extension()
        .and_then(|extension| extension.to_str())
        .unwrap_or_default()
        .to_ascii_lowercase()
        .as_str()
    {
        "html" | "htm" => "text/html; charset=utf-8",
        "css" => "text/css; charset=utf-8",
        "js" | "mjs" => "application/javascript; charset=utf-8",
        "json" => "application/json; charset=utf-8",
        "txt" => "text/plain; charset=utf-8",
        _ => "application/octet-stream",
    }
}

const LIBRARY_SCAN_TASK_ID: &str = "scan-media-library";
const LIBRARY_SCAN_TASK_KEY: &str = "RefreshLibrary";
const STALE_TASK_HOURS: i64 = 24;

async fn scheduled_tasks(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
) -> Result<Json<Vec<serde_json::Value>>, ApiError> {
    require_admin(&state.db, &headers, query.api_key.as_deref()).await?;
    recover_stale_library_scan_runs(&state.db).await?;
    Ok(Json(vec![library_scan_task_json(&state.db).await?]))
}

async fn scheduled_task(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    Path(task_id): Path<String>,
) -> Result<Json<serde_json::Value>, ApiError> {
    require_admin(&state.db, &headers, query.api_key.as_deref()).await?;
    recover_stale_library_scan_runs(&state.db).await?;
    if is_library_scan_task(&task_id) {
        return Ok(Json(library_scan_task_json(&state.db).await?));
    }

    Err(ApiError::not_found("Scheduled task not found"))
}

async fn start_scheduled_task(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    Path(task_id): Path<String>,
) -> Result<StatusCode, ApiError> {
    require_admin(&state.db, &headers, query.api_key.as_deref()).await?;
    if is_library_scan_task(&task_id) {
        recover_stale_library_scan_runs(&state.db).await?;
        let run = match state.db.start_task_run(LIBRARY_SCAN_TASK_KEY).await {
            Ok(run) => run,
            Err(error) if format!("{error:#}").contains("task is already running") => {
                return Ok(StatusCode::NO_CONTENT);
            }
            Err(error)
                if state
                    .db
                    .current_task_run(LIBRARY_SCAN_TASK_KEY)
                    .await?
                    .is_some() =>
            {
                let _ = error;
                return Ok(StatusCode::NO_CONTENT);
            }
            Err(error) => return Err(error.into()),
        };
        let db = state.db.clone();
        tokio::spawn(async move {
            match scan_all_library_items(&db).await {
                Ok(scanned_count) => {
                    let _ = db
                        .complete_task_run(
                            run.id,
                            serde_json::json!({
                                "ItemsScanned": scanned_count,
                            }),
                        )
                        .await;
                }
                Err(error) => {
                    let message = format!("{error:?}");
                    let _ = db.fail_task_run(run.id, &message).await;
                }
            }
        });
        return Ok(StatusCode::NO_CONTENT);
    }

    Err(ApiError::not_found("Scheduled task not found"))
}

async fn stop_scheduled_task(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    Path(task_id): Path<String>,
) -> Result<StatusCode, ApiError> {
    require_admin(&state.db, &headers, query.api_key.as_deref()).await?;
    if is_library_scan_task(&task_id) {
        state
            .db
            .fail_current_task_run(LIBRARY_SCAN_TASK_KEY, "Task run cancelled.")
            .await?;
        return Ok(StatusCode::NO_CONTENT);
    }

    Err(ApiError::not_found("Scheduled task not found"))
}

async fn update_scheduled_task_triggers(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    Path(task_id): Path<String>,
    Json(_triggers): Json<serde_json::Value>,
) -> Result<StatusCode, ApiError> {
    require_admin(&state.db, &headers, query.api_key.as_deref()).await?;
    if is_library_scan_task(&task_id) {
        return Ok(StatusCode::NO_CONTENT);
    }

    Err(ApiError::not_found("Scheduled task not found"))
}

async fn recover_stale_library_scan_runs(db: &Database) -> Result<(), ApiError> {
    db.fail_stale_task_runs(
        LIBRARY_SCAN_TASK_KEY,
        Duration::hours(STALE_TASK_HOURS),
        "Task run expired before completion.",
    )
    .await?;
    Ok(())
}

async fn refresh_library(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
) -> Result<StatusCode, ApiError> {
    let user = require_request_user(&state.db, &headers, query.api_key.as_deref()).await?;
    if !user.is_administrator {
        return Err(ApiError::forbidden("Administrator access required"));
    }
    let scanned = scan_all_library_items(&state.db).await?;
    record_activity(
        &state.db,
        "Library scan completed",
        Some(&format!("Library refresh scanned {scanned} item(s).")),
        "Library",
        Some(user.id),
    )
    .await?;
    Ok(StatusCode::NO_CONTENT)
}

