fn broadcast_general_command(
    target_session: &DeviceSession,
    auth_user: &User,
    command: &str,
    arguments: serde_json::Map<String, serde_json::Value>,
) {
    let mut data = serde_json::Map::new();
    data.insert(
        "Name".to_string(),
        serde_json::Value::String(command.to_string()),
    );
    data.insert(
        "ControllingUserId".to_string(),
        serde_json::Value::String(auth_user.id.simple().to_string()),
    );
    data.insert(
        "Arguments".to_string(),
        serde_json::Value::Object(arguments),
    );
    broadcast_session_message(
        &target_session.access_token,
        serde_json::json!({
            "MessageType": "GeneralCommand",
            "Data": data
        }),
    );
}

async fn apply_general_command_side_effect(
    db: &Database,
    target_session: &DeviceSession,
    auth_user: &User,
    command: &str,
    arguments: &serde_json::Map<String, serde_json::Value>,
) -> Result<(), ApiError> {
    if !command.eq_ignore_ascii_case("DisplayContent") {
        return Ok(());
    }
    let payload = display_content_payload(
        db,
        DisplayContentQuery::default(),
        Some(serde_json::Value::Object(arguments.clone())),
    )
    .await?;
    persist_session_viewing(db, target_session, &payload).await?;
    broadcast_session_message(
        &target_session.access_token,
        serde_json::json!({
            "MessageType": "Browse",
            "Data": {
                "ItemId": payload.item_id,
                "ItemName": payload.item_name,
                "ItemType": payload.item_type,
                "ControllingUserId": auth_user.id.simple().to_string()
            }
        }),
    );
    broadcast_sessions_message(db, &target_session.access_token, auth_user).await
}

#[derive(Debug, Default, Deserialize)]
struct DisplayContentQuery {
    #[serde(flatten)]
    auth: AuthQuery,
    #[serde(alias = "ItemId", alias = "itemId")]
    item_id: Option<String>,
    #[serde(alias = "ItemName", alias = "itemName")]
    item_name: Option<String>,
    #[serde(alias = "ItemType", alias = "itemType")]
    item_type: Option<String>,
}

async fn display_content(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<DisplayContentQuery>,
    Path(session_id): Path<String>,
    body: Option<Json<serde_json::Value>>,
) -> Result<StatusCode, ApiError> {
    let (auth_user, target_session) =
        command_target_session(&state, &headers, &query.auth, &session_id).await?;
    let body = body.map(|Json(value)| value);
    let payload = display_content_payload(&state.db, query, body).await?;
    persist_session_viewing(&state.db, &target_session, &payload).await?;
    broadcast_session_message(
        &target_session.access_token,
        serde_json::json!({
            "MessageType": "Browse",
            "Data": {
                "ItemId": payload.item_id,
                "ItemName": payload.item_name,
                "ItemType": payload.item_type,
                "ControllingUserId": auth_user.id.simple().to_string()
            }
        }),
    );
    broadcast_sessions_message(&state.db, &target_session.access_token, &auth_user).await?;
    Ok(StatusCode::NO_CONTENT)
}

#[derive(Debug, Default, Deserialize)]
struct ReportViewingQuery {
    #[serde(flatten)]
    auth: AuthQuery,
    #[serde(alias = "SessionId", alias = "sessionId")]
    session_id: Option<String>,
    #[serde(alias = "ItemId", alias = "itemId")]
    item_id: Option<String>,
    #[serde(alias = "ItemName", alias = "itemName")]
    item_name: Option<String>,
    #[serde(alias = "ItemType", alias = "itemType")]
    item_type: Option<String>,
}

async fn report_viewing(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<ReportViewingQuery>,
    body: Option<Json<serde_json::Value>>,
) -> Result<StatusCode, ApiError> {
    let (auth_user, token) =
        require_user(&state.db, &headers, query.auth.api_key.as_deref()).await?;
    let target_session_id = query
        .session_id
        .clone()
        .unwrap_or_else(|| token.access_token.clone());
    let target_session = state
        .db
        .device_session_by_id(&target_session_id)
        .await?
        .ok_or_else(|| ApiError::not_found("Device session not found"))?;
    ensure_user_access(&auth_user, target_session.user_id)?;

    let body = body.map(|Json(value)| value);
    let payload = display_content_payload(
        &state.db,
        DisplayContentQuery {
            auth: AuthQuery::default(),
            item_id: query.item_id,
            item_name: query.item_name,
            item_type: query.item_type,
        },
        body,
    )
    .await?;
    persist_session_viewing(&state.db, &target_session, &payload).await?;
    broadcast_session_message(
        &target_session.access_token,
        serde_json::json!({
            "MessageType": "Browse",
            "Data": {
                "ItemId": payload.item_id,
                "ItemName": payload.item_name,
                "ItemType": payload.item_type,
                "ControllingUserId": auth_user.id.simple().to_string()
            }
        }),
    );
    broadcast_sessions_message(&state.db, &target_session.access_token, &auth_user).await?;
    Ok(StatusCode::NO_CONTENT)
}

async fn persist_session_viewing(
    db: &Database,
    target_session: &DeviceSession,
    payload: &DisplayContentPayload,
) -> Result<(), ApiError> {
    let Some(item_id) = payload.item_id.as_deref() else {
        db.clear_active_viewing_session(&target_session.access_token)
            .await?;
        return Ok(());
    };
    db.upsert_active_viewing_session(UpsertActiveViewingSession {
        session_id: target_session.access_token.clone(),
        user_id: target_session.user_id,
        item_id: parse_jellyfin_uuid(item_id)?,
    })
    .await?;
    Ok(())
}

#[derive(Debug, Default)]
struct DisplayContentPayload {
    item_id: Option<String>,
    item_name: Option<String>,
    item_type: Option<String>,
}

async fn display_content_payload(
    db: &Database,
    query: DisplayContentQuery,
    body: Option<serde_json::Value>,
) -> Result<DisplayContentPayload, ApiError> {
    let body_object = body.as_ref().and_then(|value| value.as_object());
    let item_id = query.item_id.or_else(|| {
        body_object.and_then(|object| json_object_string_field(object, &["ItemId", "itemId"]))
    });
    let mut item_name = query.item_name.or_else(|| {
        body_object.and_then(|object| json_object_string_field(object, &["ItemName", "itemName"]))
    });
    let mut item_type = query.item_type.or_else(|| {
        body_object.and_then(|object| json_object_string_field(object, &["ItemType", "itemType"]))
    });

    if let Some(item_id) = item_id.as_deref() {
        let item = media_item_by_id(db, item_id).await?;
        if item_name.as_deref().is_none_or(str::is_empty) {
            item_name = Some(item.name.clone());
        }
        if item_type.as_deref().is_none_or(str::is_empty) {
            item_type = Some(media_item_type(&item).to_string());
        }
    }

    Ok(DisplayContentPayload {
        item_id,
        item_name,
        item_type,
    })
}

fn json_object_string_field(
    object: &serde_json::Map<String, serde_json::Value>,
    names: &[&str],
) -> Option<String> {
    names.iter().find_map(|name| {
        object
            .get(*name)
            .and_then(|value| value.as_str())
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(ToOwned::to_owned)
    })
}

async fn send_message_command(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(auth_query): Query<AuthQuery>,
    Path(session_id): Path<String>,
    body: Option<Json<serde_json::Value>>,
) -> Result<StatusCode, ApiError> {
    let (auth_user, target_session) =
        command_target_session(&state, &headers, &auth_query, &session_id).await?;
    ensure_session_supports_command(&target_session, "DisplayMessage")?;
    let payload = body
        .map(|Json(value)| value)
        .unwrap_or_else(|| serde_json::Value::Object(serde_json::Map::new()));
    let object = payload
        .as_object()
        .ok_or_else(|| ApiError::bad_request("Message body must be an object"))?;
    let message = message_command_payload(object)?;
    let mut data = serde_json::Map::new();
    data.insert(
        "Header".to_string(),
        message
            .header
            .map(serde_json::Value::String)
            .unwrap_or(serde_json::Value::Null),
    );
    data.insert("Text".to_string(), serde_json::Value::String(message.text));
    data.insert(
        "TimeoutMs".to_string(),
        message
            .timeout_ms
            .map(serde_json::Value::Number)
            .unwrap_or(serde_json::Value::Null),
    );
    data.insert(
        "ControllingUserId".to_string(),
        serde_json::Value::String(auth_user.id.simple().to_string()),
    );
    broadcast_session_message(
        &target_session.access_token,
        serde_json::json!({
            "MessageType": "MessageCommand",
            "Data": data
        }),
    );
    Ok(StatusCode::NO_CONTENT)
}

struct MessageCommandPayload {
    header: Option<String>,
    text: String,
    timeout_ms: Option<serde_json::Number>,
}

fn message_command_payload(
    object: &serde_json::Map<String, serde_json::Value>,
) -> Result<MessageCommandPayload, ApiError> {
    let header = json_object_string_field(object, &["Header", "header"]);
    let text = json_object_string_field(object, &["Text", "text"])
        .ok_or_else(|| ApiError::bad_request("Text is required"))?;
    let timeout_ms = object
        .get("TimeoutMs")
        .or_else(|| object.get("timeoutMs"))
        .or_else(|| object.get("Timeout"))
        .or_else(|| object.get("timeout"))
        .map(json_value_non_negative_i64)
        .transpose()?
        .map(serde_json::Number::from);
    Ok(MessageCommandPayload {
        header,
        text,
        timeout_ms,
    })
}

fn json_value_non_negative_i64(value: &serde_json::Value) -> Result<i64, ApiError> {
    let parsed = if let Some(value) = value.as_i64() {
        Some(value)
    } else if let Some(value) = value.as_str() {
        value.trim().parse::<i64>().ok()
    } else {
        None
    };
    match parsed {
        Some(value) if value >= 0 => Ok(value),
        _ => Err(ApiError::bad_request(
            "TimeoutMs must be a non-negative integer",
        )),
    }
}

async fn add_user_to_session(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(auth_query): Query<AuthQuery>,
    Path((session_id, user_id)): Path<(String, String)>,
) -> Result<StatusCode, ApiError> {
    modify_session_user(state, headers, auth_query, session_id, user_id, true).await
}

async fn remove_user_from_session(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(auth_query): Query<AuthQuery>,
    Path((session_id, user_id)): Path<(String, String)>,
) -> Result<StatusCode, ApiError> {
    modify_session_user(state, headers, auth_query, session_id, user_id, false).await
}

async fn modify_session_user(
    state: AppState,
    headers: HeaderMap,
    auth_query: AuthQuery,
    session_id: String,
    user_id: String,
    add_user: bool,
) -> Result<StatusCode, ApiError> {
    let (auth_user, target_session) =
        command_target_session(&state, &headers, &auth_query, &session_id).await?;
    let requested_user_id = Uuid::parse_str(&user_id)
        .or_else(|_| Uuid::parse_str(&hyphenate_uuid(&user_id)))
        .map_err(|_| ApiError::bad_request("Invalid user id"))?;
    let requested_user = state
        .db
        .user_by_id(requested_user_id)
        .await
        .map_err(|_| ApiError::not_found("User not found"))?;
    if add_user {
        state
            .db
            .add_session_user(&target_session.access_token, requested_user_id)
            .await?;
    } else {
        state
            .db
            .remove_session_user(&target_session.access_token, requested_user_id)
            .await?;
    }
    broadcast_sessions_message(&state.db, &target_session.access_token, &auth_user).await?;
    broadcast_sessions_message_to_user_owned_sessions(
        &state.db,
        &requested_user,
        Some(&target_session.access_token),
    )
    .await?;
    Ok(StatusCode::NO_CONTENT)
}

fn canonical_playstate_command(command: &str) -> Result<&'static str, ApiError> {
    match command.to_ascii_lowercase().as_str() {
        "stop" => Ok("Stop"),
        "pause" => Ok("Pause"),
        "unpause" => Ok("Unpause"),
        "playpause" => Ok("PlayPause"),
        "seek" => Ok("Seek"),
        "nexttrack" => Ok("NextTrack"),
        "previoustrack" => Ok("PreviousTrack"),
        "rewind" => Ok("Rewind"),
        "fastforward" => Ok("FastForward"),
        _ => Err(ApiError::bad_request("Unsupported PlaystateCommand")),
    }
}

fn parse_send_playstate_command_query(raw_query: Option<&str>) -> SendPlaystateCommandQuery {
    let mut query = SendPlaystateCommandQuery::default();
    let Some(raw_query) = raw_query else {
        return query;
    };

    for part in raw_query.split('&').filter(|part| !part.is_empty()) {
        let (key, value) = part.split_once('=').unwrap_or((part, ""));
        let key = percent_decode_query_component(key).to_ascii_lowercase();
        let value = percent_decode_query_component(value);
        if key == "seekpositionticks" {
            query.seek_position_ticks = value.parse().ok();
        }
    }

    query
}

async fn quick_connect_enabled(State(state): State<AppState>) -> Result<Json<bool>, ApiError> {
    Ok(Json(quick_connect_available(&state.db).await?))
}

async fn quick_connect_available(db: &Database) -> Result<bool, ApiError> {
    let mut server_options = default_server_configuration_options();
    if let serde_json::Value::Object(current) =
        db.system_configuration_payloads().await?.server_options
    {
        for (key, value) in current {
            server_options[key] = value;
        }
    }
    Ok(server_options["QuickConnectAvailable"]
        .as_bool()
        .unwrap_or(true))
}

async fn require_quick_connect_available(db: &Database) -> Result<(), ApiError> {
    if quick_connect_available(db).await? {
        Ok(())
    } else {
        Err(ApiError::forbidden("QuickConnect is disabled"))
    }
}

async fn initiate_quick_connect(
    State(state): State<AppState>,
    headers: HeaderMap,
) -> Result<Json<serde_json::Value>, ApiError> {
    require_quick_connect_available(&state.db).await?;
    let auth = client_auth_from_headers(&headers);
    let session = state
        .db
        .initiate_quick_connect(&auth.device_id, &auth.device, &auth.client, &auth.version)
        .await?;
    Ok(Json(quick_connect_json(&session)))
}

#[derive(Debug, Deserialize)]
struct QuickConnectSecretQuery {
    #[serde(alias = "Secret", alias = "secret")]
    secret: String,
}

async fn get_quick_connect_state(
    State(state): State<AppState>,
    Query(query): Query<QuickConnectSecretQuery>,
) -> Result<Json<serde_json::Value>, ApiError> {
    let session = state
        .db
        .quick_connect_by_secret(&query.secret)
        .await
        .map_err(|_| ApiError::not_found("QuickConnect session not found"))?;
    Ok(Json(quick_connect_json(&session)))
}

#[derive(Debug, Deserialize, Default)]
struct QuickConnectCodePayload {
    #[serde(alias = "Code", alias = "code")]
    code: Option<String>,
}

#[derive(Debug, Deserialize)]
struct QuickConnectAuthorizeQuery {
    #[serde(flatten)]
    auth: AuthQuery,
    #[serde(alias = "Code", alias = "code")]
    code: Option<String>,
}

async fn authorize_quick_connect(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<QuickConnectAuthorizeQuery>,
    body: Option<Json<QuickConnectCodePayload>>,
) -> Result<Json<bool>, ApiError> {
    require_quick_connect_available(&state.db).await?;
    let user = require_request_user(&state.db, &headers, query.auth.api_key.as_deref()).await?;
    let code = query
        .code
        .as_deref()
        .or_else(|| body.as_ref().and_then(|body| body.code.as_deref()))
        .map(str::trim)
        .filter(|code| !code.is_empty())
        .ok_or_else(|| ApiError::bad_request("Code must not be empty"))?;
    state
        .db
        .authorize_quick_connect(code, user.id)
        .await
        .map_err(|_| ApiError::not_found("QuickConnect code not found"))?;
    Ok(Json(true))
}

#[derive(Debug, Deserialize)]
struct AuthenticateQuickConnectBody {
    #[serde(alias = "Secret", alias = "secret")]
    secret: String,
}

async fn authenticate_with_quick_connect(
    State(state): State<AppState>,
    Json(payload): Json<AuthenticateQuickConnectBody>,
) -> Result<Json<AuthenticationResultDto>, ApiError> {
    require_quick_connect_available(&state.db).await?;
    let session = state
        .db
        .quick_connect_by_secret(&payload.secret)
        .await
        .map_err(|_| ApiError::unauthorized("QuickConnect authorization is not complete"))?;
    if !session.authorized || session.expires_at <= OffsetDateTime::now_utc() {
        return Err(ApiError::unauthorized(
            "QuickConnect authorization is not complete",
        ));
    }
    let user_id = session
        .user_id
        .ok_or_else(|| ApiError::unauthorized("QuickConnect authorization is not complete"))?;
    let (user, token) = state
        .db
        .issue_device_token_for_user(
            user_id,
            &session.device_id,
            &session.device_name,
            &session.client,
            &session.version,
        )
        .await
        .map_err(|_| ApiError::unauthorized("QuickConnect authorization is not complete"))?;
    state
        .db
        .delete_quick_connect_session(&session.secret)
        .await?;
    let server = state.db.server_state().await?;
    Ok(Json(
        authentication_result_to_dto(&state.db, &user, &token, server.server_id).await?,
    ))
}

fn quick_connect_json(session: &QuickConnectSession) -> serde_json::Value {
    serde_json::json!({
        "Secret": session.secret,
        "Code": session.code,
        "DateAdded": format_time_for_json(session.created_at),
        "DateUpdated": format_time_for_json(session.updated_at),
        "DateExpires": format_time_for_json(session.expires_at),
        "Authenticated": session.authorized,
        "UserId": session.user_id.map(|id| id.simple().to_string())
    })
}

fn syncplay_groups() -> &'static Mutex<HashMap<String, SyncPlayGroup>> {
    SYNCPLAY_GROUPS.get_or_init(|| Mutex::new(HashMap::new()))
}

async fn optional_json_body(body: Body) -> Result<serde_json::Value, ApiError> {
    let bytes = to_bytes(body, SYNCPLAY_REQUEST_LIMIT_BYTES).await?;
    if bytes.is_empty() {
        return Ok(serde_json::json!({}));
    }
    serde_json::from_slice(&bytes).map_err(|_| ApiError::bad_request("Invalid JSON body"))
}

fn json_string_any_field(payload: &serde_json::Value, keys: &[&str]) -> Option<String> {
    keys.iter().find_map(|key| {
        payload
            .get(*key)
            .and_then(serde_json::Value::as_str)
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(ToOwned::to_owned)
    })
}

fn syncplay_participant(user: &User, token: &DeviceToken) -> SyncPlayParticipant {
    SyncPlayParticipant {
        user_id: user.id,
        user_name: user.name.clone(),
        session_id: token.access_token.clone(),
    }
}

fn syncplay_group_json(group: &SyncPlayGroup) -> serde_json::Value {
    let participants = group
        .participants
        .values()
        .map(|participant| {
            serde_json::json!({
                "UserId": participant.user_id,
                "UserName": participant.user_name,
                "SessionId": participant.session_id,
                "IsGroupOwner": participant.user_id == group.owner_user_id
            })
        })
        .collect::<Vec<_>>();
    serde_json::json!({
        "GroupId": group.id,
        "Id": group.id,
        "Name": group.name,
        "Participants": participants,
        "State": group.state,
        "LastActivityDate": format_time_for_json(group.updated_at)
    })
}

async fn syncplay_list(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
) -> Result<Json<Vec<serde_json::Value>>, ApiError> {
    require_request_user(&state.db, &headers, query.api_key.as_deref()).await?;
    let groups = syncplay_groups().lock().await;
    Ok(Json(groups.values().map(syncplay_group_json).collect()))
}

async fn syncplay_group(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    Path(id): Path<String>,
) -> Result<Json<serde_json::Value>, ApiError> {
    require_request_user(&state.db, &headers, query.api_key.as_deref()).await?;
    let groups = syncplay_groups().lock().await;
    let group = groups
        .get(id.trim())
        .ok_or_else(|| ApiError::not_found("SyncPlay group not found"))?;
    Ok(Json(syncplay_group_json(group)))
}

async fn syncplay_new(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    body: Body,
) -> Result<Json<serde_json::Value>, ApiError> {
    let (user, token) = require_user(&state.db, &headers, query.api_key.as_deref()).await?;
    let payload = optional_json_body(body).await?;
    let group_id = json_string_any_field(&payload, &["GroupId", "Id"])
        .unwrap_or_else(|| Uuid::new_v4().to_string());
    let name = json_string_any_field(&payload, &["Name", "GroupName"])
        .unwrap_or_else(|| format!("{}'s group", user.name));
    let participant = syncplay_participant(&user, &token);
    let mut participants = BTreeMap::new();
    participants.insert(participant.session_id.clone(), participant);
    let group = SyncPlayGroup {
        id: group_id.clone(),
        name,
        owner_user_id: user.id,
        participants,
        state: serde_json::json!({
            "PlayState": "Idle",
            "PositionTicks": 0,
            "IsPaused": false,
            "Queue": []
        }),
        updated_at: OffsetDateTime::now_utc(),
    };
    let response = syncplay_group_json(&group);
    syncplay_groups().lock().await.insert(group_id, group);
    Ok(Json(response))
}

async fn syncplay_join(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    body: Body,
) -> Result<Json<serde_json::Value>, ApiError> {
    let (user, token) = require_user(&state.db, &headers, query.api_key.as_deref()).await?;
    let payload = optional_json_body(body).await?;
    let group_id = json_string_any_field(&payload, &["GroupId", "Id"])
        .ok_or_else(|| ApiError::bad_request("SyncPlay group id is required"))?;
    let (group_json, participant_session_ids) = {
        let mut groups = syncplay_groups().lock().await;
        let group = groups
            .get_mut(group_id.trim())
            .ok_or_else(|| ApiError::not_found("SyncPlay group not found"))?;
        let participant = syncplay_participant(&user, &token);
        group
            .participants
            .insert(participant.session_id.clone(), participant);
        group.updated_at = OffsetDateTime::now_utc();
        (
            syncplay_group_json(group),
            group.participants.keys().cloned().collect::<Vec<_>>(),
        )
    };
    broadcast_syncplay_group_update(&participant_session_ids, &group_json, "Join");
    Ok(Json(group_json))
}

async fn syncplay_leave(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
) -> Result<StatusCode, ApiError> {
    let (_user, token) = require_user(&state.db, &headers, query.api_key.as_deref()).await?;
    let mut updates = Vec::new();
    {
        let mut groups = syncplay_groups().lock().await;
        let mut empty_groups = Vec::new();
        for group in groups.values_mut() {
            if group.participants.remove(&token.access_token).is_some() {
                group.updated_at = OffsetDateTime::now_utc();
                if group.participants.is_empty() {
                    empty_groups.push(group.id.clone());
                } else {
                    updates.push((
                        syncplay_group_json(group),
                        group.participants.keys().cloned().collect::<Vec<_>>(),
                    ));
                }
            }
        }
        for group_id in empty_groups {
            groups.remove(&group_id);
        }
    }
    for (group_json, participant_session_ids) in updates {
        broadcast_syncplay_group_update(&participant_session_ids, &group_json, "Leave");
    }
    Ok(StatusCode::NO_CONTENT)
}

