async fn live_tv_programs_post(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    body: Body,
) -> Result<Json<serde_json::Value>, ApiError> {
    require_request_user(&state.db, &headers, query.api_key.as_deref()).await?;
    let payload = optional_json_body(body).await?;
    let channel_ids = json_string_list_field(&payload, "ChannelIds").unwrap_or_default();
    live_tv_program_result(&state.db, &channel_ids).await
}

async fn live_tv_program(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    Path(program_id): Path<String>,
) -> Result<Json<serde_json::Value>, ApiError> {
    require_request_user(&state.db, &headers, query.api_key.as_deref()).await?;
    let config = state
        .db
        .named_configuration("livetv")
        .await?
        .unwrap_or_else(default_live_tv_configuration);
    let program = live_tv_program_items(&config)
        .into_iter()
        .find(|program| {
            json_string_field(program, "Id")
                .is_some_and(|id| id.eq_ignore_ascii_case(program_id.trim()))
        })
        .ok_or_else(|| ApiError::not_found("Live TV item not found"))?;
    Ok(Json(program))
}

async fn live_tv_program_result(
    db: &Database,
    channel_ids: &[String],
) -> Result<Json<serde_json::Value>, ApiError> {
    let config = db
        .named_configuration("livetv")
        .await?
        .unwrap_or_else(default_live_tv_configuration);
    let mut programs = live_tv_program_items(&config);
    if !channel_ids.is_empty() {
        programs.retain(|program| {
            json_string_field(program, "ChannelId").is_some_and(|channel_id| {
                channel_ids
                    .iter()
                    .any(|requested| requested.eq_ignore_ascii_case(&channel_id))
            })
        });
    }
    Ok(Json(query_result(programs)))
}

async fn live_tv_recording_stream(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    Path(recording_id): Path<String>,
) -> Result<axum::response::Response, ApiError> {
    require_request_user(&state.db, &headers, query.api_key.as_deref()).await?;
    let recording = live_tv_recording_by_id(&state.db, &recording_id).await?;
    stream_live_tv_recording(recording, &headers).await
}

async fn live_tv_stream_file(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    Path((stream_id, container)): Path<(String, String)>,
) -> Result<axum::response::Response, ApiError> {
    require_request_user(&state.db, &headers, query.api_key.as_deref()).await?;
    if let Ok(recording) = live_tv_recording_by_id(&state.db, &stream_id).await {
        let path = live_tv_recording_path(&recording)?;
        let path_container = path
            .extension()
            .and_then(|extension| extension.to_str())
            .unwrap_or_default();
        if !path_container.eq_ignore_ascii_case(container.trim()) {
            return Err(ApiError::not_found("Live TV stream not found"));
        }
        return stream_live_tv_recording(recording, &headers).await;
    }
    let channel = live_tv_channel_by_id(&state.db, &stream_id).await?;
    let path = live_tv_channel_path(&channel)?;
    let path_container = path
        .extension()
        .and_then(|extension| extension.to_str())
        .unwrap_or_default();
    if !path_container.eq_ignore_ascii_case(container.trim()) {
        return Err(ApiError::not_found("Live TV stream not found"));
    }
    stream_live_tv_channel(channel, &headers).await
}

