fn comma_delimited_values(value: &str) -> Vec<String> {
    value
        .split(',')
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(ToOwned::to_owned)
        .collect()
}

fn json_string_list_field(value: &serde_json::Value, field: &str) -> Option<Vec<String>> {
    let value = json_field_case_insensitive(value, field)?;
    match value {
        serde_json::Value::Array(values) => Some(
            values
                .iter()
                .filter_map(serde_json::Value::as_str)
                .map(str::trim)
                .filter(|value| !value.is_empty())
                .map(ToOwned::to_owned)
                .collect(),
        ),
        serde_json::Value::String(value) => Some(comma_delimited_values(value)),
        _ => None,
    }
}

fn live_tv_channel_items(config: &serde_json::Value) -> Vec<serde_json::Value> {
    let mut channels = Vec::new();
    let Some(tuner_hosts) = config
        .get("TunerHosts")
        .and_then(serde_json::Value::as_array)
    else {
        return channels;
    };

    for (tuner_index, tuner) in tuner_hosts.iter().enumerate() {
        let tuner_id =
            json_string_field(tuner, "Id").unwrap_or_else(|| format!("tuner-{tuner_index}"));
        let tuner_name = json_string_field(tuner, "FriendlyName")
            .or_else(|| json_string_field(tuner, "Name"))
            .or_else(|| json_string_field(tuner, "Url"))
            .unwrap_or_else(|| tuner_id.clone());
        let Some(tuner_channels) = tuner.get("Channels").and_then(serde_json::Value::as_array)
        else {
            continue;
        };
        for (channel_index, channel) in tuner_channels.iter().enumerate() {
            if let Some(channel) =
                live_tv_channel_item(&tuner_id, &tuner_name, channel, channel_index)
            {
                channels.push(channel);
            }
        }
    }
    channels.sort_by(|left, right| {
        let left_sort = json_string_field(left, "SortName")
            .or_else(|| json_string_field(left, "Name"))
            .unwrap_or_default();
        let right_sort = json_string_field(right, "SortName")
            .or_else(|| json_string_field(right, "Name"))
            .unwrap_or_default();
        left_sort
            .to_ascii_lowercase()
            .cmp(&right_sort.to_ascii_lowercase())
    });
    channels
}

fn live_tv_channel_item(
    tuner_id: &str,
    tuner_name: &str,
    channel: &serde_json::Value,
    index: usize,
) -> Option<serde_json::Value> {
    let (mut base, raw_name) = match channel {
        serde_json::Value::Object(fields) => (serde_json::Value::Object(fields.clone()), None),
        serde_json::Value::String(name) => (serde_json::json!({}), Some(name.trim().to_string())),
        _ => return None,
    };
    let name = json_string_field(&base, "Name")
        .or_else(|| json_string_field(&base, "DisplayName"))
        .or(raw_name)
        .filter(|name| !name.is_empty())
        .unwrap_or_else(|| format!("Channel {}", index + 1));
    let number = json_string_field(&base, "Number")
        .or_else(|| json_string_field(&base, "ChannelNumber"))
        .or_else(|| json_string_field(&base, "GuideNumber"));
    let id = json_string_field(&base, "Id")
        .or_else(|| json_string_field(&base, "ChannelId"))
        .or_else(|| number.clone())
        .unwrap_or_else(|| format!("{tuner_id}-{}", index + 1));

    base["Id"] = serde_json::json!(id);
    base["ChannelId"] = base["Id"].clone();
    base["Name"] = serde_json::json!(name);
    base["SortName"] = serde_json::json!(
        number
            .clone()
            .unwrap_or_else(|| { base["Name"].as_str().unwrap_or_default().to_string() })
    );
    base["Number"] = number
        .map(serde_json::Value::String)
        .unwrap_or(serde_json::Value::Null);
    base["TunerHostId"] = serde_json::json!(tuner_id);
    base["TunerHostName"] = serde_json::json!(tuner_name);
    base["Type"] = serde_json::json!("TvChannel");
    base["MediaType"] = serde_json::json!("Video");
    base["ChannelType"] = base
        .get("ChannelType")
        .cloned()
        .unwrap_or_else(|| serde_json::json!("TV"));
    base["IsFolder"] = serde_json::json!(false);
    base["IsLive"] = serde_json::json!(true);
    base["LocationType"] = serde_json::json!("Remote");
    base["RunTimeTicks"] = serde_json::Value::Null;
    base["CurrentProgram"] = serde_json::Value::Null;
    if live_tv_channel_path(&base).is_ok()
        && let Ok(media_source) = live_tv_channel_media_source(&base)
    {
        base["MediaSources"] = serde_json::json!([media_source]);
    }
    Some(base)
}

fn live_tv_channel_path(channel: &serde_json::Value) -> Result<PathBuf, ApiError> {
    json_string_field(channel, "Path")
        .or_else(|| json_string_field(channel, "MediaPath"))
        .map(PathBuf::from)
        .filter(|path| !path.as_os_str().is_empty())
        .ok_or_else(|| ApiError::not_found("Live TV stream not found"))
}

fn live_tv_channel_media_source(
    channel: &serde_json::Value,
) -> Result<serde_json::Value, ApiError> {
    let channel_id = json_string_field(channel, "Id")
        .ok_or_else(|| ApiError::not_found("Live TV item not found"))?;
    let name = json_string_field(channel, "Name").unwrap_or_else(|| channel_id.clone());
    let path = live_tv_channel_path(channel)?;
    let container = path
        .extension()
        .and_then(|extension| extension.to_str())
        .map(str::to_ascii_lowercase)
        .unwrap_or_else(|| "ts".to_string());
    Ok(serde_json::json!({
        "Protocol": "File",
        "Id": channel_id,
        "Path": path.to_string_lossy().to_string(),
        "Type": "Default",
        "Container": container,
        "Name": name,
        "IsRemote": false,
        "DirectStreamUrl": format!("/LiveTv/LiveStreamFiles/{channel_id}/stream.{container}"),
        "ETag": null,
        "RunTimeTicks": null,
        "ReadAtNativeFramerate": true,
        "SupportsTranscoding": false,
        "SupportsDirectStream": true,
        "SupportsDirectPlay": true,
        "IsInfiniteStream": true,
        "RequiresOpening": false,
        "RequiresClosing": true,
        "RequiresLooping": false,
        "SupportsProbing": false,
        "VideoType": "VideoFile",
        "MediaStreams": [{
            "Codec": container,
            "Type": "Video",
            "Index": 0,
            "IsInterlaced": false
        }],
        "Formats": [],
        "Bitrate": null
    }))
}

fn live_tv_program_items(config: &serde_json::Value) -> Vec<serde_json::Value> {
    let channels = live_tv_channel_items(config);
    let mut programs = Vec::new();
    collect_live_tv_programs(config, "ListingProviders", &channels, &mut programs);
    collect_live_tv_programs(config, "TunerHosts", &channels, &mut programs);
    programs.sort_by(|left, right| {
        let left_start = json_string_field(left, "StartDate").unwrap_or_default();
        let right_start = json_string_field(right, "StartDate").unwrap_or_default();
        left_start.cmp(&right_start).then_with(|| {
            json_string_field(left, "Name")
                .unwrap_or_default()
                .to_ascii_lowercase()
                .cmp(
                    &json_string_field(right, "Name")
                        .unwrap_or_default()
                        .to_ascii_lowercase(),
                )
        })
    });
    programs
}

fn collect_live_tv_programs(
    config: &serde_json::Value,
    collection_key: &str,
    channels: &[serde_json::Value],
    programs: &mut Vec<serde_json::Value>,
) {
    let Some(sources) = config
        .get(collection_key)
        .and_then(serde_json::Value::as_array)
    else {
        return;
    };
    for (source_index, source) in sources.iter().enumerate() {
        let source_id = json_string_field(source, "Id")
            .unwrap_or_else(|| format!("{collection_key}-{source_index}"));
        let Some(source_programs) = source.get("Programs").and_then(serde_json::Value::as_array)
        else {
            continue;
        };
        for (program_index, program) in source_programs.iter().enumerate() {
            if let Some(program) =
                live_tv_program_item(&source_id, channels, program, program_index)
            {
                programs.push(program);
            }
        }
    }
}

fn live_tv_program_item(
    source_id: &str,
    channels: &[serde_json::Value],
    program: &serde_json::Value,
    index: usize,
) -> Option<serde_json::Value> {
    let (mut base, raw_name) = match program {
        serde_json::Value::Object(fields) => (serde_json::Value::Object(fields.clone()), None),
        serde_json::Value::String(name) => (serde_json::json!({}), Some(name.trim().to_string())),
        _ => return None,
    };
    let name = json_string_field(&base, "Name")
        .or_else(|| json_string_field(&base, "Title"))
        .or(raw_name)
        .filter(|name| !name.is_empty())
        .unwrap_or_else(|| format!("Program {}", index + 1));
    let channel_id = json_string_field(&base, "ChannelId")
        .or_else(|| json_string_field(&base, "Channel"))
        .or_else(|| {
            channels
                .first()
                .and_then(|channel| json_string_field(channel, "Id"))
        })
        .unwrap_or_default();
    let channel_name = channels
        .iter()
        .find(|channel| {
            json_string_field(channel, "Id").is_some_and(|id| id.eq_ignore_ascii_case(&channel_id))
        })
        .and_then(|channel| json_string_field(channel, "Name"));
    let id = json_string_field(&base, "Id")
        .or_else(|| json_string_field(&base, "ProgramId"))
        .unwrap_or_else(|| format!("{source_id}-program-{}", index + 1));

    base["Id"] = serde_json::json!(id);
    base["Name"] = serde_json::json!(name.clone());
    base["SortName"] = serde_json::json!(name);
    base["Type"] = serde_json::json!("Program");
    base["MediaType"] = serde_json::json!("Video");
    base["ChannelId"] = serde_json::json!(channel_id);
    base["ChannelName"] = channel_name
        .map(serde_json::Value::String)
        .unwrap_or(serde_json::Value::Null);
    base["IsFolder"] = serde_json::json!(false);
    base["IsLive"] = base
        .get("IsLive")
        .cloned()
        .unwrap_or(serde_json::Value::Bool(false));
    base["StartDate"] = base
        .get("StartDate")
        .cloned()
        .or_else(|| base.get("Start").cloned())
        .unwrap_or(serde_json::Value::Null);
    base["EndDate"] = base
        .get("EndDate")
        .cloned()
        .or_else(|| base.get("End").cloned())
        .unwrap_or(serde_json::Value::Null);
    base["Overview"] = base
        .get("Overview")
        .cloned()
        .or_else(|| base.get("Description").cloned())
        .unwrap_or_else(|| serde_json::json!(""));
    Some(base)
}

fn live_tv_recording_items(config: &serde_json::Value) -> Vec<serde_json::Value> {
    let channels = live_tv_channel_items(config);
    let mut recordings = config
        .get("Recordings")
        .and_then(serde_json::Value::as_array)
        .map(|recordings| {
            recordings
                .iter()
                .enumerate()
                .filter_map(|(index, recording)| {
                    live_tv_recording_item(recording, index, &channels)
                })
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    recordings.sort_by(|left, right| {
        json_string_field(right, "DateCreated")
            .unwrap_or_default()
            .cmp(&json_string_field(left, "DateCreated").unwrap_or_default())
            .then_with(|| {
                json_string_field(left, "Name")
                    .unwrap_or_default()
                    .to_ascii_lowercase()
                    .cmp(
                        &json_string_field(right, "Name")
                            .unwrap_or_default()
                            .to_ascii_lowercase(),
                    )
            })
    });
    recordings
}

fn live_tv_recording_item(
    recording: &serde_json::Value,
    index: usize,
    channels: &[serde_json::Value],
) -> Option<serde_json::Value> {
    let serde_json::Value::Object(fields) = recording else {
        return None;
    };
    let mut item = serde_json::Value::Object(fields.clone());
    let name = json_string_field(&item, "Name")
        .or_else(|| json_string_field(&item, "Title"))
        .unwrap_or_else(|| format!("Recording {}", index + 1));
    let id = json_string_field(&item, "Id")
        .or_else(|| json_string_field(&item, "RecordingId"))
        .unwrap_or_else(|| format!("recording-{}", index + 1));
    let channel_id = json_string_field(&item, "ChannelId").unwrap_or_default();
    let channel_name = channels
        .iter()
        .find(|channel| {
            json_string_field(channel, "Id").is_some_and(|id| id.eq_ignore_ascii_case(&channel_id))
        })
        .and_then(|channel| json_string_field(channel, "Name"));

    item["Id"] = serde_json::json!(id);
    item["Name"] = serde_json::json!(name.clone());
    item["SortName"] = serde_json::json!(name);
    item["Type"] = serde_json::json!("Recording");
    item["MediaType"] = serde_json::json!("Video");
    item["ChannelId"] = serde_json::json!(channel_id);
    item["ChannelName"] = channel_name
        .map(serde_json::Value::String)
        .unwrap_or(serde_json::Value::Null);
    item["IsFolder"] = serde_json::json!(false);
    item["IsLive"] = serde_json::json!(false);
    item["Status"] = item
        .get("Status")
        .cloned()
        .unwrap_or_else(|| serde_json::json!("Completed"));
    item["DateCreated"] = item
        .get("DateCreated")
        .cloned()
        .or_else(|| item.get("StartDate").cloned())
        .unwrap_or(serde_json::Value::Null);
    item["SeriesName"] = item
        .get("SeriesName")
        .cloned()
        .or_else(|| item.get("Series").cloned())
        .unwrap_or(serde_json::Value::Null);
    item["RecordingType"] = item
        .get("RecordingType")
        .cloned()
        .unwrap_or_else(|| serde_json::json!("Manual"));
    Some(item)
}

fn live_tv_recording_path(recording: &serde_json::Value) -> Result<PathBuf, ApiError> {
    json_string_field(recording, "Path")
        .or_else(|| json_string_field(recording, "MediaPath"))
        .map(PathBuf::from)
        .filter(|path| !path.as_os_str().is_empty())
        .ok_or_else(|| ApiError::not_found("Live TV stream not found"))
}

fn live_tv_recording_content_type(path: &FsPath) -> &'static str {
    match path
        .extension()
        .and_then(|extension| extension.to_str())
        .map(str::to_ascii_lowercase)
        .as_deref()
    {
        Some("ts") => "video/mp2t",
        Some("mp4" | "m4v") => "video/mp4",
        Some("mkv") => "video/x-matroska",
        Some("webm") => "video/webm",
        _ => "application/octet-stream",
    }
}

fn live_tv_recording_group_items(
    config: &serde_json::Value,
    group_type: &'static str,
) -> Vec<serde_json::Value> {
    let mut groups: BTreeMap<String, usize> = BTreeMap::new();
    for recording in live_tv_recording_items(config) {
        let key = match group_type {
            "Folder" => json_string_field(&recording, "FolderName")
                .or_else(|| json_string_field(&recording, "Category"))
                .unwrap_or_else(|| "Recordings".to_string()),
            "Series" => json_string_field(&recording, "SeriesName")
                .or_else(|| json_string_field(&recording, "Name"))
                .unwrap_or_else(|| "Recordings".to_string()),
            _ => json_string_field(&recording, "GroupName")
                .or_else(|| json_string_field(&recording, "SeriesName"))
                .or_else(|| json_string_field(&recording, "Name"))
                .unwrap_or_else(|| "Recordings".to_string()),
        };
        *groups.entry(key).or_insert(0) += 1;
    }
    groups
        .into_iter()
        .map(|(name, count)| {
            serde_json::json!({
                "Id": sanitize_live_tv_group_id(&name),
                "Name": name,
                "Type": format!("Recording{group_type}"),
                "IsFolder": true,
                "ChildCount": count,
                "RecordingCount": count
            })
        })
        .collect()
}

fn sanitize_live_tv_group_id(name: &str) -> String {
    name.to_ascii_lowercase()
        .chars()
        .map(|character| {
            if character.is_ascii_alphanumeric() {
                character
            } else {
                '-'
            }
        })
        .collect::<String>()
        .trim_matches('-')
        .to_string()
}

async fn delete_persisted_live_tv_recording(
    db: &Database,
    recording_id: &str,
) -> Result<StatusCode, ApiError> {
    let mut config = db
        .named_configuration("livetv")
        .await?
        .unwrap_or_else(default_live_tv_configuration);
    let mut recordings = config
        .get("Recordings")
        .and_then(serde_json::Value::as_array)
        .cloned()
        .unwrap_or_default();
    let before = recordings.len();
    recordings.retain(|recording| {
        json_string_field(recording, "Id")
            .or_else(|| json_string_field(recording, "RecordingId"))
            .is_none_or(|id| !id.eq_ignore_ascii_case(recording_id))
    });
    if recordings.len() == before {
        return Err(ApiError::not_found("Live TV recording not found"));
    }
    config["Recordings"] = serde_json::json!(recordings);
    db.update_named_configuration("livetv", live_tv_configuration_json(config))
        .await?;
    Ok(StatusCode::NO_CONTENT)
}

fn live_tv_channel_mapping_option(channel: serde_json::Value) -> serde_json::Value {
    serde_json::json!({
        "Id": json_string_field(&channel, "Id").unwrap_or_default(),
        "Name": json_string_field(&channel, "Name").unwrap_or_default(),
        "Number": json_string_field(&channel, "Number"),
        "ChannelId": json_string_field(&channel, "ChannelId").unwrap_or_default()
    })
}

fn live_tv_provider_channels(provider: &serde_json::Value) -> Vec<serde_json::Value> {
    if let Some(channels) = provider
        .get("Channels")
        .and_then(serde_json::Value::as_array)
    {
        return channels
            .iter()
            .enumerate()
            .filter_map(|channel| live_tv_provider_channel(channel.1, channel.0))
            .collect();
    }
    provider
        .get("ChannelMappings")
        .and_then(serde_json::Value::as_array)
        .map(|mappings| {
            mappings
                .iter()
                .filter_map(|mapping| {
                    let value = json_string_field(mapping, "Value")?;
                    Some(serde_json::json!({
                        "Id": value,
                        "Name": value,
                        "Number": null
                    }))
                })
                .collect()
        })
        .unwrap_or_default()
}

fn live_tv_provider_channel(
    channel: &serde_json::Value,
    index: usize,
) -> Option<serde_json::Value> {
    match channel {
        serde_json::Value::Object(_) => {
            let name = json_string_field(channel, "Name")
                .or_else(|| json_string_field(channel, "DisplayName"))
                .unwrap_or_else(|| format!("Provider Channel {}", index + 1));
            let id = json_string_field(channel, "Id")
                .or_else(|| json_string_field(channel, "ChannelId"))
                .unwrap_or_else(|| name.clone());
            Some(serde_json::json!({
                "Id": id,
                "Name": name,
                "Number": json_string_field(channel, "Number").or_else(|| json_string_field(channel, "ChannelNumber"))
            }))
        }
        serde_json::Value::String(name) if !name.trim().is_empty() => Some(serde_json::json!({
            "Id": name.trim(),
            "Name": name.trim(),
            "Number": null
        })),
        _ => None,
    }
}

