async fn get_playlist_user(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    Path((playlist_id, user_id)): Path<(String, String)>,
) -> Result<Json<serde_json::Value>, ApiError> {
    let user = require_request_user(&state.db, &headers, query.api_key.as_deref()).await?;
    let playlist =
        ensure_media_list_kind(&state.db, parse_jellyfin_uuid(&playlist_id)?, "playlist").await?;
    let requested_user = state.db.user_by_id(resolve_user_id(&user_id)?).await?;
    let is_owner = playlist.owner_user_id == Some(requested_user.id);
    let permission = if is_owner {
        None
    } else {
        state
            .db
            .media_list_user_permission(playlist.id, requested_user.id)
            .await?
    };
    let can_read = media_list_is_owner_or_admin(&user, &playlist)
        || (requested_user.id == user.id && (is_owner || permission.is_some()));
    if !can_read {
        return Err(ApiError::forbidden("Playlist access denied"));
    }
    if !is_owner && permission.is_none() {
        return Err(ApiError::not_found("Playlist user not found"));
    }
    Ok(Json(playlist_user_json(
        &requested_user,
        is_owner,
        permission
            .as_ref()
            .is_some_and(|permission| permission.can_edit),
    )))
}

async fn add_playlist_user(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    Path((playlist_id, user_id)): Path<(String, String)>,
    body: Option<Json<serde_json::Value>>,
) -> Result<StatusCode, ApiError> {
    let user = require_request_user(&state.db, &headers, query.api_key.as_deref()).await?;
    let playlist =
        ensure_media_list_kind(&state.db, parse_jellyfin_uuid(&playlist_id)?, "playlist").await?;
    ensure_media_list_manage_access(&user, &playlist)?;
    let requested_user = state.db.user_by_id(resolve_user_id(&user_id)?).await?;
    if playlist.owner_user_id != Some(requested_user.id) {
        let body = body.map(|Json(value)| value);
        state
            .db
            .upsert_media_list_user_permission(
                playlist.id,
                requested_user.id,
                playlist_user_can_edit_from_request(body.as_ref()),
            )
            .await?;
    }
    Ok(StatusCode::NO_CONTENT)
}

async fn remove_playlist_user(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    Path((playlist_id, user_id)): Path<(String, String)>,
) -> Result<StatusCode, ApiError> {
    let user = require_request_user(&state.db, &headers, query.api_key.as_deref()).await?;
    let playlist =
        ensure_media_list_kind(&state.db, parse_jellyfin_uuid(&playlist_id)?, "playlist").await?;
    ensure_media_list_manage_access(&user, &playlist)?;
    let requested_user = state.db.user_by_id(resolve_user_id(&user_id)?).await?;
    if playlist.owner_user_id == Some(requested_user.id) {
        return Err(ApiError::bad_request("Playlist owner cannot be removed"));
    }
    state
        .db
        .delete_media_list_user_permission(playlist.id, requested_user.id)
        .await?;
    Ok(StatusCode::NO_CONTENT)
}

fn list_created_json(list: &MediaList) -> serde_json::Value {
    serde_json::json!({
        "Id": list.id.simple().to_string()
    })
}

async fn ensure_media_list_kind(
    db: &Database,
    list_id: Uuid,
    expected_kind: &str,
) -> Result<MediaList, ApiError> {
    let list = db
        .media_list_by_id(list_id)
        .await
        .map_err(|_| ApiError::not_found("List not found"))?;
    if list.kind == expected_kind {
        Ok(list)
    } else {
        Err(ApiError::not_found("List not found"))
    }
}

fn media_list_is_owner_or_admin(user: &User, list: &MediaList) -> bool {
    user.is_administrator
        || list
            .owner_user_id
            .is_none_or(|owner_id| owner_id == user.id)
}

async fn ensure_media_list_read_access(
    db: &Database,
    user: &User,
    list: &MediaList,
) -> Result<(), ApiError> {
    if media_list_is_owner_or_admin(user, list)
        || db
            .media_list_user_permission(list.id, user.id)
            .await?
            .is_some()
    {
        Ok(())
    } else {
        Err(ApiError::forbidden("Playlist access denied"))
    }
}

async fn ensure_media_list_edit_access(
    db: &Database,
    user: &User,
    list: &MediaList,
) -> Result<(), ApiError> {
    if media_list_is_owner_or_admin(user, list)
        || db
            .media_list_user_permission(list.id, user.id)
            .await?
            .is_some_and(|permission| permission.can_edit)
    {
        Ok(())
    } else {
        Err(ApiError::forbidden("Playlist access denied"))
    }
}

fn ensure_media_list_manage_access(user: &User, list: &MediaList) -> Result<(), ApiError> {
    if media_list_is_owner_or_admin(user, list) {
        Ok(())
    } else {
        Err(ApiError::forbidden("Playlist access denied"))
    }
}

fn list_name_from_request(
    raw_query: Option<&str>,
    body: Option<&serde_json::Value>,
) -> Option<String> {
    query_string_value(raw_query, &["Name", "name"])
        .or_else(|| json_string_field_from_body(body, &["Name", "name"]))
        .map(|name| name.trim().to_string())
        .filter(|name| !name.is_empty())
}

fn list_item_ids_from_request(
    raw_query: Option<&str>,
    body: Option<&serde_json::Value>,
) -> Result<Vec<Uuid>, ApiError> {
    let mut ids = query_uuid_values(raw_query, &["Ids", "ids", "ItemIds", "itemIds"])?;
    ids.extend(json_uuid_values_from_body(
        body,
        &["Ids", "ids", "ItemIds", "itemIds"],
    )?);
    Ok(dedupe_uuid_vec(ids))
}

fn query_string_value(raw_query: Option<&str>, names: &[&str]) -> Option<String> {
    query_string_values(raw_query, names).into_iter().next()
}

fn query_uuid_values(raw_query: Option<&str>, names: &[&str]) -> Result<Vec<Uuid>, ApiError> {
    query_string_values(raw_query, names)
        .into_iter()
        .flat_map(|value| {
            value
                .split(',')
                .map(str::trim)
                .filter(|value| !value.is_empty())
                .map(ToOwned::to_owned)
                .collect::<Vec<_>>()
        })
        .map(|value| parse_jellyfin_uuid(&value))
        .collect::<Result<Vec<_>, _>>()
        .map(dedupe_uuid_vec)
}

fn query_string_values(raw_query: Option<&str>, names: &[&str]) -> Vec<String> {
    let Some(raw_query) = raw_query else {
        return Vec::new();
    };
    let names = names
        .iter()
        .map(|name| name.to_ascii_lowercase())
        .collect::<Vec<_>>();
    raw_query
        .split('&')
        .filter_map(|pair| pair.split_once('='))
        .filter_map(|(key, value)| {
            let key = percent_decode_query_component(key).to_ascii_lowercase();
            if names.iter().any(|name| name == &key) {
                Some(percent_decode_query_component(value))
            } else {
                None
            }
        })
        .collect()
}

fn json_string_field_from_body(body: Option<&serde_json::Value>, names: &[&str]) -> Option<String> {
    let body = body?;
    names
        .iter()
        .find_map(|name| body.get(*name).and_then(serde_json::Value::as_str))
        .map(ToOwned::to_owned)
}

fn json_uuid_values_from_body(
    body: Option<&serde_json::Value>,
    names: &[&str],
) -> Result<Vec<Uuid>, ApiError> {
    let Some(body) = body else {
        return Ok(Vec::new());
    };
    let Some(value) = names.iter().find_map(|name| body.get(*name)) else {
        return Ok(Vec::new());
    };
    match value {
        serde_json::Value::String(value) => parse_uuid_list(value),
        serde_json::Value::Array(values) => values
            .iter()
            .filter_map(serde_json::Value::as_str)
            .map(parse_jellyfin_uuid)
            .collect::<Result<Vec<_>, _>>()
            .map(dedupe_uuid_vec),
        _ => Ok(Vec::new()),
    }
}

fn dedupe_uuid_vec(values: Vec<Uuid>) -> Vec<Uuid> {
    let mut seen = HashSet::new();
    values
        .into_iter()
        .filter(|value| seen.insert(*value))
        .collect()
}

fn media_list_to_json(list: &MediaList, server_id: &str, child_count: usize) -> serde_json::Value {
    let item_type = if list.kind == "collection" {
        "BoxSet"
    } else {
        "Playlist"
    };
    serde_json::json!({
        "Name": list.name,
        "ServerId": server_id,
        "Id": list.id.simple().to_string(),
        "Etag": null,
        "DateCreated": list.created_at.to_string(),
        "DateLastMediaAdded": list.updated_at.to_string(),
        "CanDelete": true,
        "CanDownload": false,
        "SortName": list.name,
        "ExternalUrls": [],
        "Path": null,
        "EnableMediaSourceDisplay": true,
        "ChannelId": null,
        "Taglines": [],
        "Genres": [],
        "PlayAccess": "Full",
        "RemoteTrailers": [],
        "ProviderIds": {},
        "IsFolder": true,
        "ParentId": null,
        "Type": item_type,
        "MediaType": null,
        "CollectionType": list.collection_type,
        "ChildCount": child_count,
        "UserData": { "PlaybackPositionTicks": 0, "PlayCount": 0, "IsFavorite": false, "Played": false },
        "ImageTags": {},
        "BackdropImageTags": [],
        "LocationType": "Virtual",
        "OwnerUserId": list.owner_user_id.map(|id| id.simple().to_string())
    })
}

async fn media_list_items_to_json(
    db: &Database,
    items: Vec<MediaListItem>,
    server_id: &str,
    user_id: Option<Uuid>,
) -> Result<Vec<serde_json::Value>, ApiError> {
    let mut values = Vec::with_capacity(items.len());
    let metadata_by_item =
        media_metadata_by_item_id(db, items.iter().map(|item| item.item.id).collect()).await?;
    for item in items {
        let playback = if let Some(user_id) = user_id {
            db.playback_state_for_item(user_id, item.item.id).await?
        } else {
            None
        };
        let mut value = media_item_to_json_with_playback_and_metadata(
            &item.item,
            server_id,
            playback.as_ref(),
            metadata_by_item.get(&item.item.id),
        );
        if let Some(object) = value.as_object_mut() {
            object.insert(
                "PlaylistItemId".to_string(),
                serde_json::json!(item.playlist_item_id.simple().to_string()),
            );
            object.insert(
                "IndexNumber".to_string(),
                serde_json::json!(item.position + 1),
            );
            object.insert(
                "DateCreated".to_string(),
                serde_json::json!(item.added_at.to_string()),
            );
        }
        values.push(value);
    }
    Ok(values)
}

async fn playlist_users_json(
    db: &Database,
    playlist: &MediaList,
) -> Result<Vec<serde_json::Value>, ApiError> {
    let permissions = db.media_list_user_permissions(playlist.id).await?;
    let mut users = Vec::with_capacity(permissions.len() + 1);
    if let Some(owner_id) = playlist.owner_user_id {
        let owner = db.user_by_id(owner_id).await?;
        users.push(playlist_user_json(&owner, true, true));
    }
    users.extend(permissions.iter().map(playlist_user_permission_json));
    Ok(users)
}

fn playlist_user_permission_json(permission: &MediaListUserPermission) -> serde_json::Value {
    playlist_user_json(&permission.user, false, permission.can_edit)
}

fn playlist_user_json(user: &User, is_owner: bool, can_edit: bool) -> serde_json::Value {
    serde_json::json!({
        "Id": user.id.simple().to_string(),
        "UserId": user.id.simple().to_string(),
        "Name": user.name,
        "CanEdit": is_owner || user.is_administrator || can_edit,
        "IsOwner": is_owner
    })
}

fn playlist_user_can_edit_from_request(body: Option<&serde_json::Value>) -> bool {
    body.and_then(|body| {
        ["CanEdit", "canEdit", "CanManage", "canManage"]
            .iter()
            .find_map(|name| body.get(*name).and_then(serde_json::Value::as_bool))
    })
    .unwrap_or(false)
}

