async fn user_item_rating_inner(
    state: AppState,
    headers: HeaderMap,
    query: ItemRatingQuery,
    user_id: String,
    item_id: String,
    set_rating: bool,
) -> Result<Json<serde_json::Value>, ApiError> {
    let auth_user =
        require_request_user(&state.db, &headers, query.auth.api_key.as_deref()).await?;
    let requested_user_id = resolve_user_id(&user_id)?;
    ensure_user_access(&auth_user, requested_user_id)?;
    let item = media_item_by_id(&state.db, &item_id).await?;
    let rating = set_rating.then(|| rating_from_query(&query)).flatten();
    state
        .db
        .set_item_rating(requested_user_id, item.id, rating)
        .await?;
    item_user_data_json(&state.db, requested_user_id, &item_id)
        .await
        .map(Json)
}

fn rating_from_query(query: &ItemRatingQuery) -> Option<f64> {
    query.rating.or_else(|| {
        query
            .likes
            .map(|likes| if likes { 1.0_f64 } else { 0.0_f64 })
    })
}

fn resolve_user_id(user_id: &str) -> Result<Uuid, ApiError> {
    parse_jellyfin_uuid(user_id).map_err(|_| ApiError::bad_request("Invalid user id"))
}

async fn item_ancestors(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    Path(item_id): Path<String>,
) -> Result<Json<Vec<serde_json::Value>>, ApiError> {
    require_request_user(&state.db, &headers, query.api_key.as_deref()).await?;
    let requested_id = parse_jellyfin_uuid(&item_id)?;
    let folders = state.db.virtual_folders().await?;
    let root = root_folder_json(&state.db).await?;
    let server_id = state.db.server_state().await?.server_id.to_string();
    let root_id = root["Id"].as_str().unwrap_or_default().to_string();

    if folders.iter().any(|folder| folder.id == requested_id) {
        return Ok(Json(vec![root]));
    }

    let item = state
        .db
        .media_items()
        .await?
        .into_iter()
        .find(|item| item.id == requested_id)
        .ok_or_else(|| ApiError::not_found("Item not found"))?;
    let folder = folders
        .iter()
        .find(|folder| folder.id == item.virtual_folder_id)
        .ok_or_else(|| ApiError::not_found("Parent folder not found"))?;
    let mut folder_json = user_view_to_json(folder, &server_id);
    if let Some(object) = folder_json.as_object_mut() {
        object.insert("ParentId".to_string(), serde_json::json!(root_id));
    }
    Ok(Json(vec![folder_json, root]))
}

