#[derive(Debug, Deserialize)]
struct MergeVersionsBody {
    #[serde(default, alias = "Ids", alias = "ItemIds", alias = "ItemIdList")]
    ids: Vec<String>,
}

async fn merge_video_versions(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    RawQuery(raw_query): RawQuery,
    body: Option<Json<MergeVersionsBody>>,
) -> Result<StatusCode, ApiError> {
    require_request_user(&state.db, &headers, query.api_key.as_deref()).await?;
    let mut video_ids: Vec<MediaItem> = Vec::new();
    let mut seen_ids = HashSet::new();
    let requested_ids = merge_version_ids(raw_query.as_deref(), body.map(|body| body.0));
    for item_id in requested_ids {
        let item = media_item_by_id(&state.db, &item_id).await?;
        if !seen_ids.insert(item.id) {
            continue;
        }
        if item.media_type != "Video" {
            return Err(ApiError::bad_request(
                "MergeVersions only supports video items",
            ));
        }
        if let Some(first_item) = video_ids.first()
            && item.virtual_folder_id != first_item.virtual_folder_id
        {
            return Err(ApiError::bad_request(
                "MergeVersions only supports items in the same library",
            ));
        }
        video_ids.push(item);
    }
    if video_ids.len() < 2 {
        return Err(ApiError::bad_request(
            "MergeVersions requires at least two video ids",
        ));
    }
    let primary_id = video_ids[0].id;
    let alternate_ids = video_ids.iter().skip(1).map(|item| item.id).collect();
    state
        .db
        .merge_media_item_versions(primary_id, alternate_ids)
        .await?;
    Ok(StatusCode::NO_CONTENT)
}

fn merge_version_ids(raw_query: Option<&str>, body: Option<MergeVersionsBody>) -> Vec<String> {
    let query_ids = raw_query
        .into_iter()
        .flat_map(|query| query.split('&'))
        .filter_map(|part| part.split_once('='))
        .find_map(|(key, value)| key.eq_ignore_ascii_case("ids").then_some(value))
        .map(split_comma_separated_ids)
        .unwrap_or_default();
    if query_ids.is_empty() {
        body.map(|body| body.ids).unwrap_or_default()
    } else {
        query_ids
    }
}

fn split_comma_separated_ids(value: &str) -> Vec<String> {
    value
        .split(',')
        .map(str::trim)
        .filter(|id| !id.is_empty())
        .map(ToOwned::to_owned)
        .collect()
}

#[derive(Debug, Deserialize)]
struct OpenLiveStreamBody {
    #[serde(alias = "ItemId")]
    item_id: Option<String>,
    #[serde(alias = "OpenToken")]
    open_token: Option<String>,
    #[serde(alias = "MediaSourceId")]
    media_source_id: Option<String>,
}

#[derive(Debug, Deserialize)]
struct CloseLiveStreamBody {
    #[serde(alias = "LiveStreamId")]
    live_stream_id: Option<String>,
    #[serde(alias = "MediaSourceId")]
    media_source_id: Option<String>,
}

async fn open_live_stream(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    body: Option<Json<OpenLiveStreamBody>>,
) -> Result<Json<serde_json::Value>, ApiError> {
    require_request_user(&state.db, &headers, query.api_key.as_deref()).await?;
    let body = body.map(|body| body.0).unwrap_or(OpenLiveStreamBody {
        item_id: None,
        open_token: None,
        media_source_id: None,
    });
    let item_id = body
        .item_id
        .or(body.media_source_id)
        .or(body.open_token)
        .ok_or_else(|| ApiError::bad_request("ItemId is required"))?;
    if let Ok(channel) = live_tv_channel_by_id(&state.db, &item_id).await {
        let media_source = live_tv_channel_media_source(&channel)?;
        let live_stream_id = json_string_field(&channel, "Id").unwrap_or(item_id);
        return Ok(Json(serde_json::json!({
            "MediaSource": media_source,
            "LiveStreamId": live_stream_id,
            "MediaSourceId": live_stream_id,
        })));
    }
    let item = media_item_by_id(&state.db, &item_id).await?;
    let server_id = state.db.server_state().await?.server_id.to_string();
    let item_json = media_item_to_json(&item, &server_id);
    let media_source = item_json["MediaSources"]
        .as_array()
        .and_then(|sources| sources.first())
        .cloned()
        .ok_or_else(|| ApiError::not_found("Media source not found"))?;
    let live_stream_id = item.id.simple().to_string();
    Ok(Json(serde_json::json!({
        "MediaSource": media_source,
        "LiveStreamId": live_stream_id,
        "MediaSourceId": live_stream_id,
    })))
}

async fn close_live_stream(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    body: Option<Json<CloseLiveStreamBody>>,
) -> Result<StatusCode, ApiError> {
    require_request_user(&state.db, &headers, query.api_key.as_deref()).await?;
    if let Some(Json(body)) = body
        && let Some(item_id) = body.live_stream_id.or(body.media_source_id)
        && live_tv_channel_by_id(&state.db, &item_id).await.is_err()
    {
        media_item_by_id(&state.db, &item_id).await?;
    }
    Ok(StatusCode::NO_CONTENT)
}

async fn video_additional_parts(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    Path(item_id): Path<String>,
) -> Result<Json<serde_json::Value>, ApiError> {
    let user = require_request_user(&state.db, &headers, query.api_key.as_deref()).await?;
    let item = media_item_by_id(&state.db, &item_id).await?;
    if item.media_type != "Video" {
        return Err(ApiError::not_found("Video item not found"));
    }
    let server_id = state.db.server_state().await?.server_id.to_string();
    let mut versions = state.db.media_item_versions(item.id).await?;
    let discovered_parts =
        local_sidecar_items(&state.db, &item, SidecarKind::AdditionalPart).await?;
    let mut seen_ids = versions.iter().map(|item| item.id).collect::<HashSet<_>>();
    for part in discovered_parts {
        if seen_ids.insert(part.id) {
            versions.push(part);
        }
    }
    versions.sort_by(|left, right| compare_media_items(left, right, &[SortField::SortName]));
    let total_record_count = versions.len();
    let items = items_to_json(&state.db, versions, &server_id, Some(user.id)).await?;
    Ok(Json(query_result_with_total(items, total_record_count, 0)))
}

async fn media_segments(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    Path(item_id): Path<String>,
    RawQuery(raw_query): RawQuery,
) -> Result<Json<serde_json::Value>, ApiError> {
    require_request_user(&state.db, &headers, query.api_key.as_deref()).await?;
    let item = media_item_by_id(&state.db, &item_id).await?;
    let include_segment_types = csv_values_lowercase(&query_string_values(
        raw_query.as_deref(),
        &["IncludeSegmentTypes", "includeSegmentTypes"],
    ));
    let metadata = state
        .db
        .media_item_metadata()
        .await?
        .into_iter()
        .find(|metadata| metadata.item_id == item.id)
        .map(|metadata| metadata.payload)
        .unwrap_or_else(|| serde_json::json!({}));
    let mut segments = metadata
        .get("MediaSegments")
        .and_then(serde_json::Value::as_array)
        .map(|segments| {
            segments
                .iter()
                .enumerate()
                .filter_map(|(index, segment)| media_segment_json(&item, index, segment))
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    if let Some(include_segment_types) = include_segment_types {
        segments.retain(|segment| {
            segment["Type"].as_str().is_some_and(|segment_type| {
                include_segment_types
                    .iter()
                    .any(|include_type| include_type.eq_ignore_ascii_case(segment_type))
            })
        });
    }
    segments.sort_by(|left, right| {
        left["StartTicks"]
            .as_i64()
            .unwrap_or_default()
            .cmp(&right["StartTicks"].as_i64().unwrap_or_default())
    });
    let total_record_count = segments.len();
    let start_index = query_string_value(raw_query.as_deref(), &["StartIndex", "startIndex"])
        .and_then(|value| value.parse::<usize>().ok())
        .unwrap_or(0);
    let limit = query_string_value(raw_query.as_deref(), &["Limit", "limit"])
        .and_then(|value| value.parse::<usize>().ok())
        .unwrap_or(usize::MAX);
    Ok(Json(query_result_with_total(
        segments.into_iter().skip(start_index).take(limit).collect(),
        total_record_count,
        start_index,
    )))
}

fn media_segment_json(
    item: &MediaItem,
    index: usize,
    segment: &serde_json::Value,
) -> Option<serde_json::Value> {
    let start_ticks = json_i64_field(segment, "StartTicks")
        .or_else(|| json_i64_field(segment, "StartPositionTicks"))?;
    let end_ticks =
        json_i64_field(segment, "EndTicks").or_else(|| json_i64_field(segment, "EndPositionTicks"));
    let segment_type = json_string_field(segment, "Type").unwrap_or_else(|| "Unknown".to_string());
    Some(serde_json::json!({
        "Id": json_string_field(segment, "Id").unwrap_or_else(|| format!("{}-{index}", item.id.simple())),
        "ItemId": item.id.simple().to_string(),
        "Type": segment_type,
        "StartTicks": start_ticks,
        "EndTicks": end_ticks,
        "SegmentProviderId": json_string_field(segment, "SegmentProviderId"),
        "Status": json_string_field(segment, "Status").unwrap_or_else(|| "Succeeded".to_string())
    }))
}

