async fn hls_master_playlist_response(
    state: &AppState,
    headers: &HeaderMap,
    item_id: &str,
    query: HlsQuery,
    raw_query: Option<&str>,
    include_body: bool,
) -> Result<axum::response::Response, ApiError> {
    hls_master_playlist_response_for(
        state,
        headers,
        item_id,
        query,
        raw_query,
        include_body,
        "Video",
    )
    .await
}

async fn hls_master_playlist_response_for(
    state: &AppState,
    headers: &HeaderMap,
    item_id: &str,
    query: HlsQuery,
    raw_query: Option<&str>,
    include_body: bool,
    media_type: &str,
) -> Result<axum::response::Response, ApiError> {
    let session =
        active_hls_transcode_session_for(state, headers, item_id, &query, media_type).await?;
    let playlist = render_hls_master_playlist(&HlsVariantInfo {
        uri: append_query(HLS_MEDIA_PLAYLIST_NAME, raw_query),
        bandwidth: session
            .item
            .bitrate
            .and_then(positive_u32)
            .unwrap_or(1_000_000),
        resolution: session
            .item
            .width
            .and_then(|value| positive_u32(i64::from(value)))
            .zip(
                session
                    .item
                    .height
                    .and_then(|value| positive_u32(i64::from(value))),
            ),
        codecs: hls_codecs(&session.item),
    });
    playlist_response(playlist, include_body)
}

