async fn remote_subtitle_candidates(
    item: &MediaItem,
    language: &str,
) -> Result<Vec<serde_json::Value>, ApiError> {
    let Some(item_dir) = media_item_path(item).parent() else {
        return Ok(Vec::new());
    };
    let remote_dir = item_dir.join(".jellyrin-remote-subtitles");
    let mut entries = match tokio::fs::read_dir(&remote_dir).await {
        Ok(entries) => entries,
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => return Ok(Vec::new()),
        Err(error) if error.kind() == std::io::ErrorKind::NotADirectory => return Ok(Vec::new()),
        Err(error) => return Err(error.into()),
    };

    let mut subtitles = Vec::new();
    while let Some(entry) = entries.next_entry().await? {
        let path = entry.path();
        if !is_supported_subtitle_path(&path) || !remote_subtitle_matches_language(&path, language)
        {
            continue;
        }
        let metadata = match entry.metadata().await {
            Ok(metadata) if metadata.is_file() => metadata,
            Ok(_) => continue,
            Err(_) => continue,
        };
        let canonical_path = tokio::fs::canonicalize(path).await?;
        let name = entry.file_name().to_string_lossy().into_owned();
        let format = subtitle_path_format(&canonical_path).unwrap_or_else(|| "srt".to_string());
        let detected_language =
            remote_subtitle_language_from_path(&canonical_path).unwrap_or_else(|| {
                language
                    .trim()
                    .to_ascii_lowercase()
                    .chars()
                    .filter(|character| character.is_ascii_alphanumeric())
                    .collect()
            });
        subtitles.push(serde_json::json!({
            "ThreeLetterISOLanguageName": detected_language,
            "Id": remote_subtitle_id_for_path(&canonical_path),
            "ProviderName": "Local cache",
            "Name": name,
            "Format": format,
            "Author": null,
            "Comment": null,
            "DateCreated": metadata.modified().ok().map(OffsetDateTime::from).map(format_time_for_json),
            "CommunityRating": null,
            "DownloadCount": null,
            "IsHashMatch": false
        }));
    }
    subtitles.sort_by_key(|subtitle| {
        subtitle
            .get("Name")
            .and_then(serde_json::Value::as_str)
            .unwrap_or_default()
            .to_ascii_lowercase()
    });
    Ok(subtitles)
}

async fn install_remote_subtitle(
    db: &Database,
    item: MediaItem,
    remote_path: &FsPath,
) -> Result<(), ApiError> {
    let bytes = tokio::fs::read(remote_path).await?;
    if bytes.is_empty() {
        return Err(ApiError::bad_request("Remote subtitle file is empty"));
    }
    if bytes.len() > SUBTITLE_UPLOAD_LIMIT_BYTES {
        return Err(ApiError::bad_request("Remote subtitle file is too large"));
    }

    let item_path = media_item_path(&item);
    let item_dir = item_path
        .parent()
        .ok_or_else(|| ApiError::not_found("Subtitle media source not found"))?;
    let subtitle_dir = item_dir.join(".jellyrin-subtitles");
    tokio::fs::create_dir_all(&subtitle_dir).await?;

    let mut streams = media_item_streams(&item);
    let next_index = next_subtitle_stream_index(&streams);
    let format = subtitle_path_format(remote_path).unwrap_or_else(|| "srt".to_string());
    let source_stem = remote_path
        .file_stem()
        .and_then(|stem| stem.to_str())
        .map(sanitize_file_stem)
        .filter(|stem| !stem.is_empty())
        .unwrap_or_else(|| format!("remote-{}", item.id.simple()));
    let subtitle_path = subtitle_dir.join(format!("{source_stem}-{next_index}.{format}"));
    tokio::fs::write(&subtitle_path, bytes).await?;

    let language = remote_subtitle_language_from_path(remote_path);
    let payload = UploadSubtitleDto {
        data: None,
        format: Some(format.clone()),
        language: language.clone(),
        is_forced: Some(false),
        is_hearing_impaired: Some(false),
        file_name: remote_path
            .file_name()
            .and_then(|name| name.to_str())
            .map(str::to_string),
    };
    streams.push(serde_json::json!({
        "Codec": format,
        "Language": language,
        "DisplayTitle": subtitle_display_title(&payload, &format),
        "IsInterlaced": false,
        "IsDefault": false,
        "IsForced": false,
        "Type": "Subtitle",
        "Index": next_index,
        "IsExternal": true,
        "IsTextSubtitleStream": true,
        "SupportsExternalStream": true,
        "Path": subtitle_path.to_string_lossy().to_string(),
        "DeliveryMethod": "External",
        "IsHearingImpaired": false,
        "ProviderName": "Local cache"
    }));
    persist_media_streams(db, &item, streams).await
}

fn remote_subtitle_id_for_path(path: &FsPath) -> String {
    format!(
        "local-cache:{}",
        general_purpose::URL_SAFE_NO_PAD.encode(path.to_string_lossy().as_bytes())
    )
}

async fn remote_subtitle_path_from_id(subtitle_id: &str) -> Result<PathBuf, ApiError> {
    let encoded = subtitle_id
        .strip_prefix("local-cache:")
        .ok_or_else(|| ApiError::not_found("Remote subtitle not found"))?;
    let bytes = general_purpose::URL_SAFE_NO_PAD
        .decode(encoded)
        .map_err(|_| ApiError::not_found("Remote subtitle not found"))?;
    let path =
        String::from_utf8(bytes).map_err(|_| ApiError::not_found("Remote subtitle not found"))?;
    let canonical_path = tokio::fs::canonicalize(PathBuf::from(path))
        .await
        .map_err(|_| ApiError::not_found("Remote subtitle not found"))?;
    if !is_supported_subtitle_path(&canonical_path)
        || !path_contains_component(&canonical_path, ".jellyrin-remote-subtitles")
    {
        return Err(ApiError::not_found("Remote subtitle not found"));
    }
    Ok(canonical_path)
}

fn is_supported_subtitle_path(path: &FsPath) -> bool {
    matches!(
        subtitle_path_format(path).as_deref(),
        Some("srt" | "vtt" | "ass" | "ssa")
    )
}

fn path_contains_component(path: &FsPath, component: &str) -> bool {
    path.components().any(|path_component| {
        path_component
            .as_os_str()
            .to_str()
            .is_some_and(|value| value == component)
    })
}

fn remote_subtitle_matches_language(path: &FsPath, language: &str) -> bool {
    let language = language.trim().to_ascii_lowercase();
    if language.is_empty() || language == "any" {
        return true;
    }
    path.file_stem()
        .and_then(|stem| stem.to_str())
        .is_some_and(|stem| {
            stem.to_ascii_lowercase()
                .split(['.', '-', '_', ' '])
                .any(|part| part == language)
        })
}

fn remote_subtitle_language_from_path(path: &FsPath) -> Option<String> {
    path.file_stem()
        .and_then(|stem| stem.to_str())
        .and_then(|stem| {
            stem.to_ascii_lowercase()
                .split(['.', '-', '_', ' '])
                .find(|part| part.len() == 3 && part.chars().all(|ch| ch.is_ascii_alphabetic()))
                .map(str::to_string)
        })
}

const LYRICS_UPLOAD_LIMIT_BYTES: usize = 4 * 1024 * 1024;

#[derive(Debug, Deserialize)]
struct UploadLyricsQuery {
    #[serde(flatten)]
    auth: AuthQuery,
    #[serde(alias = "FileName", alias = "fileName")]
    file_name: Option<String>,
}

async fn get_lyrics(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    Path(item_id): Path<String>,
) -> Result<Json<serde_json::Value>, ApiError> {
    require_request_user(&state.db, &headers, query.api_key.as_deref()).await?;
    let item = lyrics_audio_item(&state.db, &item_id).await?;
    let lyrics = state
        .db
        .media_item_lyrics(item.id)
        .await?
        .ok_or_else(|| ApiError::not_found("Lyrics not found"))?;
    Ok(Json(lyrics.payload))
}

async fn upload_lyrics(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<UploadLyricsQuery>,
    Path(item_id): Path<String>,
    body: Body,
) -> Result<Json<serde_json::Value>, ApiError> {
    require_admin(&state.db, &headers, query.auth.api_key.as_deref()).await?;
    let item = lyrics_audio_item(&state.db, &item_id).await?;
    let file_name = query
        .file_name
        .as_deref()
        .ok_or_else(|| ApiError::bad_request("Lyrics fileName is required"))?;
    let format = lyrics_upload_format(file_name)?;
    let body = to_bytes(body, LYRICS_UPLOAD_LIMIT_BYTES)
        .await
        .map_err(|_| ApiError::bad_request("Invalid lyrics upload body"))?;
    if body.is_empty() {
        return Err(ApiError::bad_request("Lyrics upload body is empty"));
    }
    let text = String::from_utf8(body.to_vec())
        .map_err(|_| ApiError::bad_request("Lyrics upload body must be UTF-8 text"))?;
    let lyrics = parse_lyrics_text(&text, &format, file_name)?;
    state
        .db
        .update_media_item_lyrics(item.id, lyrics.clone())
        .await?;
    Ok(Json(lyrics))
}

async fn delete_lyrics(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    Path(item_id): Path<String>,
) -> Result<StatusCode, ApiError> {
    require_admin(&state.db, &headers, query.api_key.as_deref()).await?;
    let item = lyrics_audio_item(&state.db, &item_id).await?;
    state.db.delete_media_item_lyrics(item.id).await?;
    Ok(StatusCode::NO_CONTENT)
}

async fn search_remote_lyrics(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    Path(item_id): Path<String>,
) -> Result<Json<Vec<serde_json::Value>>, ApiError> {
    require_admin(&state.db, &headers, query.api_key.as_deref()).await?;
    let item = lyrics_audio_item(&state.db, &item_id).await?;
    let Some(lyrics) = state.db.media_item_lyrics(item.id).await? else {
        return Ok(Json(Vec::new()));
    };
    Ok(Json(vec![remote_lyrics_result(&item, &lyrics.payload)]))
}

async fn download_remote_lyrics(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    Path((item_id, lyric_id)): Path<(String, String)>,
) -> Result<StatusCode, ApiError> {
    require_admin(&state.db, &headers, query.api_key.as_deref()).await?;
    let item = lyrics_audio_item(&state.db, &item_id).await?;
    let requested_id = remote_lyrics_id_for_item(item.id);
    if lyric_id != requested_id {
        return Err(ApiError::not_found("Remote lyrics not found"));
    }
    state
        .db
        .media_item_lyrics(item.id)
        .await?
        .ok_or_else(|| ApiError::not_found("Remote lyrics not found"))?;
    Ok(StatusCode::NO_CONTENT)
}

async fn get_remote_lyrics(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    Path(lyric_id): Path<String>,
) -> Result<Json<serde_json::Value>, ApiError> {
    require_admin(&state.db, &headers, query.api_key.as_deref()).await?;
    let item_id = remote_lyrics_item_id(&lyric_id)?;
    let item = lyrics_audio_item(&state.db, &item_id.simple().to_string()).await?;
    let lyrics = state
        .db
        .media_item_lyrics(item.id)
        .await?
        .ok_or_else(|| ApiError::not_found("Remote lyrics not found"))?;
    Ok(Json(lyrics.payload))
}

async fn lyrics_audio_item(db: &Database, item_id: &str) -> Result<MediaItem, ApiError> {
    let item = media_item_by_id(db, item_id).await?;
    if !item.media_type.eq_ignore_ascii_case("Audio") {
        return Err(ApiError::bad_request(
            "Lyrics are only supported for audio items",
        ));
    }
    Ok(item)
}

fn lyrics_upload_format(file_name: &str) -> Result<String, ApiError> {
    let candidate = FsPath::new(file_name)
        .extension()
        .and_then(|ext| ext.to_str())
        .unwrap_or("")
        .trim()
        .trim_start_matches('.')
        .to_ascii_lowercase();
    if matches!(candidate.as_str(), "lrc" | "elrc" | "txt") {
        Ok(candidate)
    } else {
        Err(ApiError::bad_request("Unsupported lyrics format"))
    }
}

fn parse_lyrics_text(
    text: &str,
    format: &str,
    file_name: &str,
) -> Result<serde_json::Value, ApiError> {
    let lines = match format {
        "lrc" | "elrc" => parse_lrc_lyrics_lines(text),
        "txt" => parse_plain_lyrics_lines(text),
        _ => return Err(ApiError::bad_request("Unsupported lyrics format")),
    };
    if lines.is_empty() {
        return Err(ApiError::bad_request(
            "Lyrics upload body contains no lyrics",
        ));
    }
    Ok(serde_json::json!({
        "Metadata": {
            "FileName": file_name,
            "Format": format,
            "IsSynced": format != "txt"
        },
        "Lyrics": lines
    }))
}

fn remote_lyrics_result(item: &MediaItem, lyrics: &serde_json::Value) -> serde_json::Value {
    let metadata = lyrics.get("Metadata");
    let format = metadata
        .and_then(|metadata| metadata.get("Format"))
        .and_then(serde_json::Value::as_str)
        .unwrap_or("lrc");
    let file_name = metadata
        .and_then(|metadata| metadata.get("FileName"))
        .and_then(serde_json::Value::as_str)
        .unwrap_or("local lyrics");
    serde_json::json!({
        "Id": remote_lyrics_id_for_item(item.id),
        "ProviderName": "Local cache",
        "Name": file_name,
        "Format": format,
        "Author": null,
        "AlbumArtist": null,
        "Artist": null,
        "Album": null,
        "Title": item.name,
        "Duration": null,
        "IsPerfectMatch": true
    })
}

fn remote_lyrics_id_for_item(item_id: Uuid) -> String {
    format!("local-cache:{}", item_id.simple())
}

fn remote_lyrics_item_id(lyric_id: &str) -> Result<Uuid, ApiError> {
    let encoded = lyric_id
        .strip_prefix("local-cache:")
        .ok_or_else(|| ApiError::not_found("Remote lyrics not found"))?;
    parse_jellyfin_uuid(encoded).map_err(|_| ApiError::not_found("Remote lyrics not found"))
}

fn parse_plain_lyrics_lines(text: &str) -> Vec<serde_json::Value> {
    text.lines()
        .map(str::trim)
        .filter(|line| !line.is_empty())
        .map(|line| serde_json::json!({ "Text": line, "Start": null }))
        .collect()
}

fn parse_lrc_lyrics_lines(text: &str) -> Vec<serde_json::Value> {
    let mut lines = Vec::new();
    for raw_line in text.lines() {
        let mut remainder = raw_line.trim();
        let mut starts = Vec::new();
        while let Some(stripped) = remainder.strip_prefix('[') {
            let Some((tag, rest)) = stripped.split_once(']') else {
                break;
            };
            match parse_lrc_timestamp_ticks(tag) {
                Some(start) => {
                    starts.push(start);
                    remainder = rest.trim_start();
                }
                None => {
                    remainder = rest.trim_start();
                    break;
                }
            }
        }
        let text = remainder.trim();
        if text.is_empty() {
            continue;
        }
        for start in &starts {
            lines.push(serde_json::json!({ "Text": text, "Start": start }));
        }
    }
    lines.sort_by_key(|line| {
        line.get("Start")
            .and_then(json_value_i64)
            .unwrap_or_default()
    });
    lines
}

fn parse_lrc_timestamp_ticks(value: &str) -> Option<i64> {
    let (minutes, rest) = value.split_once(':')?;
    let minutes = minutes.parse::<i64>().ok()?;
    let (seconds, fraction) = rest
        .split_once('.')
        .or_else(|| rest.split_once(','))
        .map_or((rest, ""), |(seconds, fraction)| (seconds, fraction));
    let seconds = seconds.parse::<i64>().ok()?;
    if !(0..60).contains(&seconds) {
        return None;
    }
    let fraction = fraction
        .chars()
        .take(7)
        .filter(|ch| ch.is_ascii_digit())
        .collect::<String>();
    let fraction_ticks = if fraction.is_empty() {
        0
    } else {
        let scale = 10_i64.pow(7_u32.saturating_sub(fraction.len() as u32));
        fraction.parse::<i64>().ok()?.saturating_mul(scale)
    };
    Some(
        minutes
            .saturating_mul(60)
            .saturating_add(seconds)
            .saturating_mul(10_000_000)
            .saturating_add(fraction_ticks),
    )
}

async fn upload_subtitle(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    Path(item_id): Path<String>,
    body: Body,
) -> Result<StatusCode, ApiError> {
    require_admin(&state.db, &headers, query.api_key.as_deref()).await?;
    let item = subtitle_media_item(&state, &item_id, None).await?;
    let body = to_bytes(body, SUBTITLE_UPLOAD_LIMIT_BYTES)
        .await
        .map_err(|_| ApiError::bad_request("Invalid subtitle upload body"))?;
    let payload: UploadSubtitleDto = serde_json::from_slice(&body)
        .map_err(|_| ApiError::bad_request("Subtitle upload body must be JSON"))?;
    let format = subtitle_upload_format(&payload)?;
    let data = payload
        .data
        .as_deref()
        .ok_or_else(|| ApiError::bad_request("Subtitle upload data is required"))?;
    let data = decode_upload_subtitle_data(data)?;
    if data.is_empty() {
        return Err(ApiError::bad_request("Subtitle upload data is empty"));
    }

    let item_path = media_item_path(&item);
    let item_dir = item_path
        .parent()
        .ok_or_else(|| ApiError::not_found("Subtitle media source not found"))?;
    let subtitle_dir = item_dir.join(".jellyrin-subtitles");
    tokio::fs::create_dir_all(&subtitle_dir).await?;

    let mut streams = media_item_streams(&item);
    let next_index = next_subtitle_stream_index(&streams);
    let file_stem = subtitle_upload_file_stem(&payload)
        .unwrap_or_else(|| format!("{}-{next_index}", item.id.simple()));
    let subtitle_path = subtitle_dir.join(format!("{file_stem}.{format}"));
    tokio::fs::write(&subtitle_path, data).await?;

    streams.push(serde_json::json!({
        "Codec": format,
        "Language": payload.language.as_deref().filter(|value| !value.trim().is_empty()),
        "DisplayTitle": subtitle_display_title(&payload, &format),
        "IsInterlaced": false,
        "IsDefault": false,
        "IsForced": payload.is_forced.unwrap_or(false),
        "Type": "Subtitle",
        "Index": next_index,
        "IsExternal": true,
        "IsTextSubtitleStream": true,
        "SupportsExternalStream": true,
        "Path": subtitle_path.to_string_lossy().to_string(),
        "DeliveryMethod": "External",
        "IsHearingImpaired": payload.is_hearing_impaired.unwrap_or(false)
    }));
    persist_media_streams(&state.db, &item, streams).await?;
    Ok(StatusCode::NO_CONTENT)
}

async fn delete_subtitle(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    Path((item_id, index)): Path<(String, i64)>,
) -> Result<StatusCode, ApiError> {
    require_admin(&state.db, &headers, query.api_key.as_deref()).await?;
    let item = subtitle_media_item(&state, &item_id, None).await?;
    let mut removed_path = None;
    let mut found = false;
    let streams = media_item_streams(&item)
        .into_iter()
        .filter(|stream| {
            let is_target = stream
                .get("Type")
                .and_then(serde_json::Value::as_str)
                .is_some_and(|stream_type| stream_type.eq_ignore_ascii_case("Subtitle"))
                && stream.get("Index").and_then(json_value_i64) == Some(index);
            if is_target {
                found = true;
                if stream
                    .get("IsExternal")
                    .and_then(serde_json::Value::as_bool)
                    .unwrap_or(false)
                {
                    removed_path = stream
                        .get("Path")
                        .and_then(serde_json::Value::as_str)
                        .map(PathBuf::from);
                }
            }
            !is_target
        })
        .collect::<Vec<_>>();

    if !found {
        return Err(ApiError::not_found("Subtitle stream not found"));
    }
    if let Some(path) = removed_path
        && subtitle_sidecar_is_within_item_dir(&item, &path).await?
    {
        match tokio::fs::remove_file(path).await {
            Ok(()) => {}
            Err(error) if error.kind() == std::io::ErrorKind::NotFound => {}
            Err(error) => return Err(error.into()),
        }
    }
    persist_media_streams(&state.db, &item, streams).await?;
    Ok(StatusCode::NO_CONTENT)
}

fn subtitle_upload_format(payload: &UploadSubtitleDto) -> Result<String, ApiError> {
    let candidate = payload
        .format
        .as_deref()
        .or_else(|| {
            payload
                .file_name
                .as_deref()
                .and_then(|name| FsPath::new(name).extension().and_then(|ext| ext.to_str()))
        })
        .unwrap_or("srt")
        .trim()
        .trim_start_matches('.')
        .to_ascii_lowercase();
    if matches!(candidate.as_str(), "srt" | "vtt" | "ass" | "ssa") {
        Ok(candidate)
    } else {
        Err(ApiError::bad_request("Unsupported subtitle format"))
    }
}

fn decode_upload_subtitle_data(value: &str) -> Result<Vec<u8>, ApiError> {
    let data = value.split_once(',').map_or(value, |(_, data)| data).trim();
    general_purpose::STANDARD
        .decode(data)
        .map_err(|_| ApiError::bad_request("Subtitle upload data must be base64"))
}

fn subtitle_upload_file_stem(payload: &UploadSubtitleDto) -> Option<String> {
    payload
        .file_name
        .as_deref()
        .and_then(|name| FsPath::new(name).file_stem().and_then(|stem| stem.to_str()))
        .map(sanitize_file_stem)
        .filter(|value| !value.is_empty())
}

fn sanitize_file_stem(value: &str) -> String {
    value
        .chars()
        .map(|ch| {
            if ch.is_ascii_alphanumeric() || matches!(ch, '-' | '_' | '.') {
                ch
            } else {
                '-'
            }
        })
        .collect::<String>()
        .trim_matches('-')
        .to_string()
}

fn subtitle_display_title(payload: &UploadSubtitleDto, format: &str) -> String {
    let mut parts = Vec::new();
    if let Some(language) = payload
        .language
        .as_deref()
        .filter(|value| !value.is_empty())
    {
        parts.push(language.to_string());
    }
    if payload.is_forced.unwrap_or(false) {
        parts.push("Forced".to_string());
    }
    if payload.is_hearing_impaired.unwrap_or(false) {
        parts.push("SDH".to_string());
    }
    if parts.is_empty() {
        format.to_ascii_uppercase()
    } else {
        parts.join(" - ")
    }
}

fn next_subtitle_stream_index(streams: &[serde_json::Value]) -> i64 {
    streams
        .iter()
        .filter_map(|stream| stream.get("Index").and_then(json_value_i64))
        .max()
        .map_or(0, |index| index.saturating_add(1))
}

async fn persist_media_streams(
    db: &Database,
    item: &MediaItem,
    streams: Vec<serde_json::Value>,
) -> Result<(), ApiError> {
    db.update_media_item_media_info(
        item.id,
        item.runtime_ticks,
        item.bitrate,
        item.width,
        item.height,
        streams,
    )
    .await?;
    Ok(())
}

async fn subtitle_sidecar_is_within_item_dir(
    item: &MediaItem,
    subtitle_path: &FsPath,
) -> Result<bool, ApiError> {
    let item_dir = media_item_path(item)
        .parent()
        .ok_or_else(|| ApiError::not_found("Subtitle media source not found"))?
        .to_path_buf();
    let canonical_item_dir = tokio::fs::canonicalize(item_dir).await?;
    let canonical_subtitle = match tokio::fs::canonicalize(subtitle_path).await {
        Ok(path) => path,
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => return Ok(false),
        Err(error) => return Err(error.into()),
    };
    Ok(canonical_subtitle.starts_with(canonical_item_dir))
}

#[derive(Debug, Deserialize)]
struct SubtitlePlaylistQuery {
    #[serde(alias = "api_key", alias = "apiKey", alias = "ApiKey")]
    api_key: Option<String>,
    #[serde(default, alias = "segmentLength", alias = "SegmentLength")]
    segment_length: Option<i64>,
}

#[derive(Debug, Default)]
struct SubtitleStreamQuery {
    _api_key: Option<String>,
    item_id: Option<String>,
    media_source_id: Option<String>,
    index: Option<i64>,
    format: Option<String>,
    start_position_ticks: Option<i64>,
    end_position_ticks: Option<i64>,
    _copy_timestamps: bool,
    add_vtt_time_map: bool,
}

#[derive(Debug)]
struct SubtitleStreamRoute {
    item_id: String,
    media_source_id: String,
    index: i64,
    start_position_ticks: i64,
    format: String,
}

async fn subtitle_playlist(
    State(state): State<AppState>,
    headers: HeaderMap,
    Path((item_id, media_source_id, index)): Path<(String, String, i64)>,
    Query(query): Query<SubtitlePlaylistQuery>,
) -> Result<axum::response::Response, ApiError> {
    require_request_user(&state.db, &headers, query.api_key.as_deref()).await?;
    let item = subtitle_media_item(&state, &item_id, Some(&media_source_id)).await?;
    subtitle_stream_info(&item, index)?;
    let runtime_ticks = item
        .runtime_ticks
        .filter(|runtime_ticks| *runtime_ticks > 0)
        .ok_or_else(|| ApiError::bad_request("HLS Subtitles are not supported for this media"))?;
    let segment_length = query
        .segment_length
        .filter(|segment_length| *segment_length > 0)
        .ok_or_else(|| ApiError::bad_request("segmentLength is required"))?;
    let segment_length_ticks = segment_length
        .checked_mul(10_000_000)
        .ok_or_else(|| ApiError::bad_request("segmentLength is invalid"))?;

    let mut playlist = String::new();
    playlist.push_str("#EXTM3U\n");
    playlist.push_str(&format!("#EXT-X-TARGETDURATION:{segment_length}\n"));
    playlist.push_str("#EXT-X-VERSION:3\n");
    playlist.push_str("#EXT-X-MEDIA-SEQUENCE:0\n");
    playlist.push_str("#EXT-X-PLAYLIST-TYPE:VOD\n");

    let mut position_ticks = 0_i64;
    while position_ticks < runtime_ticks {
        let end_ticks = runtime_ticks.min(position_ticks.saturating_add(segment_length_ticks));
        let duration = (end_ticks - position_ticks) as f64 / 10_000_000.0;
        playlist.push_str(&format!("#EXTINF:{duration},\n"));
        playlist.push_str(&format!(
            "stream.vtt?CopyTimestamps=true&AddVttTimeMap=true&StartPositionTicks={position_ticks}&EndPositionTicks={end_ticks}"
        ));
        if let Some(api_key) = query
            .api_key
            .as_deref()
            .filter(|api_key| !api_key.trim().is_empty())
        {
            playlist.push_str("&ApiKey=");
            playlist.push_str(api_key);
        }
        playlist.push('\n');
        position_ticks = position_ticks.saturating_add(segment_length_ticks);
    }
    playlist.push_str("#EXT-X-ENDLIST\n");

    playlist_response(playlist, true)
}

async fn subtitle_stream(
    State(state): State<AppState>,
    headers: HeaderMap,
    Path((route_item_id, route_media_source_id, route_index, route_format)): Path<(
        String,
        String,
        i64,
        String,
    )>,
    RawQuery(raw_query): RawQuery,
) -> Result<axum::response::Response, ApiError> {
    let query = parse_subtitle_stream_query(raw_query.as_deref());
    subtitle_stream_response(
        &state,
        &headers,
        SubtitleStreamRoute {
            item_id: route_item_id,
            media_source_id: route_media_source_id,
            index: route_index,
            start_position_ticks: 0,
            format: route_format,
        },
        query,
    )
    .await
}

async fn subtitle_stream_with_ticks(
    State(state): State<AppState>,
    headers: HeaderMap,
    Path((
        route_item_id,
        route_media_source_id,
        route_index,
        route_start_position_ticks,
        route_format,
    )): Path<(String, String, i64, i64, String)>,
    RawQuery(raw_query): RawQuery,
) -> Result<axum::response::Response, ApiError> {
    let query = parse_subtitle_stream_query(raw_query.as_deref());
    subtitle_stream_response(
        &state,
        &headers,
        SubtitleStreamRoute {
            item_id: route_item_id,
            media_source_id: route_media_source_id,
            index: route_index,
            start_position_ticks: route_start_position_ticks,
            format: route_format,
        },
        query,
    )
    .await
}

async fn subtitle_stream_response(
    state: &AppState,
    _headers: &HeaderMap,
    route: SubtitleStreamRoute,
    query: SubtitleStreamQuery,
) -> Result<axum::response::Response, ApiError> {
    let item_id = query.item_id.as_deref().unwrap_or(&route.item_id);
    let media_source_id = query
        .media_source_id
        .as_deref()
        .unwrap_or(&route.media_source_id);
    let index = query.index.unwrap_or(route.index);
    let format = query
        .format
        .as_deref()
        .unwrap_or(&route.format)
        .trim()
        .to_ascii_lowercase();
    let format = if format == "js" { "json" } else { &format };
    let start_position_ticks = query
        .start_position_ticks
        .unwrap_or(route.start_position_ticks)
        .max(0);
    let end_position_ticks = query.end_position_ticks.filter(|ticks| *ticks >= 0);

    let item = subtitle_media_item(state, item_id, Some(media_source_id)).await?;
    let stream = subtitle_stream_info(&item, index)?;
    let output = if let Some(path) = stream.get("Path").and_then(serde_json::Value::as_str) {
        subtitle_output_from_external_path(path, format, start_position_ticks, end_position_ticks)
            .await?
    } else {
        subtitle_output_from_ffmpeg(
            media_item_path(&item),
            index,
            format,
            start_position_ticks,
            end_position_ticks,
        )
        .await?
    };
    let output = if format == "vtt" && query.add_vtt_time_map {
        subtitle_add_vtt_time_map(output)
    } else {
        output
    };

    Ok((
        StatusCode::OK,
        [(
            header::CONTENT_TYPE,
            subtitle_content_type(format).to_string(),
        )],
        Body::from(output),
    )
        .into_response())
}

async fn subtitle_media_item(
    state: &AppState,
    item_id: &str,
    media_source_id: Option<&str>,
) -> Result<MediaItem, ApiError> {
    let requested_item = media_item_by_id(&state.db, item_id).await?;
    let item = resolve_media_source_item(&state.db, requested_item, media_source_id)
        .await?
        .ok_or_else(|| ApiError::not_found("Subtitle media source not found"))?;
    if item.media_type != "Video" {
        return Err(ApiError::not_found("Subtitle media source not found"));
    }
    Ok(item)
}

fn subtitle_stream_info(item: &MediaItem, index: i64) -> Result<serde_json::Value, ApiError> {
    media_item_streams(item)
        .into_iter()
        .find(|stream| {
            stream
                .get("Type")
                .and_then(serde_json::Value::as_str)
                .is_some_and(|stream_type| stream_type.eq_ignore_ascii_case("Subtitle"))
                && stream.get("Index").and_then(json_value_i64) == Some(index)
        })
        .ok_or_else(|| ApiError::not_found("Subtitle stream not found"))
}

async fn subtitle_output_from_external_path(
    path: &str,
    format: &str,
    start_position_ticks: i64,
    end_position_ticks: Option<i64>,
) -> Result<Vec<u8>, ApiError> {
    let source_path = PathBuf::from(path);
    if subtitle_path_format(&source_path).as_deref() == Some(format) && start_position_ticks == 0 {
        let bytes = tokio::fs::read(source_path).await?;
        return Ok(bytes);
    }
    subtitle_output_from_ffmpeg(
        source_path.as_path(),
        0,
        format,
        start_position_ticks,
        end_position_ticks,
    )
    .await
}

async fn subtitle_output_from_ffmpeg(
    input_path: &FsPath,
    index: i64,
    format: &str,
    start_position_ticks: i64,
    end_position_ticks: Option<i64>,
) -> Result<Vec<u8>, ApiError> {
    if !matches!(format, "vtt" | "srt" | "ass" | "ssa") {
        return Err(ApiError::bad_request("Unsupported subtitle format"));
    }
    if index < 0 {
        return Err(ApiError::bad_request("Invalid subtitle index"));
    }

    let mut command = Command::new("ffmpeg");
    command.arg("-hide_banner").arg("-nostdin").arg("-y");
    if start_position_ticks > 0 {
        command
            .arg("-ss")
            .arg(format_ticks_as_ffmpeg_seconds(start_position_ticks));
    }
    command.arg("-i").arg(input_path);
    if let Some(end_position_ticks) = end_position_ticks
        && end_position_ticks > start_position_ticks
    {
        command
            .arg("-to")
            .arg(format_ticks_as_ffmpeg_seconds(end_position_ticks));
    }
    command
        .arg("-map")
        .arg(format!("0:{index}"))
        .arg("-f")
        .arg(subtitle_ffmpeg_format(format))
        .arg("pipe:1")
        .stdout(Stdio::piped())
        .stderr(Stdio::piped());

    let output = command.output().await?;
    if !output.status.success() {
        tracing::warn!(
            index,
            format,
            stderr = %String::from_utf8_lossy(&output.stderr),
            "ffmpeg failed to extract subtitle stream"
        );
        return Err(ApiError::not_found("Subtitle stream not found"));
    }
    Ok(output.stdout)
}

fn subtitle_add_vtt_time_map(output: Vec<u8>) -> Vec<u8> {
    let text = String::from_utf8_lossy(&output);
    if text.starts_with("WEBVTT\nX-TIMESTAMP-MAP=")
        || text.starts_with("WEBVTT\r\nX-TIMESTAMP-MAP=")
    {
        return output;
    }
    if text.starts_with("WEBVTT") {
        return text
            .replacen(
                "WEBVTT",
                "WEBVTT\nX-TIMESTAMP-MAP=MPEGTS:900000,LOCAL:00:00:00.000",
                1,
            )
            .into_bytes();
    }
    output
}

fn parse_subtitle_stream_query(raw_query: Option<&str>) -> SubtitleStreamQuery {
    let mut query = SubtitleStreamQuery::default();
    let Some(raw_query) = raw_query else {
        return query;
    };
    for (key, value) in raw_query.split('&').filter_map(|pair| pair.split_once('=')) {
        match key.to_ascii_lowercase().as_str() {
            "api_key" | "apikey" => query._api_key = Some(value.to_string()),
            "itemid" => query.item_id = Some(value.to_string()),
            "mediasourceid" => query.media_source_id = Some(value.to_string()),
            "index" => query.index = value.parse().ok(),
            "format" => query.format = Some(value.to_string()),
            "startpositionticks" => query.start_position_ticks = value.parse().ok(),
            "endpositionticks" => query.end_position_ticks = value.parse().ok(),
            "copytimestamps" => query._copy_timestamps = parse_query_bool(value).unwrap_or(false),
            "addvtttimemap" => query.add_vtt_time_map = parse_query_bool(value).unwrap_or(false),
            _ => {}
        }
    }
    query
}

fn subtitle_path_format(path: &FsPath) -> Option<String> {
    path.extension()
        .and_then(|extension| extension.to_str())
        .map(|extension| extension.to_ascii_lowercase())
}

fn subtitle_ffmpeg_format(format: &str) -> &'static str {
    match format {
        "vtt" => "webvtt",
        "srt" => "srt",
        "ass" | "ssa" => "ass",
        _ => "webvtt",
    }
}

fn subtitle_content_type(format: &str) -> &'static str {
    match format {
        "vtt" => "text/vtt; charset=utf-8",
        "srt" => "application/x-subrip; charset=utf-8",
        "ass" | "ssa" => "text/plain; charset=utf-8",
        "json" => "application/json; charset=utf-8",
        _ => "text/plain; charset=utf-8",
    }
}

fn format_ticks_as_ffmpeg_seconds(ticks: i64) -> String {
    format!("{:.3}", ticks.max(0) as f64 / 10_000_000.0)
}

async fn audio_hls_item(
    state: &AppState,
    headers: &HeaderMap,
    query_token: Option<&str>,
    item_id: &str,
) -> Result<MediaItem, ApiError> {
    require_request_user(&state.db, headers, query_token).await?;
    let item = media_item_by_id(&state.db, item_id).await?;
    if item.media_type != "Audio" {
        return Err(ApiError::not_found("Audio HLS item not found"));
    }
    Ok(item)
}

fn audio_hls_segment_container(item: &MediaItem) -> Result<String, ApiError> {
    let container = media_item_container(item)
        .ok_or_else(|| ApiError::not_found("Audio HLS segment not found"))?;
    if matches!(container.as_str(), "aac" | "mp3") {
        Ok(container)
    } else {
        Err(ApiError::not_found("Audio HLS segment not found"))
    }
}

async fn trickplay_playlist(
    State(state): State<AppState>,
    Path((item_id, width)): Path<(String, String)>,
    headers: HeaderMap,
    Query(query): Query<TrickplayQuery>,
) -> Result<axum::response::Response, ApiError> {
    let item = trickplay_video_item(&state, &headers, &query, &item_id).await?;
    let width = parse_positive_u32(&width, "Invalid trickplay width")?;
    let settings = trickplay_settings(&state.db).await?;
    validate_trickplay_width(width, &settings)?;
    let info = ensure_trickplay_info(&state.db, &item, &settings, width, 0).await?;
    let thumbnail_duration = (info.interval_ms as f64 / 1000.0).max(1.0);
    let thumbnails_per_sprite = trickplay_thumbnails_per_sprite(&settings);
    let sprite_count = trickplay_sprite_count(info.thumbnail_count, thumbnails_per_sprite);
    let mut playlist = format!(
        "#EXTM3U\n#EXT-X-TARGETDURATION:{sprite_count}\n#EXT-X-VERSION:7\n#EXT-X-MEDIA-SEQUENCE:1\n#EXT-X-PLAYLIST-TYPE:VOD\n#EXT-X-IMAGES-ONLY\n"
    );
    for index in 0..sprite_count {
        let sprite_duration = trickplay_sprite_duration(
            info.thumbnail_count,
            thumbnails_per_sprite,
            thumbnail_duration,
            index,
        );
        playlist.push_str(&format!(
            "#EXTINF:{sprite_duration:.3},\n#EXT-X-TILES:RESOLUTION={}x{},LAYOUT={}x{},DURATION={thumbnail_duration:.3}\n{}\n",
            info.width,
            info.height,
            info.tile_width,
            info.tile_height,
            trickplay_tile_uri(index, item.id, query.api_key.as_deref())
        ));
    }
    playlist.push_str("#EXT-X-ENDLIST\n");
    playlist_response(playlist, true)
}

async fn trickplay_tile(
    State(state): State<AppState>,
    Path((item_id, width, tile_file)): Path<(String, String, String)>,
    headers: HeaderMap,
    Query(query): Query<TrickplayQuery>,
) -> Result<axum::response::Response, ApiError> {
    let item = trickplay_video_item(&state, &headers, &query, &item_id).await?;
    let width = parse_positive_u32(&width, "Invalid trickplay width")?;
    let settings = trickplay_settings(&state.db).await?;
    validate_trickplay_width(width, &settings)?;
    let index = tile_file
        .strip_suffix(".jpg")
        .ok_or_else(|| ApiError::not_found("Trickplay tile not found"))?;
    let index = parse_non_negative_i64(index, "Invalid trickplay index")?;
    let info = ensure_trickplay_info(&state.db, &item, &settings, width, 0).await?;
    let sprite_count = trickplay_sprite_count(
        info.thumbnail_count,
        trickplay_thumbnails_per_sprite(&settings),
    );
    let index =
        u32::try_from(index).map_err(|_| ApiError::not_found("Trickplay tile not found"))?;
    if i64::from(index) >= sprite_count {
        return Err(ApiError::not_found("Trickplay tile not found"));
    }
    let tile_path = ensure_trickplay_tile(&state.db, &item, &settings, width, index).await?;
    stream_path(tile_path, "image/jpeg".to_string(), &headers, true).await
}

async fn ensure_trickplay_tile(
    db: &Database,
    item: &MediaItem,
    settings: &TrickplaySettings,
    width: u32,
    index: u32,
) -> Result<PathBuf, ApiError> {
    let tile_path = trickplay_tile_cache_path(item, settings, width, index);
    if tokio::fs::try_exists(&tile_path).await? {
        return Ok(tile_path);
    }

    let tile_lock = trickplay_tile_lock(&tile_path).await;
    let _tile_guard = tile_lock.lock().await;
    if tokio::fs::try_exists(&tile_path).await? {
        return Ok(tile_path);
    }

    let parent = tile_path
        .parent()
        .ok_or_else(|| ApiError::not_found("Trickplay tile not found"))?;
    tokio::fs::create_dir_all(parent).await?;
    let tmp_path = tile_path.with_extension(format!("jpg.tmp.{}", Uuid::new_v4().simple()));
    let thumbnails_per_sprite = trickplay_thumbnails_per_sprite(settings);
    let first_thumbnail = i64::from(index) * thumbnails_per_sprite;
    let info = ensure_trickplay_info(db, item, settings, width, 0).await?;
    let remaining = info.thumbnail_count.saturating_sub(first_thumbnail);
    let frame_count = remaining.min(thumbnails_per_sprite).max(1);
    let seek_seconds = first_thumbnail as f64 * settings.interval_seconds;
    let scale_filter = format!("scale='min({width},iw)':-2:force_original_aspect_ratio=decrease");
    let tile_filter = format!(
        "tile={}x{}:nb_frames={frame_count}:padding=0:margin=0",
        settings.tile_width, settings.tile_height
    );
    let filter = format!(
        "fps=1/{:.3},{scale_filter},{tile_filter}",
        settings.interval_seconds
    );
    let output = Command::new("ffmpeg")
        .arg("-hide_banner")
        .arg("-nostdin")
        .arg("-y")
        .arg("-ss")
        .arg(format!("{seek_seconds:.3}"))
        .arg("-i")
        .arg(media_item_path(item))
        .arg("-vf")
        .arg(filter)
        .arg("-frames:v")
        .arg("1")
        .arg("-threads")
        .arg(settings.process_threads.to_string())
        .arg("-q:v")
        .arg(settings.qscale.to_string())
        .arg("-f")
        .arg("image2")
        .arg("-c:v")
        .arg("mjpeg")
        .arg(&tmp_path)
        .stdout(Stdio::null())
        .stderr(Stdio::piped())
        .output()
        .await
        .map_err(|_| ApiError::not_found("Trickplay tile could not be generated"))?;
    if !output.status.success() {
        let _ = tokio::fs::remove_file(&tmp_path).await;
        let stderr = String::from_utf8_lossy(&output.stderr)
            .chars()
            .take(512)
            .collect::<String>();
        tracing::warn!(
            item_id = %item.id,
            width,
            index,
            status = %output.status,
            stderr = %stderr,
            "ffmpeg failed to generate trickplay tile"
        );
        return Err(ApiError::not_found("Trickplay tile could not be generated"));
    }
    if tokio::fs::try_exists(&tile_path).await? {
        let _ = tokio::fs::remove_file(&tmp_path).await;
        return Ok(tile_path);
    }
    tokio::fs::rename(&tmp_path, &tile_path).await?;
    persist_trickplay_info_from_tile(db, item, settings, width, &tile_path, info).await?;
    Ok(tile_path)
}

async fn ensure_trickplay_info(
    db: &Database,
    item: &MediaItem,
    settings: &TrickplaySettings,
    width: u32,
    bandwidth: i64,
) -> Result<TrickplayInfo, ApiError> {
    let (thumbnail_width, thumbnail_height) = trickplay_tile_resolution(item, width);
    if let Some(existing) = db
        .trickplay_info(item.id, i64::from(thumbnail_width))
        .await?
        && existing.height == i64::from(thumbnail_height)
        && existing.tile_width == i64::from(settings.tile_width)
        && existing.tile_height == i64::from(settings.tile_height)
        && existing.interval_ms == settings.interval_ms
        && existing.thumbnail_count
            == trickplay_thumbnail_count(
                trickplay_duration_seconds(item),
                settings.interval_seconds,
            )
    {
        return Ok(existing);
    }
    persist_trickplay_info(
        db,
        item.id,
        thumbnail_width,
        thumbnail_height,
        settings,
        trickplay_thumbnail_count(trickplay_duration_seconds(item), settings.interval_seconds),
        bandwidth,
    )
    .await
}

async fn persist_trickplay_info_from_tile(
    db: &Database,
    item: &MediaItem,
    settings: &TrickplaySettings,
    width: u32,
    tile_path: &FsPath,
    current: TrickplayInfo,
) -> Result<TrickplayInfo, ApiError> {
    let thumbnails_per_sprite = trickplay_thumbnails_per_sprite(settings);
    let tile_len = tokio::fs::metadata(tile_path)
        .await
        .map(|metadata| metadata.len())
        .unwrap_or(0);
    let bandwidth = ((tile_len.saturating_mul(8)) as f64
        / thumbnails_per_sprite.max(1) as f64
        / settings.interval_seconds.max(1.0))
    .ceil() as i64;
    persist_trickplay_info(
        db,
        item.id,
        u32::try_from(current.width).unwrap_or(width),
        u32::try_from(current.height).unwrap_or(width),
        settings,
        current.thumbnail_count,
        bandwidth.max(current.bandwidth),
    )
    .await
}

async fn persist_trickplay_info(
    db: &Database,
    item_id: Uuid,
    width: u32,
    height: u32,
    settings: &TrickplaySettings,
    thumbnail_count: i64,
    bandwidth: i64,
) -> Result<TrickplayInfo, ApiError> {
    db.upsert_trickplay_info(TrickplayInfo {
        item_id,
        width: i64::from(width),
        height: i64::from(height),
        tile_width: i64::from(settings.tile_width),
        tile_height: i64::from(settings.tile_height),
        thumbnail_count,
        interval_ms: settings.interval_ms,
        bandwidth: bandwidth.max(0),
        created_at: OffsetDateTime::now_utc(),
        updated_at: OffsetDateTime::now_utc(),
    })
    .await
    .map_err(Into::into)
}

fn trickplay_duration_seconds(item: &MediaItem) -> f64 {
    item.runtime_ticks
        .and_then(|ticks| u64::try_from(ticks).ok())
        .map(|ticks| (ticks as f64 / 10_000_000.0).max(1.0))
        .unwrap_or(10.0)
}

fn trickplay_thumbnail_count(duration_seconds: f64, interval_seconds: f64) -> i64 {
    ((duration_seconds / interval_seconds).ceil() as i64).clamp(1, 100_000)
}

fn trickplay_thumbnails_per_sprite(settings: &TrickplaySettings) -> i64 {
    i64::from(settings.tile_width) * i64::from(settings.tile_height)
}

fn trickplay_sprite_count(thumbnail_count: i64, thumbnails_per_sprite: i64) -> i64 {
    ((thumbnail_count.max(1) + thumbnails_per_sprite.max(1) - 1) / thumbnails_per_sprite.max(1))
        .clamp(1, 10_000)
}

fn trickplay_sprite_duration(
    thumbnail_count: i64,
    thumbnails_per_sprite: i64,
    thumbnail_duration: f64,
    index: i64,
) -> f64 {
    let first_thumbnail = index * thumbnails_per_sprite;
    let remaining = thumbnail_count.saturating_sub(first_thumbnail);
    let thumbnails = remaining.min(thumbnails_per_sprite).max(1);
    thumbnail_duration * thumbnails as f64
}

fn trickplay_tile_uri(index: i64, item_id: Uuid, api_key: Option<&str>) -> String {
    let mut uri = format!("{index}.jpg?MediaSourceId={}", item_id.simple());
    if let Some(api_key) = api_key.filter(|api_key| !api_key.trim().is_empty()) {
        uri.push_str("&ApiKey=");
        uri.push_str(api_key);
    }
    uri
}

fn trickplay_tile_resolution(item: &MediaItem, requested_width: u32) -> (u32, u32) {
    let source_width = item.width.and_then(|width| positive_u32(i64::from(width)));
    let source_height = item
        .height
        .and_then(|height| positive_u32(i64::from(height)));
    match (source_width, source_height) {
        (Some(source_width), Some(source_height)) if source_width > 0 && source_height > 0 => {
            let output_width = requested_width.min(source_width).max(1);
            let output_height = ((output_width as f64 * source_height as f64 / source_width as f64)
                .round() as u32)
                .max(1);
            (output_width, output_height)
        }
        _ => (requested_width, requested_width),
    }
}

#[derive(Debug, Clone)]
struct TrickplaySettings {
    interval_ms: i64,
    interval_seconds: f64,
    allowed_widths: Vec<u32>,
    tile_width: u32,
    tile_height: u32,
    qscale: u32,
    process_threads: u32,
}

async fn trickplay_settings(db: &Database) -> Result<TrickplaySettings, ApiError> {
    let payloads = db.system_configuration_payloads().await?;
    let mut server_options = default_server_configuration_options();
    if let serde_json::Value::Object(current) = payloads.server_options {
        for (key, value) in current {
            server_options[key] = value;
        }
    }
    let options = server_options
        .get("TrickplayOptions")
        .cloned()
        .unwrap_or_else(default_trickplay_options);
    Ok(TrickplaySettings {
        interval_ms: trickplay_interval_ms_from_options(&options),
        interval_seconds: trickplay_interval_seconds_from_options(&options),
        allowed_widths: trickplay_width_resolutions_from_options(&options),
        tile_width: trickplay_tile_dimension_from_options(&options, "TileWidth"),
        tile_height: trickplay_tile_dimension_from_options(&options, "TileHeight"),
        qscale: trickplay_qscale_from_options(&options),
        process_threads: trickplay_process_threads_from_options(&options),
    })
}

fn trickplay_interval_ms_from_options(options: &serde_json::Value) -> i64 {
    options
        .get("Interval")
        .and_then(serde_json::Value::as_i64)
        .filter(|interval_ms| *interval_ms > 0)
        .map(|interval_ms| interval_ms.max(1000))
        .unwrap_or(10_000)
}

fn trickplay_interval_seconds_from_options(options: &serde_json::Value) -> f64 {
    trickplay_interval_ms_from_options(options) as f64 / 1000.0
}

fn trickplay_width_resolutions_from_options(options: &serde_json::Value) -> Vec<u32> {
    let widths = options
        .get("WidthResolutions")
        .and_then(serde_json::Value::as_array)
        .map(|values| {
            values
                .iter()
                .filter_map(serde_json::Value::as_i64)
                .filter_map(positive_u32)
                .collect::<BTreeSet<_>>()
        })
        .unwrap_or_else(|| BTreeSet::from([320]));
    if widths.is_empty() {
        vec![320]
    } else {
        widths.into_iter().collect()
    }
}

fn trickplay_qscale_from_options(options: &serde_json::Value) -> u32 {
    options
        .get("Qscale")
        .and_then(serde_json::Value::as_i64)
        .and_then(positive_u32)
        .map(|qscale| qscale.clamp(2, 31))
        .unwrap_or(4)
}

fn trickplay_tile_dimension_from_options(options: &serde_json::Value, key: &str) -> u32 {
    options
        .get(key)
        .and_then(serde_json::Value::as_i64)
        .and_then(positive_u32)
        .map(|dimension| dimension.clamp(1, 100))
        .unwrap_or(10)
}

fn trickplay_process_threads_from_options(options: &serde_json::Value) -> u32 {
    options
        .get("ProcessThreads")
        .and_then(serde_json::Value::as_i64)
        .and_then(positive_u32)
        .map(|threads| threads.clamp(1, 32))
        .unwrap_or(1)
}

fn validate_trickplay_width(width: u32, settings: &TrickplaySettings) -> Result<(), ApiError> {
    if settings.allowed_widths.contains(&width) {
        Ok(())
    } else {
        Err(ApiError::not_found("Trickplay width not found"))
    }
}

fn trickplay_tile_cache_path(
    item: &MediaItem,
    settings: &TrickplaySettings,
    width: u32,
    index: u32,
) -> PathBuf {
    trickplay_cache_root()
        .join(item.id.simple().to_string())
        .join(trickplay_cache_revision(item, settings))
        .join(width.to_string())
        .join(format!("{index}.jpg"))
}

fn trickplay_cache_revision(item: &MediaItem, settings: &TrickplaySettings) -> String {
    let path = media_item_path(item);
    let metadata = fs::metadata(path).ok();
    let modified = metadata
        .as_ref()
        .and_then(|metadata| metadata.modified().ok())
        .and_then(|modified| modified.duration_since(UNIX_EPOCH).ok())
        .map(|duration| duration.as_nanos())
        .unwrap_or_else(|| item.updated_at.unix_timestamp_nanos() as u128);
    let len = metadata
        .map(|metadata| metadata.len())
        .or_else(|| item.file_size.and_then(|size| u64::try_from(size).ok()))
        .unwrap_or(0);
    format!(
        "mtime-{modified}-len-{len}-interval-{}-tile-{}x{}-q{}-threads{}",
        settings.interval_ms,
        settings.tile_width,
        settings.tile_height,
        settings.qscale,
        settings.process_threads
    )
}

fn trickplay_cache_root() -> PathBuf {
    std::env::temp_dir().join("jellyrin").join("trickplay")
}

static TRICKPLAY_TILE_LOCKS: OnceLock<Mutex<HashMap<String, Arc<Mutex<()>>>>> = OnceLock::new();

async fn trickplay_tile_lock(tile_path: &FsPath) -> Arc<Mutex<()>> {
    let key = tile_path.to_string_lossy().to_string();
    let locks = TRICKPLAY_TILE_LOCKS.get_or_init(|| Mutex::new(HashMap::new()));
    let mut guard = locks.lock().await;
    guard
        .entry(key)
        .or_insert_with(|| Arc::new(Mutex::new(())))
        .clone()
}

async fn trickplay_video_item(
    state: &AppState,
    headers: &HeaderMap,
    query: &TrickplayQuery,
    item_id: &str,
) -> Result<MediaItem, ApiError> {
    require_request_user(&state.db, headers, query.api_key.as_deref()).await?;
    let selected_item_id = query
        .media_source_id
        .as_deref()
        .filter(|media_source_id| !media_source_id.trim().is_empty())
        .unwrap_or(item_id);
    let item = media_item_by_id(&state.db, selected_item_id).await?;
    if item.media_type != "Video" {
        return Err(ApiError::not_found("Video item not found"));
    }
    Ok(item)
}

fn parse_positive_u32(value: &str, message: &'static str) -> Result<u32, ApiError> {
    let value = value
        .parse::<u32>()
        .map_err(|_| ApiError::bad_request(message))?;
    if value == 0 {
        return Err(ApiError::bad_request(message));
    }
    Ok(value)
}

fn parse_non_negative_i64(value: &str, message: &'static str) -> Result<i64, ApiError> {
    let value = value
        .parse::<i64>()
        .map_err(|_| ApiError::bad_request(message))?;
    if value < 0 {
        return Err(ApiError::bad_request(message));
    }
    Ok(value)
}

async fn active_hls_transcode_session_for(
    state: &AppState,
    headers: &HeaderMap,
    item_id: &str,
    query: &HlsQuery,
    media_type: &str,
) -> Result<TranscodeSession, ApiError> {
    require_request_user(&state.db, headers, query.api_key.as_deref()).await?;
    let requested_item_id = parse_jellyfin_uuid(item_id)?;
    let play_session_id = query
        .play_session_id
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or_else(|| ApiError::bad_request("PlaySessionId is required"))?;
    let session = state
        .db
        .transcode_session_by_play_session_id(play_session_id)
        .await?
        .ok_or_else(|| ApiError::not_found("HLS transcode session not found"))?;
    if session.item.id != requested_item_id
        || session.item.media_type != media_type
        || !matches!(
            session.status.as_str(),
            "starting" | "running" | "completed"
        )
    {
        return Err(ApiError::not_found("HLS transcode session not found"));
    }
    Ok(session)
}

fn playlist_response(
    playlist: String,
    include_body: bool,
) -> Result<axum::response::Response, ApiError> {
    let content_length = playlist.len().to_string();
    let body = if include_body {
        Body::from(playlist)
    } else {
        Body::empty()
    };
    Ok((
        StatusCode::OK,
        [
            (
                header::CONTENT_TYPE,
                "application/vnd.apple.mpegurl".to_string(),
            ),
            (header::CONTENT_LENGTH, content_length),
        ],
        body,
    )
        .into_response())
}

async fn stream_path(
    path: PathBuf,
    content_type: String,
    headers: &HeaderMap,
    include_body: bool,
) -> Result<axum::response::Response, ApiError> {
    let mut file = tokio::fs::File::open(path).await?;
    let total_len = file.metadata().await?.len();
    let range = match parse_range_header(headers, total_len) {
        Ok(range) => range,
        Err(()) => {
            return Ok((
                StatusCode::RANGE_NOT_SATISFIABLE,
                [
                    (header::CONTENT_TYPE, content_type),
                    (header::ACCEPT_RANGES, "bytes".to_string()),
                    (header::CONTENT_RANGE, format!("bytes */{total_len}")),
                ],
                Body::empty(),
            )
                .into_response());
        }
    };

    if let Some((start, end)) = range {
        file.seek(std::io::SeekFrom::Start(start)).await?;
        let content_length = end - start + 1;
        let stream = ReaderStream::new(file.take(content_length));
        let body = if include_body {
            Body::from_stream(stream)
        } else {
            Body::empty()
        };
        return Ok((
            StatusCode::PARTIAL_CONTENT,
            [
                (header::CONTENT_TYPE, content_type),
                (header::ACCEPT_RANGES, "bytes".to_string()),
                (header::CONTENT_LENGTH, content_length.to_string()),
                (
                    header::CONTENT_RANGE,
                    format!("bytes {start}-{end}/{total_len}"),
                ),
            ],
            body,
        )
            .into_response());
    }

    let stream = ReaderStream::new(file);
    let body = if include_body {
        Body::from_stream(stream)
    } else {
        Body::empty()
    };
    Ok((
        StatusCode::OK,
        [
            (header::CONTENT_TYPE, content_type),
            (header::ACCEPT_RANGES, "bytes".to_string()),
            (header::CONTENT_LENGTH, total_len.to_string()),
        ],
        body,
    )
        .into_response())
}

async fn direct_stream_media(
    state: &AppState,
    headers: &HeaderMap,
    api_key: Option<&str>,
    item_id: &str,
    media_source_id: Option<&str>,
    media_type: &str,
    include_body: bool,
) -> Result<axum::response::Response, ApiError> {
    require_request_user(&state.db, headers, api_key).await?;
    let requested_item = media_item_by_id(&state.db, item_id).await?;
    let item = resolve_media_source_item(&state.db, requested_item, media_source_id)
        .await?
        .ok_or_else(|| ApiError::not_found(format!("{media_type} stream not found")))?;
    if item.media_type != media_type {
        return Err(ApiError::not_found(format!(
            "{media_type} stream not found"
        )));
    }

    stream_media_item(item, headers, include_body).await
}

async fn library_item_file_response(
    state: &AppState,
    headers: &HeaderMap,
    api_key: Option<&str>,
    item_id: &str,
    media_source_id: Option<&str>,
    download: bool,
) -> Result<axum::response::Response, ApiError> {
    require_request_user(&state.db, headers, api_key).await?;
    let requested_item = media_item_by_id(&state.db, item_id).await?;
    let item = resolve_media_source_item(&state.db, requested_item, media_source_id)
        .await?
        .ok_or_else(|| ApiError::not_found("File not found"))?;
    let file_name = download.then(|| media_item_download_file_name(&item));
    let mut response = stream_media_item(item, headers, true).await?;
    if let Some(file_name) = file_name {
        response.headers_mut().insert(
            header::CONTENT_DISPOSITION,
            format!("attachment; filename=\"{file_name}\"")
                .parse()
                .unwrap(),
        );
    }
    Ok(response)
}

fn media_item_download_file_name(item: &MediaItem) -> String {
    media_item_path(item)
        .file_name()
        .and_then(|name| name.to_str())
        .map(sanitize_download_file_name)
        .filter(|name| !name.is_empty())
        .unwrap_or_else(|| {
            format!(
                "{}.{}",
                item.id.simple(),
                media_item_container(item).unwrap_or_else(|| "bin".to_string())
            )
        })
}

fn sanitize_download_file_name(name: &str) -> String {
    name.chars()
        .filter(|character| !matches!(character, '"' | '\\' | '\r' | '\n'))
        .collect::<String>()
        .trim()
        .to_string()
}

async fn stream_media_item(
    item: MediaItem,
    headers: &HeaderMap,
    include_body: bool,
) -> Result<axum::response::Response, ApiError> {
    let mut file = tokio::fs::File::open(media_item_path(&item)).await?;
    let total_len = file.metadata().await?.len();
    let content_type = media_item_content_type(&item);

    let range = match parse_range_header(headers, total_len) {
        Ok(range) => range,
        Err(()) => {
            return Ok((
                StatusCode::RANGE_NOT_SATISFIABLE,
                [
                    (header::CONTENT_TYPE, content_type),
                    (header::ACCEPT_RANGES, "bytes".to_string()),
                    (header::CONTENT_RANGE, format!("bytes */{total_len}")),
                ],
                Body::empty(),
            )
                .into_response());
        }
    };

    if let Some((start, end)) = range {
        file.seek(std::io::SeekFrom::Start(start)).await?;
        let content_length = end - start + 1;
        let stream = ReaderStream::new(file.take(content_length));
        let body = if include_body {
            Body::from_stream(stream)
        } else {
            Body::empty()
        };
        return Ok((
            StatusCode::PARTIAL_CONTENT,
            [
                (header::CONTENT_TYPE, content_type),
                (header::ACCEPT_RANGES, "bytes".to_string()),
                (header::CONTENT_LENGTH, content_length.to_string()),
                (
                    header::CONTENT_RANGE,
                    format!("bytes {start}-{end}/{total_len}"),
                ),
            ],
            body,
        )
            .into_response());
    }

    let stream = ReaderStream::new(file);
    let body = if include_body {
        Body::from_stream(stream)
    } else {
        Body::empty()
    };
    Ok((
        StatusCode::OK,
        [
            (header::CONTENT_TYPE, content_type),
            (header::ACCEPT_RANGES, "bytes".to_string()),
            (header::CONTENT_LENGTH, total_len.to_string()),
        ],
        body,
    )
        .into_response())
}

