async fn suggestions_result(
    db: &Database,
    mut query: ItemsQuery,
    requested_user_id: Uuid,
) -> Result<Json<serde_json::Value>, ApiError> {
    if query.is_played.is_none() && query_filters_played_value(&query.filters).is_none() {
        query.is_played = Some(false);
    }
    if query.sort_by.is_none() {
        query.sort_by = Some("DateCreated,SortName".to_string());
    }
    if query.sort_order.is_none() {
        query.sort_order = Some("Descending".to_string());
    }
    if query.limit.is_none() {
        query.limit = Some(20);
    }

    let filtered_items =
        filtered_media_items(db.media_items().await?, &query, Some(requested_user_id), db).await?;
    let total_record_count = filtered_items.len();
    let server_id = db.server_state().await?.server_id.to_string();
    let items = items_to_json(
        db,
        paged_media_items(filtered_items, &query),
        &server_id,
        Some(requested_user_id),
    )
    .await?;
    Ok(Json(query_result_with_total(
        items,
        total_record_count,
        query.start_index.unwrap_or(0),
    )))
}

async fn series_episodes(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(auth_query): Query<AuthQuery>,
    Path(series_id): Path<String>,
    RawQuery(raw_query): RawQuery,
) -> Result<Json<serde_json::Value>, ApiError> {
    let mut query = parse_items_query(raw_query.as_deref());
    let auth_user =
        require_request_user(&state.db, &headers, auth_query.api_key.as_deref()).await?;
    let requested_user_id = query
        .user_id
        .as_deref()
        .map(resolve_user_id)
        .transpose()?
        .unwrap_or(auth_user.id);
    ensure_user_access(&auth_user, requested_user_id)?;
    if query.include_item_types.is_empty() {
        query.include_item_types.push("Episode".to_string());
    }

    let mut episodes = filtered_media_items(
        state.db.media_items().await?,
        &query,
        Some(requested_user_id),
        &state.db,
    )
    .await?
    .into_iter()
    .filter(|item| tv_episode_matches_series(item, &series_id))
    .filter(|item| {
        query
            .season_id
            .as_deref()
            .is_none_or(|season_id| tv_episode_matches_season(item, season_id))
    })
    .collect::<Vec<_>>();
    if episodes.is_empty()
        && series_name_for_id(state.db.media_items().await?, &series_id).is_none()
    {
        return Err(ApiError::not_found("Series not found"));
    }
    episodes.sort_by(compare_tv_episodes);

    let total_record_count = episodes.len();
    let server_id = state.db.server_state().await?.server_id.to_string();
    let items = items_to_json(
        &state.db,
        paged_media_items(episodes, &query),
        &server_id,
        Some(requested_user_id),
    )
    .await?;
    Ok(Json(query_result_with_total(
        items,
        total_record_count,
        query.start_index.unwrap_or(0),
    )))
}

async fn series_seasons(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(auth_query): Query<AuthQuery>,
    Path(series_id): Path<String>,
    RawQuery(raw_query): RawQuery,
) -> Result<Json<serde_json::Value>, ApiError> {
    let query = parse_items_query(raw_query.as_deref());
    let auth_user =
        require_request_user(&state.db, &headers, auth_query.api_key.as_deref()).await?;
    let requested_user_id = query
        .user_id
        .as_deref()
        .map(resolve_user_id)
        .transpose()?
        .unwrap_or(auth_user.id);
    ensure_user_access(&auth_user, requested_user_id)?;

    let episodes = state
        .db
        .media_items()
        .await?
        .into_iter()
        .filter(|item| tv_episode_matches_series(item, &series_id))
        .collect::<Vec<_>>();
    let series_name = episodes
        .iter()
        .find_map(|item| tv_episode_info(item).map(|info| info.series_name))
        .ok_or_else(|| ApiError::not_found("Series not found"))?;
    let mut seasons = BTreeMap::<Option<i32>, usize>::new();
    for episode in &episodes {
        let season_number = tv_episode_info(episode).and_then(|info| info.season_number);
        *seasons.entry(season_number).or_insert(0) += 1;
    }
    let server_id = state.db.server_state().await?.server_id.to_string();
    let mut season_items = seasons
        .into_iter()
        .map(|(season_number, episode_count)| {
            tv_season_json(&server_id, &series_name, season_number, episode_count)
        })
        .collect::<Vec<_>>();
    season_items.sort_by(|left, right| {
        let left_index = left
            .get("IndexNumber")
            .and_then(serde_json::Value::as_i64)
            .unwrap_or(i64::MAX);
        let right_index = right
            .get("IndexNumber")
            .and_then(serde_json::Value::as_i64)
            .unwrap_or(i64::MAX);
        left_index.cmp(&right_index)
    });
    let total_record_count = season_items.len();
    let start_index = query.start_index.unwrap_or(0);
    let limit = query.limit.unwrap_or(usize::MAX);
    let items = season_items
        .into_iter()
        .skip(start_index)
        .take(limit)
        .collect::<Vec<_>>();
    Ok(Json(query_result_with_total(
        items,
        total_record_count,
        start_index,
    )))
}

async fn search_hints(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(auth_query): Query<AuthQuery>,
    RawQuery(raw_query): RawQuery,
) -> Result<Json<serde_json::Value>, ApiError> {
    let mut query = parse_items_query(raw_query.as_deref());
    let search_term = query
        .search_term
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(ToOwned::to_owned);
    query.search_term = None;
    let auth_user =
        require_request_user(&state.db, &headers, auth_query.api_key.as_deref()).await?;
    let requested_user_id = query.user_id.as_deref().map(resolve_user_id).transpose()?;
    if let Some(requested_user_id) = requested_user_id {
        ensure_user_access(&auth_user, requested_user_id)?;
    }
    let items = filtered_media_items(
        state.db.media_items().await?,
        &query,
        requested_user_id,
        &state.db,
    )
    .await?;
    let metadata = search_hint_metadata_values(&state.db, &items).await?;
    let items = items
        .into_iter()
        .filter(|item| {
            search_term
                .as_deref()
                .is_none_or(|term| search_hint_matches(item, metadata.get(&item.id), term))
        })
        .collect::<Vec<_>>();
    let total_record_count = items.len();
    let search_hints = items
        .into_iter()
        .take(query.limit.unwrap_or(20).min(100))
        .map(|item| {
            let metadata = metadata.get(&item.id).cloned().unwrap_or_default();
            let matched_term = search_term
                .as_deref()
                .and_then(|term| search_hint_matched_term(&item, &metadata, term))
                .unwrap_or_else(|| item.name.clone());
            serde_json::json!({
                "ItemId": item.id.simple().to_string(),
                "Id": item.id.simple().to_string(),
                "Name": item.name,
                "MatchedTerm": matched_term,
                "IndexNumber": null,
                "ProductionYear": metadata.production_year,
                "ParentIndexNumber": null,
                "PrimaryImageTag": "placeholder",
                "ThumbImageTag": null,
                "ThumbImageItemId": null,
                "BackdropImageTag": null,
                "BackdropImageItemId": null,
                "Type": media_item_type(&item),
                "IsFolder": false,
                "RunTimeTicks": item.runtime_ticks,
                "MediaType": item.media_type,
                "StartDate": null,
                "EndDate": null,
                "Series": metadata.series,
                "Status": null,
                "Album": metadata.album,
                "AlbumId": null,
                "AlbumArtist": metadata.album_artist,
                "Artists": metadata.artists
            })
        })
        .collect::<Vec<_>>();
    Ok(Json(serde_json::json!({
        "SearchHints": search_hints,
        "TotalRecordCount": total_record_count
    })))
}

#[derive(Clone, Default)]
struct SearchHintMetadata {
    album: Option<String>,
    album_artist: Option<String>,
    artists: Vec<String>,
    production_year: Option<i32>,
    series: Option<String>,
}

async fn search_hint_metadata_values(
    db: &Database,
    items: &[MediaItem],
) -> Result<HashMap<Uuid, SearchHintMetadata>, ApiError> {
    if items.is_empty() {
        return Ok(HashMap::new());
    }
    let item_ids = items.iter().map(|item| item.id).collect::<HashSet<_>>();
    let mut values = HashMap::<Uuid, SearchHintMetadata>::new();
    for metadata in db.media_item_metadata().await? {
        if !item_ids.contains(&metadata.item_id) {
            continue;
        }
        values.insert(
            metadata.item_id,
            SearchHintMetadata {
                album: first_metadata_string(&metadata, &["Album", "AlbumName"]),
                album_artist: first_metadata_string(&metadata, &["AlbumArtist", "AlbumArtists"]),
                artists: metadata_strings(&metadata, &["Artists"]),
                production_year: first_metadata_string(&metadata, &["ProductionYear", "Year"])
                    .and_then(|value| value.parse::<i32>().ok()),
                series: first_metadata_string(&metadata, &["SeriesName", "Series"]),
            },
        );
    }
    Ok(values)
}

fn metadata_strings(metadata: &MediaItemMetadata, keys: &[&str]) -> Vec<String> {
    let mut values = BTreeMap::<String, String>::new();
    for key in keys {
        collect_item_count_metadata_value(metadata, key, &mut values);
    }
    values.into_values().collect()
}

fn first_metadata_string(metadata: &MediaItemMetadata, keys: &[&str]) -> Option<String> {
    metadata_strings(metadata, keys).into_iter().next()
}

fn search_hint_matches(
    item: &MediaItem,
    metadata: Option<&SearchHintMetadata>,
    search_term: &str,
) -> bool {
    metadata
        .and_then(|metadata| search_hint_matched_term(item, metadata, search_term))
        .or_else(|| {
            let metadata = SearchHintMetadata::default();
            search_hint_matched_term(item, &metadata, search_term)
        })
        .is_some()
}

fn search_hint_matched_term(
    item: &MediaItem,
    metadata: &SearchHintMetadata,
    search_term: &str,
) -> Option<String> {
    let needle = search_term.to_ascii_lowercase();
    [
        Some(item.name.as_str()),
        metadata.album.as_deref(),
        metadata.album_artist.as_deref(),
        metadata.series.as_deref(),
    ]
    .into_iter()
    .flatten()
    .find(|value| value.to_ascii_lowercase().contains(&needle))
    .map(ToOwned::to_owned)
    .or_else(|| {
        metadata
            .artists
            .iter()
            .find(|value| value.to_ascii_lowercase().contains(&needle))
            .cloned()
    })
}

