async fn authenticated_similar_show_items(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(auth_query): Query<AuthQuery>,
    Path(item_id): Path<String>,
    RawQuery(raw_query): RawQuery,
) -> Result<Json<serde_json::Value>, ApiError> {
    let query = parse_items_query(raw_query.as_deref());
    let auth_user =
        require_request_user(&state.db, &headers, auth_query.api_key.as_deref()).await?;
    let requested_user_id = query
        .user_id
        .as_deref()
        .map(resolve_user_id)
        .transpose()?
        .unwrap_or(auth_user.id);
    ensure_user_access(&auth_user, requested_user_id)?;

    match similar_items_for_media_source(&state, &query, requested_user_id, &item_id).await {
        Ok(response) => return Ok(response),
        Err(error) if error.status == StatusCode::NOT_FOUND => {}
        Err(error) => return Err(error),
    }

    let mut items_query = query.clone();
    if items_query.include_item_types.is_empty() {
        items_query.include_item_types.push("Episode".to_string());
    }
    items_query.ids = None;
    items_query.search_term = None;
    items_query.name_starts_with = None;
    items_query.name_starts_with_or_greater = None;
    items_query.name_less_than = None;
    items_query.start_index = None;
    items_query.limit = None;
    items_query.sort_by = None;
    items_query.sort_order = None;

    let mut episodes = filtered_media_items(
        state.db.media_items().await?,
        &items_query,
        Some(requested_user_id),
        &state.db,
    )
    .await?
    .into_iter()
    .filter(|item| tv_episode_matches_series(item, &item_id))
    .collect::<Vec<_>>();
    if episodes.is_empty() {
        return Err(ApiError::not_found("Similar source not found"));
    }
    episodes.sort_by(compare_tv_episodes);
    paged_similar_items_response(&state, &query, requested_user_id, episodes).await
}

async fn authenticated_similar_trailer_items(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(auth_query): Query<AuthQuery>,
    Path(item_id): Path<String>,
    RawQuery(raw_query): RawQuery,
) -> Result<Json<serde_json::Value>, ApiError> {
    let query = parse_items_query(raw_query.as_deref());
    let auth_user =
        require_request_user(&state.db, &headers, auth_query.api_key.as_deref()).await?;
    let requested_user_id = query
        .user_id
        .as_deref()
        .map(resolve_user_id)
        .transpose()?
        .unwrap_or(auth_user.id);
    ensure_user_access(&auth_user, requested_user_id)?;

    match similar_items_for_media_source(&state, &query, requested_user_id, &item_id).await {
        Ok(response) => return Ok(response),
        Err(error) if error.status == StatusCode::NOT_FOUND => {}
        Err(error) => return Err(error),
    }

    let mut scope_query = query.clone();
    scope_query.ids = None;
    scope_query.search_term = None;
    scope_query.name_starts_with = None;
    scope_query.name_starts_with_or_greater = None;
    scope_query.name_less_than = None;
    scope_query.is_folder = None;
    scope_query.filters = metadata_scope_filters(&query.filters);
    scope_query.start_index = None;
    scope_query.limit = None;
    scope_query.sort_by = None;
    scope_query.sort_order = None;
    let scoped_items = filtered_media_items(
        state.db.media_items().await?,
        &scope_query,
        Some(requested_user_id),
        &state.db,
    )
    .await?;
    let item_by_id = scoped_items
        .iter()
        .map(|item| (item.id, item))
        .collect::<HashMap<_, _>>();
    let server_id = state.db.server_state().await?.server_id.to_string();
    let mut trailers = Vec::new();
    for metadata in state.db.media_item_metadata().await? {
        let Some(item) = item_by_id.get(&metadata.item_id) else {
            continue;
        };
        trailers.extend(metadata_remote_trailers(
            &metadata.payload,
            item,
            &server_id,
        ));
    }
    let parent_id = trailers
        .iter()
        .find(|trailer| {
            trailer["Id"]
                .as_str()
                .is_some_and(|id| id.eq_ignore_ascii_case(&item_id))
        })
        .and_then(|trailer| trailer["ParentId"].as_str())
        .map(str::to_string)
        .ok_or_else(|| ApiError::not_found("Similar source not found"))?;
    trailers.retain(|trailer| {
        trailer["ParentId"]
            .as_str()
            .is_some_and(|candidate_parent_id| candidate_parent_id == parent_id)
            && trailer["Id"]
                .as_str()
                .is_some_and(|candidate_id| !candidate_id.eq_ignore_ascii_case(&item_id))
            && remote_trailer_matches_query(trailer, &query)
    });
    trailers.sort_by(|left, right| {
        left["SortName"]
            .as_str()
            .unwrap_or_default()
            .to_ascii_lowercase()
            .cmp(
                &right["SortName"]
                    .as_str()
                    .unwrap_or_default()
                    .to_ascii_lowercase(),
            )
    });
    if metadata_sort_descending("Trailer", &query) {
        trailers.reverse();
    }
    let total_record_count = trailers.len();
    let start_index = query.start_index.unwrap_or(0);
    let limit = query.limit.unwrap_or(20).min(100);
    Ok(Json(query_result_with_total(
        trailers.into_iter().skip(start_index).take(limit).collect(),
        total_record_count,
        start_index,
    )))
}

async fn similar_items_from_metadata_entity(
    state: AppState,
    headers: HeaderMap,
    auth_query: AuthQuery,
    raw_query: Option<String>,
    item_id: String,
    entity_type: &'static str,
    metadata_keys: &'static [&'static str],
) -> Result<Json<serde_json::Value>, ApiError> {
    let query = parse_items_query(raw_query.as_deref());
    let auth_user =
        require_request_user(&state.db, &headers, auth_query.api_key.as_deref()).await?;
    let requested_user_id = query
        .user_id
        .as_deref()
        .map(resolve_user_id)
        .transpose()?
        .unwrap_or(auth_user.id);
    ensure_user_access(&auth_user, requested_user_id)?;

    match similar_items_for_media_source(&state, &query, requested_user_id, &item_id).await {
        Ok(response) => return Ok(response),
        Err(error) if error.status == StatusCode::NOT_FOUND => {}
        Err(error) => return Err(error),
    }

    let mut items_query = query.clone();
    if items_query.include_item_types.is_empty() {
        items_query.include_item_types.push("Audio".to_string());
    }
    items_query.ids = None;
    items_query.search_term = None;
    items_query.name_starts_with = None;
    items_query.name_starts_with_or_greater = None;
    items_query.name_less_than = None;
    items_query.start_index = None;
    items_query.limit = None;
    items_query.sort_by = Some("SortName".to_string());
    items_query.sort_order = None;

    let candidates = filtered_media_items(
        state.db.media_items().await?,
        &items_query,
        Some(requested_user_id),
        &state.db,
    )
    .await?;
    let metadata_by_item = state
        .db
        .media_item_metadata()
        .await?
        .into_iter()
        .map(|metadata| (metadata.item_id, metadata))
        .collect::<HashMap<_, _>>();
    let entity_name = metadata_values_for_keys(&state.db, metadata_keys, &candidates)
        .await?
        .into_iter()
        .find(|name| stable_entity_id(entity_type, name).eq_ignore_ascii_case(&item_id))
        .ok_or_else(|| ApiError::not_found("Similar source not found"))?;
    let items =
        metadata_entity_audio_items(candidates, &metadata_by_item, metadata_keys, &entity_name);
    paged_similar_items_response(&state, &query, requested_user_id, items).await
}

async fn similar_items_for_media_source(
    state: &AppState,
    query: &ItemsQuery,
    requested_user_id: Uuid,
    item_id: &str,
) -> Result<Json<serde_json::Value>, ApiError> {
    let source = media_item_by_id(&state.db, item_id).await?;
    let server_id = state.db.server_state().await?.server_id.to_string();
    let mut items_query = query.clone();
    if items_query.include_item_types.is_empty() {
        items_query
            .include_item_types
            .push(media_item_type(&source).to_string());
    }
    let mut candidates = filtered_media_items(
        state.db.media_items().await?,
        &items_query,
        Some(requested_user_id),
        &state.db,
    )
    .await?;
    candidates.retain(|item| item.id != source.id);

    let metadata = state.db.media_item_metadata().await?;
    let metadata_by_item = metadata
        .iter()
        .map(|metadata| (metadata.item_id, metadata))
        .collect::<HashMap<_, _>>();
    let source_terms = similar_item_terms(metadata_by_item.get(&source.id).copied());
    let source_type = media_item_type(&source);
    let mut scored = candidates
        .into_iter()
        .filter_map(|item| {
            if media_item_type(&item) != source_type {
                return None;
            }
            let terms = similar_item_terms(metadata_by_item.get(&item.id).copied());
            let shared_terms = terms.intersection(&source_terms).count();
            if shared_terms == 0 {
                return None;
            }
            Some((shared_terms, item))
        })
        .collect::<Vec<_>>();

    scored.sort_by(|(left_score, left_item), (right_score, right_item)| {
        right_score
            .cmp(left_score)
            .then_with(|| compare_media_items(left_item, right_item, &[SortField::SortName]))
    });

    let start_index = items_query.start_index.unwrap_or(0);
    let total_record_count = scored.len();
    let limit = items_query.limit.unwrap_or(20).min(100);
    let items = scored
        .into_iter()
        .skip(start_index)
        .take(limit)
        .map(|(_, item)| item)
        .collect::<Vec<_>>();
    Ok(Json(query_result_with_total(
        items_to_json(&state.db, items, &server_id, Some(requested_user_id)).await?,
        total_record_count,
        start_index,
    )))
}

async fn paged_similar_items_response(
    state: &AppState,
    query: &ItemsQuery,
    requested_user_id: Uuid,
    items: Vec<MediaItem>,
) -> Result<Json<serde_json::Value>, ApiError> {
    let server_id = state.db.server_state().await?.server_id.to_string();
    let total_record_count = items.len();
    let start_index = query.start_index.unwrap_or(0);
    let limit = query.limit.unwrap_or(20).min(100);
    Ok(Json(query_result_with_total(
        items_to_json(
            &state.db,
            items.into_iter().skip(start_index).take(limit).collect(),
            &server_id,
            Some(requested_user_id),
        )
        .await?,
        total_record_count,
        start_index,
    )))
}

fn similar_item_terms(metadata: Option<&MediaItemMetadata>) -> BTreeSet<String> {
    let mut terms = BTreeMap::<String, String>::new();
    if let Some(metadata) = metadata {
        for key in [
            "Genres",
            "MusicGenres",
            "Tags",
            "Studios",
            "Artists",
            "AlbumArtists",
            "OfficialRating",
            "ProductionYear",
            "Series",
            "SeriesName",
        ] {
            collect_item_count_metadata_value(metadata, key, &mut terms);
        }
    }
    terms.into_keys().collect()
}

async fn item_filters(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(auth_query): Query<AuthQuery>,
    RawQuery(raw_query): RawQuery,
) -> Result<Json<serde_json::Value>, ApiError> {
    let query = parse_items_query(raw_query.as_deref());
    let items =
        filtered_items_for_query(&state, &headers, auth_query.api_key.as_deref(), &query).await?;
    let media_types = items
        .iter()
        .map(|item| item.media_type.clone())
        .collect::<BTreeSet<_>>()
        .into_iter()
        .collect::<Vec<_>>();
    let containers = items
        .iter()
        .filter_map(media_item_container)
        .collect::<BTreeSet<_>>()
        .into_iter()
        .collect::<Vec<_>>();
    let metadata_values = item_filter_metadata_values(&state.db, &items).await?;

    Ok(Json(serde_json::json!({
        "Genres": metadata_values.genres.into_values().collect::<Vec<_>>(),
        "Tags": metadata_values.tags.into_values().collect::<Vec<_>>(),
        "OfficialRatings": metadata_values.official_ratings.into_values().collect::<Vec<_>>(),
        "Years": metadata_values.years.into_values().collect::<Vec<_>>(),
        "Containers": containers,
        "MediaTypes": media_types,
        "VideoTypes": [],
        "SeriesStatuses": [],
        "Staff": [],
        "Artists": metadata_values.artists.into_values().collect::<Vec<_>>(),
        "Albums": metadata_values.albums.into_values().collect::<Vec<_>>(),
        "Studios": metadata_values.studios.into_values().collect::<Vec<_>>(),
        "Trailers": [],
        "Features": []
    })))
}

async fn query_filters(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(auth_query): Query<AuthQuery>,
    RawQuery(raw_query): RawQuery,
) -> Result<Json<serde_json::Value>, ApiError> {
    let query = parse_items_query(raw_query.as_deref());
    let items =
        filtered_items_for_query(&state, &headers, auth_query.api_key.as_deref(), &query).await?;
    let metadata_values = item_filter_metadata_values(&state.db, &items).await?;
    Ok(Json(serde_json::json!({
        "Genres": metadata_values.genres.into_values().collect::<Vec<_>>(),
        "Tags": metadata_values.tags.into_values().collect::<Vec<_>>(),
        "AudioLanguages": [],
        "SubtitleLanguages": []
    })))
}

#[derive(Default)]
struct ItemFilterMetadataValues {
    albums: BTreeMap<String, String>,
    artists: BTreeMap<String, String>,
    genres: BTreeMap<String, String>,
    official_ratings: BTreeMap<String, String>,
    studios: BTreeMap<String, String>,
    tags: BTreeMap<String, String>,
    years: BTreeMap<String, String>,
}

async fn item_filter_metadata_values(
    db: &Database,
    items: &[MediaItem],
) -> Result<ItemFilterMetadataValues, ApiError> {
    if items.is_empty() {
        return Ok(ItemFilterMetadataValues::default());
    }
    let item_ids = items.iter().map(|item| item.id).collect::<HashSet<_>>();
    let mut values = ItemFilterMetadataValues::default();
    for metadata in db.media_item_metadata().await? {
        if item_ids.contains(&metadata.item_id) {
            collect_item_count_metadata_value(&metadata, "Album", &mut values.albums);
            collect_item_count_metadata_value(&metadata, "AlbumName", &mut values.albums);
            collect_item_count_metadata_value(&metadata, "Artists", &mut values.artists);
            collect_item_count_metadata_value(&metadata, "AlbumArtists", &mut values.artists);
            collect_item_count_metadata_value(&metadata, "Genres", &mut values.genres);
            collect_item_count_metadata_value(
                &metadata,
                "OfficialRating",
                &mut values.official_ratings,
            );
            collect_item_count_metadata_value(
                &metadata,
                "OfficialRatings",
                &mut values.official_ratings,
            );
            collect_item_count_metadata_value(&metadata, "Studios", &mut values.studios);
            collect_item_count_metadata_value(&metadata, "Tags", &mut values.tags);
            collect_item_count_metadata_value(&metadata, "ProductionYear", &mut values.years);
            collect_item_count_metadata_value(&metadata, "Years", &mut values.years);
        }
    }
    Ok(values)
}

async fn filtered_items_for_query(
    state: &AppState,
    headers: &HeaderMap,
    api_key: Option<&str>,
    query: &ItemsQuery,
) -> Result<Vec<MediaItem>, ApiError> {
    let auth_user = require_request_user(&state.db, headers, api_key).await?;
    let requested_user_id = query.user_id.as_deref().map(resolve_user_id).transpose()?;
    if let Some(requested_user_id) = requested_user_id {
        ensure_user_access(&auth_user, requested_user_id)?;
    }
    filtered_media_items(
        state.db.media_items().await?,
        query,
        requested_user_id,
        &state.db,
    )
    .await
}

fn query_result(items: Vec<serde_json::Value>) -> serde_json::Value {
    let total_record_count = items.len();
    query_result_with_total(items, total_record_count, 0)
}

fn query_result_with_total(
    items: Vec<serde_json::Value>,
    total_record_count: usize,
    start_index: usize,
) -> serde_json::Value {
    serde_json::json!({
        "TotalRecordCount": total_record_count,
        "StartIndex": start_index,
        "Items": items,
    })
}

async fn filtered_media_items(
    items: Vec<MediaItem>,
    query: &ItemsQuery,
    user_id: Option<Uuid>,
    db: &Database,
) -> Result<Vec<MediaItem>, ApiError> {
    let parent_id = query
        .parent_id
        .as_deref()
        .map(parse_jellyfin_uuid)
        .transpose()?;
    let ids = query.ids.as_deref().map(parse_uuid_list).transpose()?;
    let include_types = csv_values_lowercase(&query.include_item_types);
    let exclude_types = csv_values_lowercase(&query.exclude_item_types);
    let media_types = csv_values_lowercase(&query.media_types);
    let filters = csv_values_lowercase(&query.filters);
    let search_term = query
        .search_term
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_ascii_lowercase);
    let name_starts_with = normalized_prefix(query.name_starts_with.as_deref());
    let name_starts_with_or_greater =
        normalized_prefix(query.name_starts_with_or_greater.as_deref());
    let name_less_than = normalized_prefix(query.name_less_than.as_deref());
    let is_folder_filter = query
        .is_folder
        .or_else(|| filters.as_deref().and_then(folder_filter_value));
    let is_played_filter = query
        .is_played
        .or_else(|| filters.as_deref().and_then(played_filter_value));

    let mut items = items
        .into_iter()
        .filter(|item| ids.as_ref().is_none_or(|ids| ids.contains(&item.id)))
        .filter(|item| parent_id.is_none_or(|parent_id| item.virtual_folder_id == parent_id))
        .filter(|item| {
            include_types.as_ref().is_none_or(|types| {
                let item_type = media_item_type(item).to_ascii_lowercase();
                types.iter().any(|allowed| allowed == &item_type)
            })
        })
        .filter(|item| {
            exclude_types.as_ref().is_none_or(|types| {
                let item_type = media_item_type(item).to_ascii_lowercase();
                !types.iter().any(|excluded| excluded == &item_type)
            })
        })
        .filter(|item| {
            media_types.as_ref().is_none_or(|types| {
                let media_type = item.media_type.to_ascii_lowercase();
                types.iter().any(|allowed| allowed == &media_type)
            })
        })
        .filter(|_| is_folder_filter.is_none_or(|is_folder| !is_folder))
        .filter(|item| {
            search_term
                .as_ref()
                .is_none_or(|term| item.name.to_ascii_lowercase().contains(term))
        })
        .filter(|item| {
            name_starts_with
                .as_ref()
                .is_none_or(|prefix| item.name.to_ascii_lowercase().starts_with(prefix))
        })
        .filter(|item| {
            name_starts_with_or_greater
                .as_ref()
                .is_none_or(|prefix| item.name.to_ascii_lowercase().as_str() >= prefix.as_str())
        })
        .filter(|item| {
            name_less_than
                .as_ref()
                .is_none_or(|prefix| item.name.to_ascii_lowercase().as_str() < prefix.as_str())
        })
        .collect::<Vec<_>>();

    if let Some(is_played) = is_played_filter {
        let Some(user_id) = user_id else {
            items.clear();
            return Ok(items);
        };
        let mut filtered = Vec::new();
        for item in items {
            let played = db
                .playback_state_for_item(user_id, item.id)
                .await?
                .is_some_and(|state| state.played);
            if played == is_played {
                filtered.push(item);
            }
        }
        items = filtered;
    }

    let sort_fields = sort_fields(query.sort_by.as_deref());
    if query
        .sort_order
        .as_deref()
        .is_some_and(|order| order.eq_ignore_ascii_case("Descending"))
    {
        items.sort_by(|left, right| compare_media_items(right, left, &sort_fields));
    } else {
        items.sort_by(|left, right| compare_media_items(left, right, &sort_fields));
    }

    Ok(items)
}

fn paged_media_items(items: Vec<MediaItem>, query: &ItemsQuery) -> Vec<MediaItem> {
    let start_index = query.start_index.unwrap_or(0);
    let limit = query.limit.unwrap_or(usize::MAX);
    items.into_iter().skip(start_index).take(limit).collect()
}

async fn items_to_json(
    db: &Database,
    items: Vec<MediaItem>,
    server_id: &str,
    user_id: Option<Uuid>,
) -> Result<Vec<serde_json::Value>, ApiError> {
    let mut values = Vec::with_capacity(items.len());
    let metadata_by_item =
        media_metadata_by_item_id(db, items.iter().map(|item| item.id).collect()).await?;
    for item in items {
        let playback = if let Some(user_id) = user_id {
            db.playback_state_for_item(user_id, item.id).await?
        } else {
            None
        };
        values.push(media_item_to_json_with_playback_and_metadata(
            &item,
            server_id,
            playback.as_ref(),
            metadata_by_item.get(&item.id),
        ));
    }
    Ok(values)
}

async fn media_metadata_by_item_id(
    db: &Database,
    item_ids: HashSet<Uuid>,
) -> Result<HashMap<Uuid, serde_json::Value>, ApiError> {
    if item_ids.is_empty() {
        return Ok(HashMap::new());
    }
    Ok(db
        .media_item_metadata()
        .await?
        .into_iter()
        .filter(|metadata| item_ids.contains(&metadata.item_id))
        .map(|metadata| (metadata.item_id, metadata.payload))
        .collect())
}

fn csv_values_lowercase(values: &[String]) -> Option<Vec<String>> {
    let values = values
        .iter()
        .flat_map(|value| value.split(','))
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_ascii_lowercase)
        .collect::<Vec<_>>();
    if values.is_empty() {
        None
    } else {
        Some(values)
    }
}

#[derive(Debug, Deserialize)]
#[serde(untagged)]
enum QueryStringValues {
    One(String),
    Many(Vec<String>),
}

fn deserialize_csv_values<'de, D>(deserializer: D) -> Result<Vec<String>, D::Error>
where
    D: Deserializer<'de>,
{
    let values = Option::<QueryStringValues>::deserialize(deserializer)?;
    Ok(match values {
        Some(QueryStringValues::One(value)) => vec![value],
        Some(QueryStringValues::Many(values)) => values,
        None => Vec::new(),
    })
}

fn normalized_prefix(value: Option<&str>) -> Option<String> {
    value
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_ascii_lowercase)
}

fn folder_filter_value(filters: &[String]) -> Option<bool> {
    if filters.iter().any(|filter| filter == "isfolder") {
        Some(true)
    } else if filters.iter().any(|filter| filter == "isnotfolder") {
        Some(false)
    } else {
        None
    }
}

fn played_filter_value(filters: &[String]) -> Option<bool> {
    if filters.iter().any(|filter| filter == "isplayed") {
        Some(true)
    } else if filters.iter().any(|filter| filter == "isunplayed") {
        Some(false)
    } else {
        None
    }
}

fn query_filters_played_value(filters: &[String]) -> Option<bool> {
    let filters = filters
        .iter()
        .flat_map(|filter| filter.split(','))
        .map(str::trim)
        .filter(|filter| !filter.is_empty())
        .map(str::to_ascii_lowercase)
        .collect::<Vec<_>>();
    played_filter_value(&filters)
}

#[derive(Debug, Clone, Copy)]
enum SortField {
    SortName,
    DateCreated,
    DateLastMediaAdded,
}

fn sort_fields(sort_by: Option<&str>) -> Vec<SortField> {
    let fields = sort_by
        .unwrap_or("SortName")
        .split(',')
        .filter_map(|field| match field.trim().to_ascii_lowercase().as_str() {
            "sortname" | "name" => Some(SortField::SortName),
            "datecreated" => Some(SortField::DateCreated),
            "datelastmediaadded" => Some(SortField::DateLastMediaAdded),
            _ => None,
        })
        .collect::<Vec<_>>();

    if fields.is_empty() {
        vec![SortField::SortName]
    } else {
        fields
    }
}

fn compare_media_items(left: &MediaItem, right: &MediaItem, fields: &[SortField]) -> Ordering {
    fields
        .iter()
        .map(|field| match field {
            SortField::SortName => left
                .name
                .to_ascii_lowercase()
                .cmp(&right.name.to_ascii_lowercase()),
            SortField::DateCreated => left.created_at.cmp(&right.created_at),
            SortField::DateLastMediaAdded => left.updated_at.cmp(&right.updated_at),
        })
        .find(|ordering| *ordering != Ordering::Equal)
        .unwrap_or_else(|| left.id.cmp(&right.id))
}

fn parse_uuid_list(value: &str) -> Result<Vec<Uuid>, ApiError> {
    value
        .split(',')
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(parse_jellyfin_uuid)
        .collect()
}

fn parse_jellyfin_uuid(value: &str) -> Result<Uuid, ApiError> {
    Uuid::parse_str(value)
        .or_else(|_| Uuid::parse_str(&hyphenate_uuid(value)))
        .map_err(|_| ApiError::bad_request("Invalid item id"))
}

fn hyphenate_uuid(value: &str) -> String {
    if value.len() == 32 {
        format!(
            "{}-{}-{}-{}-{}",
            &value[0..8],
            &value[8..12],
            &value[12..16],
            &value[16..20],
            &value[20..32]
        )
    } else {
        value.to_string()
    }
}

