fn media_item_to_json_with_playback(
    item: &MediaItem,
    server_id: &str,
    playback: Option<&PlaybackState>,
) -> serde_json::Value {
    media_item_to_json_with_playback_and_metadata(item, server_id, playback, None)
}

fn media_item_to_json_with_playback_and_metadata(
    item: &MediaItem,
    server_id: &str,
    playback: Option<&PlaybackState>,
    metadata: Option<&serde_json::Value>,
) -> serde_json::Value {
    let item_type = media_item_type(item);
    let item_id = item.id.simple().to_string();
    let container = media_item_container(item);
    let file_name = media_item_file_name(item);
    let file_size = media_item_file_size(item);
    let playback_position_ticks = playback.map_or(0, |state| state.position_ticks);
    let played = playback.is_some_and(|state| state.played);
    let play_count = i32::from(played);
    let is_favorite = playback.is_some_and(|state| state.is_favorite);
    let rating = playback.and_then(|state| state.rating);
    let likes = rating.map(|rating| rating > 0.0);
    let media_streams = media_item_streams(item);
    let default_audio_stream_index = default_audio_stream_index(&media_streams);
    let default_subtitle_stream_index = default_subtitle_stream_index(&media_streams);
    let selected_audio_stream_index = playback
        .and_then(|state| state.audio_stream_index)
        .or(default_audio_stream_index);
    let selected_subtitle_stream_index =
        selected_subtitle_stream_index(playback, default_subtitle_stream_index);
    let direct_stream_url = media_item_direct_stream_url(item, &item_id);
    let video_type = if item.media_type == "Video" {
        serde_json::json!("VideoFile")
    } else {
        serde_json::Value::Null
    };
    let episode_info = tv_episode_info(item);
    let series_name = episode_info
        .as_ref()
        .map(|info| serde_json::json!(info.series_name))
        .unwrap_or(serde_json::Value::Null);
    let series_id = episode_info
        .as_ref()
        .map(|info| serde_json::json!(tv_series_id(&info.series_name)))
        .unwrap_or(serde_json::Value::Null);
    let season_name = episode_info
        .as_ref()
        .and_then(|info| info.season_number.map(|season| format!("Season {season}")))
        .map(serde_json::Value::String)
        .unwrap_or(serde_json::Value::Null);
    let parent_index_number = episode_info
        .as_ref()
        .and_then(|info| info.season_number)
        .map(serde_json::Value::from)
        .unwrap_or(serde_json::Value::Null);
    let index_number = episode_info
        .as_ref()
        .and_then(|info| info.episode_number)
        .map(serde_json::Value::from)
        .unwrap_or(serde_json::Value::Null);

    let media_source = serde_json::json!({
        "Protocol": "File",
        "Id": playback.and_then(|state| state.media_source_id.clone()).unwrap_or_else(|| item_id.clone()),
        "Path": item.path,
        "Type": "Default",
        "Container": container,
        "Size": file_size,
        "Name": item.name,
        "IsRemote": false,
        "DirectStreamUrl": direct_stream_url,
        "ETag": null,
        "RunTimeTicks": item.runtime_ticks,
        "ReadAtNativeFramerate": false,
        "IgnoreDts": false,
        "IgnoreIndex": false,
        "GenPtsInput": false,
        "SupportsTranscoding": false,
        "SupportsDirectStream": true,
        "SupportsDirectPlay": true,
        "IsInfiniteStream": false,
        "RequiresOpening": false,
        "RequiresClosing": false,
        "RequiresLooping": false,
        "SupportsProbing": true,
        "VideoType": video_type,
        "DefaultAudioStreamIndex": selected_audio_stream_index,
        "DefaultSubtitleStreamIndex": selected_subtitle_stream_index,
        "MediaStreams": media_streams.clone(),
        "Formats": [],
        "Bitrate": item.bitrate,
    });

    let mut value = serde_json::json!({
        "Name": item.name,
        "OriginalTitle": null,
        "ServerId": server_id,
        "Id": item_id,
        "SeriesName": series_name,
        "SeriesId": series_id,
        "SeasonName": season_name,
        "ParentIndexNumber": parent_index_number,
        "IndexNumber": index_number,
        "Etag": null,
        "DateCreated": item.created_at.to_string(),
        "DateLastMediaAdded": item.updated_at.to_string(),
        "PremiereDate": null,
        "ProductionYear": null,
        "CommunityRating": null,
        "CriticRating": null,
        "OfficialRating": null,
        "Overview": "",
        "CanDelete": false,
        "CanDownload": true,
        "SortName": item.name,
        "ForcedSortName": null,
        "ExternalUrls": [],
        "Path": item.path,
        "FileName": file_name,
        "Container": container,
        "Size": file_size,
        "EnableMediaSourceDisplay": true,
        "ChannelId": null,
        "Taglines": [],
        "Genres": [],
        "GenreItems": [],
        "Studios": [],
        "People": [],
        "Tags": [],
        "TagItems": [],
        "Chapters": [],
        "MediaStreams": media_streams,
        "PlayAccess": "Full",
        "RemoteTrailers": [],
        "ProviderIds": {},
        "IsFolder": false,
        "ParentId": item.virtual_folder_id.simple().to_string(),
        "Type": item_type,
        "MediaType": item.media_type,
        "RunTimeTicks": item.runtime_ticks,
        "UserData": { "PlaybackPositionTicks": playback_position_ticks, "PlayCount": play_count, "IsFavorite": is_favorite, "Likes": likes, "Played": played, "Key": item_id, "ItemId": item_id, "PlayedPercentage": null, "LastPlayedDate": null, "Rating": rating },
        "ImageTags": { "Primary": "placeholder" },
        "PrimaryImageAspectRatio": 0.6666667,
        "BackdropImageTags": [],
        "LocationType": "FileSystem",
        "MediaSources": [media_source],
    });
    apply_media_item_metadata(&mut value, metadata, item, server_id);
    value
}

fn apply_media_item_metadata(
    value: &mut serde_json::Value,
    metadata: Option<&serde_json::Value>,
    item: &MediaItem,
    server_id: &str,
) {
    let Some(metadata) = metadata else {
        return;
    };
    let trailers = metadata_remote_trailers(metadata, item, server_id);
    let Some(object) = value.as_object_mut() else {
        return;
    };

    for (target, keys) in [
        ("Overview", &["Overview", "overview"][..]),
        ("OriginalTitle", &["OriginalTitle", "originalTitle"][..]),
        ("OfficialRating", &["OfficialRating", "OfficialRatings"][..]),
        ("Album", &["Album", "AlbumName"][..]),
        ("AlbumArtist", &["AlbumArtist", "AlbumArtists"][..]),
    ] {
        if let Some(field_value) = first_metadata_value_from_json(metadata, keys) {
            object.insert(target.to_string(), serde_json::Value::String(field_value));
        }
    }

    for (target, keys) in [
        ("CommunityRating", &["CommunityRating", "Rating"][..]),
        ("CriticRating", &["CriticRating"][..]),
    ] {
        if let Some(field_value) = first_metadata_number_from_json(metadata, keys) {
            object.insert(target.to_string(), serde_json::json!(field_value));
        }
    }

    if let Some(year) = first_metadata_i32_from_json(metadata, &["ProductionYear", "Year"]) {
        object.insert("ProductionYear".to_string(), serde_json::json!(year));
    }
    if let Some(premiere_date) =
        first_metadata_value_from_json(metadata, &["PremiereDate", "AirDate", "DateCreated"])
    {
        object.insert(
            "PremiereDate".to_string(),
            serde_json::Value::String(premiere_date),
        );
    }

    let taglines = metadata_values_from_json(metadata, &["Taglines"]);
    if !taglines.is_empty() {
        object.insert("Taglines".to_string(), serde_json::json!(taglines));
    }

    let genres = metadata_values_from_json(metadata, &["Genres", "MusicGenres"]);
    if !genres.is_empty() {
        object.insert("Genres".to_string(), serde_json::json!(genres));
        object.insert(
            "GenreItems".to_string(),
            serde_json::json!(metadata_name_id_items("Genre", &genres)),
        );
    }

    let studios = metadata_values_from_json(metadata, &["Studios"]);
    if !studios.is_empty() {
        object.insert("Studios".to_string(), serde_json::json!(studios));
    }

    let people = metadata_values_from_json(metadata, &["People", "Cast"]);
    if !people.is_empty() {
        object.insert(
            "People".to_string(),
            serde_json::json!(metadata_people_items(&people)),
        );
    }

    let tags = metadata_values_from_json(metadata, &["Tags"]);
    if !tags.is_empty() {
        object.insert("Tags".to_string(), serde_json::json!(tags));
        object.insert(
            "TagItems".to_string(),
            serde_json::json!(metadata_name_id_items("Tag", &tags)),
        );
    }

    let artists = metadata_values_from_json(metadata, &["Artists"]);
    if !artists.is_empty() {
        object.insert("Artists".to_string(), serde_json::json!(artists));
    }

    if let Some(provider_ids) = json_field_case_insensitive(metadata, "ProviderIds")
        .or_else(|| json_field_case_insensitive(metadata, "ProviderId"))
        && provider_ids.is_object()
    {
        object.insert("ProviderIds".to_string(), provider_ids.clone());
    }

    if !trailers.is_empty() {
        object.insert("RemoteTrailers".to_string(), serde_json::json!(trailers));
    }
}

fn metadata_values_from_json(metadata: &serde_json::Value, keys: &[&str]) -> Vec<String> {
    let mut values = BTreeMap::<String, String>::new();
    for key in keys {
        if let Some(value) = json_field_case_insensitive(metadata, key) {
            collect_metadata_value(value, &mut values);
        }
    }
    values.into_values().collect()
}

fn first_metadata_value_from_json(metadata: &serde_json::Value, keys: &[&str]) -> Option<String> {
    metadata_values_from_json(metadata, keys).into_iter().next()
}

fn first_metadata_number_from_json(metadata: &serde_json::Value, keys: &[&str]) -> Option<f64> {
    for key in keys {
        if let Some(value) = json_field_case_insensitive(metadata, key) {
            if let Some(value) = value.as_f64() {
                return Some(value);
            }
            if let Some(value) = value.as_str().and_then(|value| value.parse::<f64>().ok()) {
                return Some(value);
            }
        }
    }
    None
}

fn first_metadata_i32_from_json(metadata: &serde_json::Value, keys: &[&str]) -> Option<i32> {
    for key in keys {
        if let Some(value) = json_field_case_insensitive(metadata, key) {
            if let Some(value) = value.as_i64().and_then(|value| i32::try_from(value).ok()) {
                return Some(value);
            }
            if let Some(value) = value.as_str().and_then(|value| value.parse::<i32>().ok()) {
                return Some(value);
            }
        }
    }
    None
}

fn metadata_name_id_items(item_type: &str, names: &[String]) -> Vec<serde_json::Value> {
    names
        .iter()
        .map(|name| {
            serde_json::json!({
                "Name": name,
                "Id": stable_entity_id(item_type, name)
            })
        })
        .collect()
}

fn metadata_people_items(names: &[String]) -> Vec<serde_json::Value> {
    names
        .iter()
        .map(|name| {
            serde_json::json!({
                "Name": name,
                "Id": stable_entity_id("Person", name),
                "Role": null,
                "Type": "Person",
                "PrimaryImageTag": null
            })
        })
        .collect()
}

fn selected_subtitle_stream_index(
    playback: Option<&PlaybackState>,
    default_subtitle_stream_index: Option<i64>,
) -> serde_json::Value {
    match playback.and_then(|state| state.subtitle_stream_index) {
        Some(index) if index < 0 => serde_json::Value::Null,
        Some(index) => serde_json::json!(index),
        None => serde_json::json!(default_subtitle_stream_index),
    }
}

fn transcode_temp_root() -> PathBuf {
    std::env::temp_dir().join("jellyrin").join("transcodes")
}

fn hls_master_url(
    media_type: &str,
    item_id: &str,
    play_session_id: &str,
    access_token: &str,
) -> String {
    if media_type == "Audio" {
        format!(
            "/Audio/{item_id}/master.m3u8?PlaySessionId={play_session_id}&api_key={access_token}"
        )
    } else {
        format!(
            "/Videos/{item_id}/master.m3u8?PlaySessionId={play_session_id}&api_key={access_token}"
        )
    }
}

async fn cleanup_hls_transcode_files(output_path: &str) -> bool {
    let session_dir = HlsTranscodeLayout::from_media_playlist_path(output_path).session_dir;
    cleanup_hls_transcode_dir(&session_dir).await
}

async fn cleanup_hls_transcode_dir(session_dir: &FsPath) -> bool {
    if session_dir.as_os_str().is_empty() {
        return false;
    }
    match tokio::fs::remove_dir_all(session_dir).await {
        Ok(()) => true,
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => false,
        Err(error) => {
            tracing::warn!(
                path = %session_dir.display(),
                %error,
                "failed to remove HLS transcode directory"
            );
            false
        }
    }
}

fn first_stream_index(media_streams: &[serde_json::Value], stream_type: &str) -> Option<i64> {
    media_streams.iter().find_map(|stream| {
        let stream = stream.as_object()?;
        let type_name = stream.get("Type").and_then(serde_json::Value::as_str)?;
        if !type_name.eq_ignore_ascii_case(stream_type) {
            return None;
        }
        stream.get("Index").and_then(json_value_i64)
    })
}

fn default_audio_stream_index(media_streams: &[serde_json::Value]) -> Option<i64> {
    let mut first_audio_index = None;
    for stream in media_streams {
        let Some(stream) = stream.as_object() else {
            continue;
        };
        let Some(type_name) = stream.get("Type").and_then(serde_json::Value::as_str) else {
            continue;
        };
        if !type_name.eq_ignore_ascii_case("Audio") {
            continue;
        }

        let Some(index) = stream.get("Index").and_then(json_value_i64) else {
            continue;
        };
        if first_audio_index.is_none() {
            first_audio_index = Some(index);
        }
        if stream
            .get("IsDefault")
            .and_then(serde_json::Value::as_bool)
            .unwrap_or(false)
        {
            return Some(index);
        }
    }

    first_audio_index
}

fn default_subtitle_stream_index(media_streams: &[serde_json::Value]) -> Option<i64> {
    media_streams.iter().find_map(|stream| {
        let stream = stream.as_object()?;
        let type_name = stream.get("Type").and_then(serde_json::Value::as_str)?;
        if !type_name.eq_ignore_ascii_case("Subtitle") {
            return None;
        }
        if !stream
            .get("IsDefault")
            .and_then(serde_json::Value::as_bool)
            .unwrap_or(false)
        {
            return None;
        }

        stream.get("Index").and_then(json_value_i64)
    })
}

fn json_value_i64(value: &serde_json::Value) -> Option<i64> {
    match value {
        serde_json::Value::Number(value) => value.as_i64(),
        serde_json::Value::String(value) => value.parse::<i64>().ok(),
        _ => None,
    }
}

async fn item_counts_json(
    db: &Database,
    items: &[MediaItem],
) -> Result<serde_json::Value, ApiError> {
    let mut movie_count = 0;
    let mut series_count = 0;
    let mut synthetic_series = BTreeSet::new();
    let mut episode_count = 0;
    let mut song_count = 0;
    let mut album_count = 0;
    let mut book_count = 0;
    let mut music_video_count = 0;

    for item in items {
        match media_item_type(item) {
            "Movie" => movie_count += 1,
            "Series" => series_count += 1,
            "Episode" => {
                episode_count += 1;
                synthetic_series.insert(tv_episode_series_key(item));
            }
            "Audio" => song_count += 1,
            "MusicAlbum" => album_count += 1,
            "Book" => book_count += 1,
            "MusicVideo" => music_video_count += 1,
            _ => {}
        }
    }
    series_count += synthetic_series.len();
    let metadata_counts = item_count_metadata_values(db, items).await?;
    let artist_count = metadata_counts.artist_values.len();
    album_count += metadata_counts.album_values.len();
    let trailer_count = metadata_counts.trailer_count;

    Ok(serde_json::json!({
        "MovieCount": movie_count,
        "SeriesCount": series_count,
        "EpisodeCount": episode_count,
        "ArtistCount": artist_count,
        "ProgramCount": 0,
        "TrailerCount": trailer_count,
        "SongCount": song_count,
        "AlbumCount": album_count,
        "MusicVideoCount": music_video_count,
        "BoxSetCount": 0,
        "BookCount": book_count,
        "ItemCount": items.len(),
    }))
}

#[derive(Default)]
struct ItemCountMetadataValues {
    album_values: BTreeMap<String, String>,
    artist_values: BTreeMap<String, String>,
    trailer_count: usize,
}

async fn item_count_metadata_values(
    db: &Database,
    items: &[MediaItem],
) -> Result<ItemCountMetadataValues, ApiError> {
    if items.is_empty() {
        return Ok(ItemCountMetadataValues::default());
    }
    let item_ids = items.iter().map(|item| item.id).collect::<HashSet<_>>();
    let mut values = ItemCountMetadataValues::default();
    for metadata in db.media_item_metadata().await? {
        if item_ids.contains(&metadata.item_id) {
            collect_item_count_metadata_value(&metadata, "Album", &mut values.album_values);
            collect_item_count_metadata_value(&metadata, "AlbumName", &mut values.album_values);
            collect_item_count_metadata_value(&metadata, "Artists", &mut values.artist_values);
            collect_item_count_metadata_value(&metadata, "AlbumArtists", &mut values.artist_values);
            values.trailer_count += metadata_remote_trailer_count(&metadata.payload);
        }
    }
    Ok(values)
}

fn metadata_remote_trailer_count(metadata: &serde_json::Value) -> usize {
    ["RemoteTrailers", "Trailers"]
        .into_iter()
        .filter_map(|key| json_field_case_insensitive(metadata, key))
        .map(count_remote_trailer_values)
        .sum()
}

fn count_remote_trailer_values(value: &serde_json::Value) -> usize {
    match value {
        serde_json::Value::Array(values) => values.iter().map(count_remote_trailer_values).sum(),
        serde_json::Value::String(url) => usize::from(non_empty_json_string(url).is_some()),
        serde_json::Value::Object(object) => object
            .get("Url")
            .or_else(|| object.get("url"))
            .or_else(|| object.get("Path"))
            .or_else(|| object.get("path"))
            .and_then(serde_json::Value::as_str)
            .and_then(non_empty_json_string)
            .map(|_| 1)
            .unwrap_or(0),
        _ => 0,
    }
}

fn collect_item_count_metadata_value(
    metadata: &MediaItemMetadata,
    key: &str,
    values: &mut BTreeMap<String, String>,
) {
    if let Some(value) = metadata.payload.get(key) {
        collect_metadata_value(value, values);
    }
}

fn media_item_path(item: &MediaItem) -> &FsPath {
    FsPath::new(&item.path)
}

fn media_item_container(item: &MediaItem) -> Option<String> {
    media_item_path(item)
        .extension()
        .and_then(|extension| extension.to_str())
        .map(|extension| extension.to_ascii_lowercase())
}

fn media_item_file_name(item: &MediaItem) -> Option<String> {
    media_item_path(item)
        .file_name()
        .and_then(|file_name| file_name.to_str())
        .map(ToOwned::to_owned)
}

fn media_item_file_size(item: &MediaItem) -> Option<u64> {
    item.file_size
        .and_then(|file_size| u64::try_from(file_size).ok())
}

fn media_item_content_type(item: &MediaItem) -> String {
    match media_item_container(item).as_deref() {
        Some("mp4" | "m4v") => "video/mp4",
        Some("webm") => "video/webm",
        Some("mkv") => "video/x-matroska",
        Some("mov") => "video/quicktime",
        Some("avi") => "video/x-msvideo",
        Some("mp3") => "audio/mpeg",
        Some("m4a") => "audio/mp4",
        Some("aac") => "audio/aac",
        Some("flac") => "audio/flac",
        Some("ogg") => "audio/ogg",
        Some("wav") => "audio/wav",
        _ => "application/octet-stream",
    }
    .to_string()
}

fn media_item_direct_stream_url(item: &MediaItem, item_id: &str) -> String {
    match item.media_type.as_str() {
        "Audio" => format!("/Audio/{item_id}/stream"),
        _ => format!("/Videos/{item_id}/stream"),
    }
}

fn hls_codecs(item: &MediaItem) -> Option<String> {
    let codecs = [
        media_item_stream_codec(item, "Video"),
        media_item_stream_codec(item, "Audio"),
    ]
    .into_iter()
    .flatten()
    .filter(|codec| !codec.trim().is_empty())
    .collect::<Vec<_>>();
    (!codecs.is_empty()).then(|| codecs.join(","))
}

fn rewrite_hls_media_playlist(
    playlist: &str,
    item_id: &str,
    raw_query: Option<&str>,
    route_media_type: &str,
) -> String {
    let mut rewritten = String::with_capacity(playlist.len());
    for line in playlist.lines() {
        if line.trim().is_empty() || line.starts_with('#') {
            rewritten.push_str(line);
        } else if let Some(segment_id) = hls_segment_id_from_uri(line) {
            rewritten.push_str(&append_query(
                &format!("/{route_media_type}/{item_id}/hls1/main/{segment_id}.ts"),
                raw_query,
            ));
        } else {
            rewritten.push_str(line);
        }
        rewritten.push('\n');
    }
    rewritten
}

fn hls_segment_id_from_uri(uri: &str) -> Option<u32> {
    let path = uri.split_once('?').map_or(uri, |(path, _)| path);
    let file_name = FsPath::new(path).file_name()?.to_str()?;
    let segment_id = file_name.strip_prefix("segment_")?.strip_suffix(".ts")?;
    segment_id.parse().ok()
}

fn parse_hls_segment_file(segment_file: &str) -> Result<(i64, &str), ApiError> {
    let (segment_id, container) = segment_file
        .rsplit_once('.')
        .ok_or_else(|| ApiError::not_found("HLS segment not found"))?;
    let segment_id = segment_id
        .parse()
        .map_err(|_| ApiError::not_found("HLS segment not found"))?;
    Ok((segment_id, container))
}

fn append_query(path: &str, raw_query: Option<&str>) -> String {
    raw_query
        .filter(|query| !query.trim().is_empty())
        .map_or_else(|| path.to_string(), |query| format!("{path}?{query}"))
}

fn positive_u32(value: i64) -> Option<u32> {
    u32::try_from(value).ok().filter(|value| *value > 0)
}

