enum ImageOwner<'a> {
    Item(&'a str),
    User(&'a str),
    Branding,
}

impl ImageOwner<'_> {
    fn directory_segments(&self) -> [&str; 2] {
        match self {
            ImageOwner::Item(id) => ["items", id],
            ImageOwner::User(id) => ["users", id],
            ImageOwner::Branding => ["branding", "global"],
        }
    }
}

