async fn remote_image_candidates(
    item: &MediaItem,
    requested_image_type: Option<&str>,
) -> Result<Vec<serde_json::Value>, ApiError> {
    let Some(item_dir) = media_item_path(item).parent() else {
        return Ok(Vec::new());
    };
    let remote_dir = item_dir.join(".jellyrin-remote-images");
    let mut entries = match tokio::fs::read_dir(&remote_dir).await {
        Ok(entries) => entries,
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => return Ok(Vec::new()),
        Err(error) if error.kind() == std::io::ErrorKind::NotADirectory => return Ok(Vec::new()),
        Err(error) => return Err(error.into()),
    };
    let requested_image_type = requested_image_type.map(normalize_image_type);
    let mut images = Vec::new();
    while let Some(entry) = entries.next_entry().await? {
        let path = entry.path();
        if !is_supported_remote_image_path(&path) {
            continue;
        }
        let metadata = match entry.metadata().await {
            Ok(metadata) if metadata.is_file() => metadata,
            Ok(_) => continue,
            Err(_) => continue,
        };
        let canonical_path = tokio::fs::canonicalize(path).await?;
        let image_type = remote_image_type_from_path(&canonical_path);
        if requested_image_type
            .as_deref()
            .is_some_and(|requested| requested != image_type)
        {
            continue;
        }
        let name = entry.file_name().to_string_lossy().into_owned();
        let extension = canonical_path
            .extension()
            .and_then(|extension| extension.to_str())
            .unwrap_or_default();
        images.push(serde_json::json!({
            "ProviderName": "Local cache",
            "Url": remote_image_id_for_path(&canonical_path),
            "ThumbnailUrl": null,
            "Name": name,
            "Type": canonical_image_type(&image_type),
            "Language": null,
            "RatingType": "Score",
            "CommunityRating": null,
            "VoteCount": null,
            "Width": null,
            "Height": null,
            "Size": metadata.len(),
            "MimeType": image_format_from_extension(extension).content_type,
        }));
    }
    images.sort_by_key(|image| {
        image
            .get("Name")
            .and_then(serde_json::Value::as_str)
            .unwrap_or_default()
            .to_ascii_lowercase()
    });
    Ok(images)
}

async fn install_remote_image(
    state: &AppState,
    item_id: &str,
    remote_path: &FsPath,
    image_type: &str,
) -> Result<(), ApiError> {
    let bytes = tokio::fs::read(remote_path).await?;
    if bytes.is_empty() {
        return Err(ApiError::bad_request("Remote image file is empty"));
    }
    if bytes.len() > IMAGE_UPLOAD_LIMIT_BYTES {
        return Err(ApiError::bad_request("Remote image file is too large"));
    }
    store_image_bytes(state, ImageOwner::Item(item_id), image_type, 0, bytes).await
}

fn remote_image_id_for_path(path: &FsPath) -> String {
    format!(
        "local-image:{}",
        general_purpose::URL_SAFE_NO_PAD.encode(path.to_string_lossy().as_bytes())
    )
}

async fn remote_image_path_from_id(image_id: &str) -> Result<PathBuf, ApiError> {
    let encoded = image_id
        .strip_prefix("local-image:")
        .ok_or_else(|| ApiError::not_found("Remote image not found"))?;
    let bytes = general_purpose::URL_SAFE_NO_PAD
        .decode(encoded)
        .map_err(|_| ApiError::not_found("Remote image not found"))?;
    let path =
        String::from_utf8(bytes).map_err(|_| ApiError::not_found("Remote image not found"))?;
    let canonical_path = tokio::fs::canonicalize(PathBuf::from(path))
        .await
        .map_err(|_| ApiError::not_found("Remote image not found"))?;
    if !is_supported_remote_image_path(&canonical_path)
        || !path_contains_component(&canonical_path, ".jellyrin-remote-images")
    {
        return Err(ApiError::not_found("Remote image not found"));
    }
    Ok(canonical_path)
}

fn is_supported_remote_image_path(path: &FsPath) -> bool {
    path.extension()
        .and_then(|extension| extension.to_str())
        .map(|extension| {
            matches!(
                extension.to_ascii_lowercase().as_str(),
                "png" | "jpg" | "jpeg" | "webp" | "gif"
            )
        })
        .unwrap_or(false)
}

fn remote_image_type_from_path(path: &FsPath) -> String {
    let stem = path
        .file_stem()
        .and_then(|stem| stem.to_str())
        .unwrap_or_default()
        .to_ascii_lowercase();
    if stem.contains("backdrop") || stem.contains("fanart") || stem.contains("background") {
        "backdrop".to_string()
    } else if stem.contains("thumb") {
        "thumb".to_string()
    } else if stem.contains("logo") {
        "logo".to_string()
    } else {
        "primary".to_string()
    }
}

fn normalize_image_type(image_type: &str) -> String {
    sanitize_image_path_segment(image_type)
}

async fn user_exists(db: &Database, user_id: Uuid) -> Result<(), ApiError> {
    if db.users().await?.into_iter().any(|user| user.id == user_id) {
        Ok(())
    } else {
        Err(ApiError::not_found("User not found"))
    }
}

fn parse_image_index(image_index: &str) -> Result<usize, ApiError> {
    image_index
        .parse::<usize>()
        .map_err(|_| ApiError::bad_request("Invalid image index"))
}

async fn media_item_or_folder_by_id(db: &Database, item_id: &str) -> Result<(), ApiError> {
    let requested_id = parse_jellyfin_uuid(item_id)?;
    if db
        .media_items()
        .await?
        .into_iter()
        .any(|item| item.id == requested_id)
    {
        return Ok(());
    }
    if db
        .virtual_folders()
        .await?
        .into_iter()
        .any(|folder| folder.id == requested_id)
    {
        return Ok(());
    }
    Err(ApiError::not_found("Item not found"))
}

fn playback_event_sender() -> &'static broadcast::Sender<PlaybackEvent> {
    PLAYBACK_EVENTS.get_or_init(|| {
        let (sender, _) = broadcast::channel(256);
        sender
    })
}

fn subscribe_playback_events() -> broadcast::Receiver<PlaybackEvent> {
    playback_event_sender().subscribe()
}

fn broadcast_session_message(session_id: &str, message: serde_json::Value) {
    let _ = playback_event_sender().send(PlaybackEvent {
        session_id: session_id.to_string(),
        message,
    });
}

async fn broadcast_sessions_message(
    db: &Database,
    session_id: &str,
    user: &User,
) -> Result<(), ApiError> {
    broadcast_session_message(
        session_id,
        serde_json::json!({
            "MessageType": "Sessions",
            "Data": session_list_json(db, user).await?
        }),
    );
    Ok(())
}

async fn broadcast_sessions_message_to_user_owned_sessions(
    db: &Database,
    user: &User,
    exclude_session_id: Option<&str>,
) -> Result<(), ApiError> {
    let data = session_list_json(db, user).await?;
    for session in db
        .device_sessions()
        .await?
        .into_iter()
        .filter(|session| session.user_id == user.id)
    {
        if exclude_session_id.is_some_and(|excluded| excluded == session.access_token) {
            continue;
        }
        broadcast_session_message(
            &session.access_token,
            serde_json::json!({
                "MessageType": "Sessions",
                "Data": data.clone()
            }),
        );
    }
    Ok(())
}

async fn websocket(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<AuthQuery>,
    ws: Result<WebSocketUpgrade, WebSocketUpgradeRejection>,
) -> axum::response::Response {
    let (user, session_id) = match require_user(&state.db, &headers, query.api_key.as_deref()).await
    {
        Ok((user, token)) => (user, token.access_token),
        Err(error) => return error.into_response(),
    };

    match ws {
        Ok(ws) => ws
            .on_upgrade(move |socket| handle_websocket(socket, state, user, session_id))
            .into_response(),
        Err(rejection) => rejection.into_response(),
    }
}

async fn handle_websocket(mut socket: WebSocket, state: AppState, user: User, session_id: String) {
    let _ = socket
        .send(Message::Text(
            serde_json::json!({
                "MessageType": "ForceKeepAlive",
                "Data": 60
            })
            .to_string()
            .into(),
        ))
        .await;
    let mut receiver = subscribe_playback_events();
    loop {
        tokio::select! {
            event = receiver.recv() => {
                match event {
                    Ok(event) if event.session_id == session_id => {
                        if socket
                            .send(Message::Text(event.message.to_string().into()))
                            .await
                            .is_err()
                        {
                            break;
                        }
                    }
                    Ok(_) => {}
                    Err(broadcast::error::RecvError::Lagged(_)) => {}
                    Err(broadcast::error::RecvError::Closed) => break,
                }
            }
            message = socket.recv() => {
                match message {
                    Some(Ok(Message::Text(text))) => {
                        if should_send_sessions_message(&text) {
                            let sessions = match session_list_json(&state.db, &user).await {
                                Ok(sessions) => sessions,
                                Err(_) => break,
                            };
                            let message = serde_json::json!({
                                "MessageType": "Sessions",
                                "Data": sessions
                            });
                            if socket
                                .send(Message::Text(message.to_string().into()))
                                .await
                                .is_err()
                            {
                                break;
                            }
                        }
                    }
                    Some(Ok(Message::Close(_))) | None => break,
                    Some(Ok(_)) => {}
                    Some(Err(_)) => break,
                }
            }
        }
    }
}

fn should_send_sessions_message(text: &str) -> bool {
    serde_json::from_str::<serde_json::Value>(text)
        .ok()
        .and_then(|value| {
            value
                .get("MessageType")
                .and_then(serde_json::Value::as_str)
                .map(str::to_string)
        })
        .is_some_and(|message_type| message_type.eq_ignore_ascii_case("SessionsStart"))
}

