    #[tokio::test]
    async fn backup_endpoints_list_create_manifest_and_reject_restore() {
        let db = Database::connect("sqlite::memory:").await.unwrap();
        let user = db
            .update_first_user("admin".to_string(), "secret")
            .await
            .unwrap();
        let api_key = db
            .issue_api_key_for_user(user.id, "test-key")
            .await
            .unwrap();
        let app = router(AppState {
            db,
            web_dir: ".".into(),
            log_dir: ".".into(),
            local_address: "http://127.0.0.1:8097".to_string(),
        });

        let response = app
            .clone()
            .oneshot(
                Request::builder()
                    .uri("/Backup")
                    .body(Body::empty())
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::UNAUTHORIZED);

        let response = app
            .clone()
            .oneshot(
                Request::builder()
                    .uri("/backup")
                    .header("X-Emby-Token", &api_key)
                    .body(Body::empty())
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::OK);
        let body = response.into_body().collect().await.unwrap().to_bytes();
        let backups: Value = serde_json::from_slice(&body).unwrap();
        assert_eq!(backups.as_array().unwrap().len(), 0);

        let response = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::POST)
                    .uri("/Backup/Create")
                    .header("X-Emby-Token", &api_key)
                    .header(header::CONTENT_TYPE, "application/json")
                    .body(Body::from(
                        json!({
                            "Metadata": true,
                            "Subtitles": false,
                            "Trickplay": true
                        })
                        .to_string(),
                    ))
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::OK);
        let body = response.into_body().collect().await.unwrap().to_bytes();
        let created: Value = serde_json::from_slice(&body).unwrap();
        let path = created["Path"].as_str().unwrap();
        assert!(path.starts_with("jellyrin-backup-"));
        assert_eq!(created["ServerVersion"], COMPATIBLE_SERVER_VERSION);
        assert_eq!(created["BackupEngineVersion"], "1");
        assert!(created["DateCreated"].as_str().unwrap().ends_with('Z'));
        assert_eq!(created["Options"]["Metadata"], true);
        assert_eq!(created["Options"]["Trickplay"], true);
        assert_eq!(created["Options"]["Subtitles"], false);
        assert_eq!(created["Options"]["Database"], true);

        let response = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::POST)
                    .uri("/backup/create")
                    .header("X-Emby-Token", &api_key)
                    .header(header::CONTENT_TYPE, "application/json")
                    .body(Body::from(
                        json!({
                            "metadata": false,
                            "subtitles": true,
                            "trickplay": false,
                            "database": false
                        })
                        .to_string(),
                    ))
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::OK);
        let body = response.into_body().collect().await.unwrap().to_bytes();
        let lowercase_created: Value = serde_json::from_slice(&body).unwrap();
        let lowercase_path = lowercase_created["Path"].as_str().unwrap();
        assert_ne!(lowercase_path, path);
        assert_eq!(lowercase_created["Options"]["Metadata"], false);
        assert_eq!(lowercase_created["Options"]["Trickplay"], false);
        assert_eq!(lowercase_created["Options"]["Subtitles"], true);
        assert_eq!(lowercase_created["Options"]["Database"], false);

        let response = app
            .clone()
            .oneshot(
                Request::builder()
                    .uri("/Backup")
                    .header("X-Emby-Token", &api_key)
                    .body(Body::empty())
                    .unwrap(),
            )
            .await
            .unwrap();
        let body = response.into_body().collect().await.unwrap().to_bytes();
        let backups: Value = serde_json::from_slice(&body).unwrap();
        assert_eq!(backups.as_array().unwrap().len(), 2);
        assert!(
            backups
                .as_array()
                .unwrap()
                .iter()
                .any(|backup| backup["Path"] == path)
        );
        assert!(
            backups
                .as_array()
                .unwrap()
                .iter()
                .any(|backup| backup["Path"] == lowercase_path)
        );

        let response = app
            .clone()
            .oneshot(
                Request::builder()
                    .uri(format!("/Backup/Manifest?path={path}"))
                    .header("X-Emby-Token", &api_key)
                    .body(Body::empty())
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::OK);
        let body = response.into_body().collect().await.unwrap().to_bytes();
        let manifest: Value = serde_json::from_slice(&body).unwrap();
        assert_eq!(manifest["Path"], path);

        let response = app
            .clone()
            .oneshot(
                Request::builder()
                    .uri(format!("/backup/manifest?Path={lowercase_path}"))
                    .header("X-Emby-Token", &api_key)
                    .body(Body::empty())
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::OK);
        let body = response.into_body().collect().await.unwrap().to_bytes();
        let manifest: Value = serde_json::from_slice(&body).unwrap();
        assert_eq!(manifest["Path"], lowercase_path);

        let response = app
            .clone()
            .oneshot(
                Request::builder()
                    .uri("/Backup/Manifest?path=missing.zip")
                    .header("X-Emby-Token", &api_key)
                    .body(Body::empty())
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::NOT_FOUND);

        let response = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::POST)
                    .uri("/Backup/Restore")
                    .header("X-Emby-Token", &api_key)
                    .header(header::CONTENT_TYPE, "application/json")
                    .body(Body::from(
                        json!({ "ArchiveFileName": "missing.zip" }).to_string(),
                    ))
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::NOT_FOUND);

        let response = app
            .oneshot(
                Request::builder()
                    .method(Method::POST)
                    .uri("/backup/restore")
                    .header("X-Emby-Token", &api_key)
                    .header(header::CONTENT_TYPE, "application/json")
                    .body(Body::from(json!({ "ArchiveFileName": path }).to_string()))
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::CONFLICT);
    }

    #[tokio::test]
    async fn scheduled_tasks_endpoints_expose_library_scan_stub() {
        let db = Database::connect("sqlite::memory:").await.unwrap();
        let user = db
            .update_first_user("admin".to_string(), "secret")
            .await
            .unwrap();
        let api_key = db
            .issue_api_key_for_user(user.id, "test-key")
            .await
            .unwrap();
        let app = router(AppState {
            db,
            web_dir: ".".into(),
            log_dir: ".".into(),
            local_address: "http://127.0.0.1:8097".to_string(),
        });

        let response = app
            .clone()
            .oneshot(
                Request::builder()
                    .uri("/ScheduledTasks?IsEnabled=true")
                    .body(Body::empty())
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::UNAUTHORIZED);

        let response = app
            .clone()
            .oneshot(
                Request::builder()
                    .uri(format!("/ScheduledTasks?IsEnabled=true&api_key={api_key}"))
                    .body(Body::empty())
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::OK);
        let body = response.into_body().collect().await.unwrap().to_bytes();
        let tasks: Value = serde_json::from_slice(&body).unwrap();
        assert_eq!(tasks.as_array().unwrap().len(), 1);
        assert_eq!(tasks[0]["Id"], "scan-media-library");
        assert_eq!(tasks[0]["Key"], "RefreshLibrary");
        assert_eq!(tasks[0]["Name"], "Scan Media Library");
        assert_eq!(tasks[0]["State"], "Idle");
        assert_eq!(tasks[0]["IsHidden"], false);
        assert_eq!(tasks[0]["Triggers"].as_array().unwrap().len(), 1);

        let response = app
            .clone()
            .oneshot(
                Request::builder()
                    .uri("/ScheduledTasks/scan-media-library")
                    .header("X-Emby-Token", &api_key)
                    .body(Body::empty())
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::OK);
        let body = response.into_body().collect().await.unwrap().to_bytes();
        let task: Value = serde_json::from_slice(&body).unwrap();
        assert_eq!(task["Id"], "scan-media-library");

        for endpoint in [
            "/ScheduledTasks/Running/scan-media-library",
            "/scheduledtasks/running/scan-media-library",
        ] {
            let response = app
                .clone()
                .oneshot(
                    Request::builder()
                        .method(Method::POST)
                        .uri(endpoint)
                        .header("X-Emby-Token", &api_key)
                        .body(Body::empty())
                        .unwrap(),
                )
                .await
                .unwrap();
            assert_eq!(response.status(), StatusCode::NO_CONTENT, "{endpoint}");
        }

        let mut task = json!({});
        for _ in 0..20 {
            let response = app
                .clone()
                .oneshot(
                    Request::builder()
                        .uri("/ScheduledTasks/scan-media-library")
                        .header("X-Emby-Token", &api_key)
                        .body(Body::empty())
                        .unwrap(),
                )
                .await
                .unwrap();
            assert_eq!(response.status(), StatusCode::OK);
            let body = response.into_body().collect().await.unwrap().to_bytes();
            task = serde_json::from_slice(&body).unwrap();
            if task["State"] == "Idle" && task["LastExecutionResult"]["Status"] == "Completed" {
                break;
            }
            tokio::time::sleep(std::time::Duration::from_millis(25)).await;
        }
        assert_eq!(task["State"], "Idle");
        assert_eq!(task["LastExecutionResult"]["Status"], "Completed");
        assert_eq!(task["LastExecutionResult"]["Key"], "RefreshLibrary");

        let response = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::DELETE)
                    .uri("/ScheduledTasks/Running/scan-media-library")
                    .header("X-Emby-Token", &api_key)
                    .body(Body::empty())
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::NO_CONTENT);

        let response = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::POST)
                    .uri("/ScheduledTasks/scan-media-library/Triggers")
                    .header("X-Emby-Token", &api_key)
                    .header(header::CONTENT_TYPE, "application/json")
                    .body(Body::from(json!([]).to_string()))
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::NO_CONTENT);

        let response = app
            .oneshot(
                Request::builder()
                    .method(Method::POST)
                    .uri("/ScheduledTasks/unknown/Triggers")
                    .header("X-Emby-Token", &api_key)
                    .header(header::CONTENT_TYPE, "application/json")
                    .body(Body::from(json!([]).to_string()))
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::NOT_FOUND);
    }

