        let main_playlist = transcode_dir.join("main.m3u8");
        tokio::fs::write(&main_playlist, b"#EXTM3U\n")
            .await
            .unwrap();
        tokio::fs::write(transcode_dir.join("segment_00000.ts"), b"zero")
            .await
            .unwrap();
